export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly min: number;
  readonly max: number;
  readonly name: string;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { min: 0,  max: 59, name: "minute"     },
  { min: 0,  max: 23, name: "hour"       },
  { min: 1,  max: 31, name: "dayOfMonth" },
  { min: 1,  max: 12, name: "month"      },
  { min: 0,  max: 6,  name: "dayOfWeek"  },
] as const;

function assertInRange(value: number, config: FieldConfig, context: string): void {
  if (value < config.min || value > config.max) {
    throw new RangeError(
      `Field "${config.name}": value ${value} out of valid range [${config.min}-${config.max}] in expression "${context}"`
    );
  }
}

function parseInteger(raw: string, context: string): number {
  if (!/^-?\d+$/.test(raw)) {
    throw new SyntaxError(`Field: expected integer, got "${raw}" in expression "${context}"`);
  }
  return parseInt(raw, 10);
}

function expandSingleSegment(segment: string, config: FieldConfig): number[] {
  // Step: */n  |  a-b/n  |  a/n
  if (segment.includes("/")) {
    const slashIdx = segment.indexOf("/");
    const rangeExpr = segment.slice(0, slashIdx);
    const stepRaw   = segment.slice(slashIdx + 1);

    if (stepRaw.includes("/")) {
      throw new SyntaxError(`Field "${config.name}": multiple "/" in segment "${segment}"`);
    }

    const step = parseInteger(stepRaw, segment);
    if (step <= 0) {
      throw new RangeError(`Field "${config.name}": step must be >= 1, got ${step} in "${segment}"`);
    }

    let rangeMin: number;
    let rangeMax: number;

    if (rangeExpr === "*") {
      rangeMin = config.min;
      rangeMax = config.max;
    } else if (rangeExpr.includes("-")) {
      const dashIdx = rangeExpr.indexOf("-");
      rangeMin = parseInteger(rangeExpr.slice(0, dashIdx), segment);
      rangeMax = parseInteger(rangeExpr.slice(dashIdx + 1), segment);
    } else {
      rangeMin = parseInteger(rangeExpr, segment);
      rangeMax = config.max;
    }

    assertInRange(rangeMin, config, segment);
    assertInRange(rangeMax, config, segment);

    if (rangeMin > rangeMax) {
      throw new RangeError(
        `Field "${config.name}": range start ${rangeMin} > end ${rangeMax} in "${segment}"`
      );
    }

    const values: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) {
      values.push(i);
    }
    return values;
  }

  // Wildcard
  if (segment === "*") {
    const values: number[] = [];
    for (let i = config.min; i <= config.max; i++) {
      values.push(i);
    }
    return values;
  }

  // Range: a-b
  if (segment.includes("-")) {
    const dashIdx = segment.indexOf("-");
    const start = parseInteger(segment.slice(0, dashIdx), segment);
    const end   = parseInteger(segment.slice(dashIdx + 1), segment);

    assertInRange(start, config, segment);
    assertInRange(end,   config, segment);

    if (start > end) {
      throw new RangeError(
        `Field "${config.name}": range start ${start} > end ${end} in "${segment}"`
      );
    }

    const values: number[] = [];
    for (let i = start; i <= end; i++) {
      values.push(i);
    }
    return values;
  }

  // Single number
  const num = parseInteger(segment, segment);
  assertInRange(num, config, segment);
  return [num];
}

function expandField(expr: string, config: FieldConfig): number[] {
  if (expr.length === 0) {
    throw new SyntaxError(`Field "${config.name}": empty field expression`);
  }

  const seen   = new Set<number>();
  const result: number[] = [];

  const segments = expr.split(",");

  for (const segment of segments) {
    const trimmed = segment.trim();
    if (trimmed.length === 0) {
      throw new SyntaxError(`Field "${config.name}": empty segment in comma-list "${expr}"`);
    }

    for (const value of expandSingleSegment(trimmed, config)) {
      if (!seen.has(value)) {
        seen.add(value);
        result.push(value);
      }
    }
  }

  return result.sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed.length === 0) {
    throw new SyntaxError("parseCron received an empty expression");
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), got ${fields.length}: "${expression}"`
    );
  }

  return {
    minute:     expandField(fields[0], FIELD_CONFIGS[0]),
    hour:       expandField(fields[1], FIELD_CONFIGS[1]),
    dayOfMonth: expandField(fields[2], FIELD_CONFIGS[2]),
    month:      expandField(fields[3], FIELD_CONFIGS[3]),
    dayOfWeek:  expandField(fields[4], FIELD_CONFIGS[4]),
  };
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
};

function clamp(values: number[], min: number, max: number): number[] {
  return values.filter((v) => v >= min && v <= max);
}

function unique(values: number[]): number[] {
  return [...new Set(values)].sort((a, b) => a - b);
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Step: */n or start-end/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) {
      throw new Error(`Invalid step value: ${stepStr}`);
    }
    let start = min;
    let end = max;
    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [s, e] = rangePart.split("-").map(Number);
        start = s;
        end = e;
      } else {
        start = parseInt(rangePart, 10);
      }
    }
    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range in step expression: ${segment}`);
    }
    const result: number[] = [];
    for (let i = start; i <= end; i += step) {
      result.push(i);
    }
    return clamp(result, min, max);
  }

  // Wildcard
  if (segment === "*") {
    const result: number[] = [];
    for (let i = min; i <= max; i++) {
      result.push(i);
    }
    return result;
  }

  // Range: n-m
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end) || start > end) {
      throw new Error(`Invalid range: ${segment}`);
    }
    const result: number[] = [];
    for (let i = start; i <= end; i++) {
      result.push(i);
    }
    return clamp(result, min, max);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid value: ${segment}`);
  }
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of range [${min}, ${max}]`);
  }
  return [value];
}

function parseField(expression: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];
  const segments = expression.split(",");
  const values: number[] = [];

  for (const segment of segments) {
    values.push(...parseSegment(segment.trim(), min, max));
  }

  let result = unique(values);

  // Normalize dayOfWeek: treat 7 as 0 (both = Sunday)
  if (field === "dayOfWeek") {
    result = unique(result.map((v) => (v === 7 ? 0 : v)));
  }

  return result;
}

function parseCron(expression: string): CronResult {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${fields.length}`
    );
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] =
    fields;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(dayOfMonthExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dayOfWeekExpr, "dayOfWeek"),
  };
}

export default parseCron;

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waiters: Array<{
    tokens: number;
    resolve: () => void;
    reject: (err: Error) => void;
  }>;
  private scheduled: ReturnType<typeof setTimeout> | null;

  constructor(options: {
    maxTokens: number;
    refillRate: number;
    refillIntervalMs: number;
  }) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0)
      throw new RangeError("maxTokens must be a finite positive number");
    if (!Number.isFinite(options.refillRate) || options.refillRate <= 0)
      throw new RangeError("refillRate must be a finite positive number");
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0)
      throw new RangeError("refillIntervalMs must be a finite positive number");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
    this.waiters = [];
    this.scheduled = null;
  }

  private applyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    if (elapsed > 0) {
      const tokensToAdd = (elapsed / this.refillIntervalMs) * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime = now;
    }
  }

  private validateTokenArg(tokens: number): void {
    if (!Number.isFinite(tokens) || tokens <= 0)
      throw new RangeError("tokens must be a finite positive number");
  }

  tryConsume(tokens: number = 1): boolean {
    this.validateTokenArg(tokens);
    if (tokens > this.maxTokens) return false;

    this.applyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }
    return false;
  }

  getTokens(): number {
    this.applyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.drainWaiters();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    this.validateTokenArg(tokens);

    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested tokens (${tokens}) exceeds maxTokens (${this.maxTokens}); would never be satisfiable`
        )
      );
    }

    // Only bypass queue if no one is ahead of us — prevents starvation
    if (this.waiters.length === 0) {
      this.applyRefill();
      if (this.currentTokens >= tokens) {
        this.currentTokens -= tokens;
        return Promise.resolve();
      }
    }

    return new Promise<void>((resolve, reject) => {
      this.waiters.push({ tokens, resolve, reject });
      this.ensureScheduled();
    });
  }

  private drainWaiters(): void {
    this.applyRefill();

    while (this.waiters.length > 0) {
      const waiter = this.waiters[0];
      if (this.currentTokens >= waiter.tokens) {
        this.currentTokens -= waiter.tokens;
        this.waiters.shift();
        waiter.resolve();
        // Re-apply refill in case resolution took non-zero wall time
        this.applyRefill();
      } else {
        break;
      }
    }

    if (this.waiters.length > 0) {
      this.ensureScheduled();
    }
  }

  private ensureScheduled(): void {
    if (this.scheduled !== null || this.waiters.length === 0) return;

    this.applyRefill();
    const needed = this.waiters[0].tokens - this.currentTokens;
    const delayMs =
      needed <= 0
        ? 0
        : Math.ceil((needed / this.refillRate) * this.refillIntervalMs);

    this.scheduled = setTimeout(() => {
      this.scheduled = null;
      this.drainWaiters();
    }, delayMs);
  }
}

export default RateLimiter;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  name: string;
  min: number;
  max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute",     min: 0, max: 59 },
  { name: "hour",       min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month",      min: 1, max: 12 },
  { name: "dayOfWeek",  min: 0, max: 7  },
] as const;

function intRange(start: number, end: number): number[] {
  if (start > end) return [];
  const out: number[] = [];
  for (let i = start; i <= end; i++) out.push(i);
  return out;
}

function dedupe(values: number[]): number[] {
  return [...new Set(values)].sort((a, b) => a - b);
}

function assertInRange(value: number, config: FieldConfig, raw: string): void {
  if (!Number.isInteger(value) || value < config.min || value > config.max) {
    throw new RangeError(
      `Value ${value} is out of valid range [${config.min}–${config.max}] in field "${config.name}" (expression: "${raw}")`
    );
  }
}

function parseSegment(segment: string, config: FieldConfig): number[] {
  const { min, max } = config;

  // Comma-separated list — split first, recurse on each part
  if (segment.includes(",")) {
    const parts = segment.split(",");
    if (parts.some((p) => p.trim() === "")) {
      throw new SyntaxError(
        `Empty element in comma list for field "${config.name}" (expression: "${segment}")`
      );
    }
    return dedupe(parts.flatMap((p) => parseSegment(p.trim(), config)));
  }

  // Step: base/step — base can be *, a number, or a range
  if (segment.includes("/")) {
    const slashIdx = segment.indexOf("/");
    const basePart = segment.slice(0, slashIdx);
    const stepPart = segment.slice(slashIdx + 1);

    if (stepPart === "" || stepPart.includes("/")) {
      throw new SyntaxError(
        `Malformed step expression for field "${config.name}" (expression: "${segment}")`
      );
    }

    const step = Number(stepPart);
    if (!Number.isInteger(step) || step < 1) {
      throw new RangeError(
        `Step value must be a positive integer in field "${config.name}" (expression: "${segment}")`
      );
    }

    let rangeStart: number;
    let rangeEnd: number;

    if (basePart === "*") {
      rangeStart = min;
      rangeEnd = max;
    } else if (basePart.includes("-")) {
      [rangeStart, rangeEnd] = parseRangeBounds(basePart, config);
    } else {
      const n = Number(basePart);
      if (!Number.isInteger(n)) {
        throw new SyntaxError(
          `Invalid step base in field "${config.name}" (expression: "${segment}")`
        );
      }
      assertInRange(n, config, segment);
      rangeStart = n;
      rangeEnd = max;
    }

    const result: number[] = [];
    for (let i = rangeStart; i <= rangeEnd; i += step) result.push(i);
    return result;
  }

  // Range: start-end
  if (segment.includes("-")) {
    const [start, end] = parseRangeBounds(segment, config);
    return intRange(start, end);
  }

  // Wildcard
  if (segment === "*") {
    return intRange(min, max);
  }

  // Plain integer
  const n = Number(segment);
  if (!Number.isInteger(n) || segment.trim() === "") {
    throw new SyntaxError(
      `Invalid value "${segment}" in field "${config.name}"`
    );
  }
  assertInRange(n, config, segment);
  return [n];
}

function parseRangeBounds(
  segment: string,
  config: FieldConfig
): [number, number] {
  const dashIdx = segment.indexOf("-");
  if (dashIdx <= 0 || dashIdx === segment.length - 1) {
    throw new SyntaxError(
      `Malformed range in field "${config.name}" (expression: "${segment}")`
    );
  }

  const startStr = segment.slice(0, dashIdx);
  const endStr = segment.slice(dashIdx + 1);

  // Guard against nested ranges like "1-2-3"
  if (endStr.includes("-")) {
    throw new SyntaxError(
      `Nested range is not allowed in field "${config.name}" (expression: "${segment}")`
    );
  }

  const start = Number(startStr);
  const end = Number(endStr);

  if (!Number.isInteger(start) || !Number.isInteger(end)) {
    throw new SyntaxError(
      `Non-integer range bound in field "${config.name}" (expression: "${segment}")`
    );
  }

  assertInRange(start, config, segment);
  assertInRange(end, config, segment);

  if (start > end) {
    throw new RangeError(
      `Range start (${start}) must be ≤ end (${end}) in field "${config.name}" (expression: "${segment}")`
    );
  }

  return [start, end];
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron expects a string, received ${typeof expression}`
    );
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields (got ${fields.length}): "${trimmed}"`
    );
  }

  const [minuteRaw, hourRaw, domRaw, monthRaw, dowRaw] = fields;
  const raws = [minuteRaw, hourRaw, domRaw, monthRaw, dowRaw];

  const parsed = FIELD_CONFIGS.map((config, i) => {
    try {
      return parseSegment(raws[i], config);
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      throw new (err instanceof TypeError ? TypeError : err instanceof RangeError ? RangeError : SyntaxError)(
        `Field "${config.name}": ${msg}`
      );
    }
  });

  return {
    minute:     parsed[0],
    hour:       parsed[1],
    dayOfMonth: parsed[2],
    month:      parsed[3],
    dayOfWeek:  parsed[4],
  };
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;

  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: Array<{ tokens: number; resolve: () => void }>;
  private queueScheduled: boolean;

  constructor(options: {
    maxTokens: number;
    refillRate: number;
    refillIntervalMs: number;
  }) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError("maxTokens must be a positive finite number");
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate < 0) {
      throw new RangeError("refillRate must be a non-negative finite number");
    }
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0) {
      throw new RangeError("refillIntervalMs must be a positive finite number");
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
    this.queueScheduled = false;
  }

  private applyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed >= this.refillIntervalMs && this.refillRate > 0) {
      const intervals = Math.floor(elapsed / this.refillIntervalMs);
      this.currentTokens = Math.min(
        this.maxTokens,
        this.currentTokens + intervals * this.refillRate
      );
      // Advance lastRefillTime by whole intervals only, preserving the remainder
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError("tokens must be a non-negative finite number");
    }
    if (tokens === 0) return true;
    if (tokens > this.maxTokens) return false;

    this.applyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }
    return false;
  }

  getTokens(): number {
    this.applyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.drainQueue();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0) {
      return Promise.reject(
        new RangeError("tokens must be a non-negative finite number")
      );
    }
    if (tokens === 0) return Promise.resolve();
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds bucket capacity of ${this.maxTokens}`
        )
      );
    }

    this.applyRefill();

    // Fast path: no waiters ahead and sufficient tokens available now
    if (this.waitQueue.length === 0 && this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return Promise.resolve();
    }

    return new Promise<void>((resolve) => {
      this.waitQueue.push({ tokens, resolve });
      this.scheduleNextDrain();
    });
  }

  private scheduleNextDrain(): void {
    if (this.queueScheduled || this.waitQueue.length === 0) return;
    if (this.refillRate === 0) {
      // No refill will ever happen; queue will only clear via reset() or
      // if tokens are available right now — attempt immediate drain only.
      this.drainQueue();
      return;
    }

    this.applyRefill();
    const head = this.waitQueue[0];
    const deficit = head.tokens - this.currentTokens;

    let delayMs: number;
    if (deficit <= 0) {
      delayMs = 0;
    } else {
      const intervalsNeeded = Math.ceil(deficit / this.refillRate);
      const msUntilNextInterval =
        this.refillIntervalMs - (Date.now() - this.lastRefillTime);
      delayMs = Math.max(
        0,
        msUntilNextInterval + (intervalsNeeded - 1) * this.refillIntervalMs
      );
    }

    this.queueScheduled = true;
    setTimeout(() => {
      this.queueScheduled = false;
      this.drainQueue();
    }, delayMs);
  }

  private drainQueue(): void {
    this.applyRefill();

    while (this.waitQueue.length > 0) {
      const head = this.waitQueue[0];
      if (this.currentTokens >= head.tokens) {
        this.currentTokens -= head.tokens;
        this.waitQueue.shift();
        // Resolve outside the loop to avoid re-entrancy issues
        Promise.resolve().then(head.resolve);
      } else {
        break;
      }
    }

    if (this.waitQueue.length > 0) {
      this.scheduleNextDrain();
    }
  }
}

export default RateLimiter;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

type CronResult = Record<CronField, number[]>;

interface FieldConfig {
  readonly name: CronField;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 7 },
] as const;

const INTEGER_RE = /^\d+$/;

function strictParseInt(raw: string, fieldName: string, context: string): number {
  if (!INTEGER_RE.test(raw)) {
    throw new Error(
      `Invalid non-integer token "${raw}" in field "${fieldName}" (context: "${context}")`
    );
  }
  const n = Number(raw);
  if (!Number.isSafeInteger(n)) {
    throw new Error(`Unsafe integer "${raw}" in field "${fieldName}"`);
  }
  return n;
}

function assertInBounds(
  n: number,
  min: number,
  max: number,
  fieldName: string,
  context: string
): void {
  if (n < min || n > max) {
    throw new RangeError(
      `Value ${n} is outside [${min}, ${max}] in field "${fieldName}" (context: "${context}")`
    );
  }
}

function expandRange(
  start: number,
  end: number,
  step: number,
  min: number,
  max: number,
  fieldName: string,
  context: string
): number[] {
  assertInBounds(start, min, max, fieldName, context);
  assertInBounds(end, min, max, fieldName, context);

  if (start > end) {
    throw new RangeError(
      `Range start ${start} exceeds end ${end} in field "${fieldName}" (context: "${context}")`
    );
  }
  if (step <= 0) {
    throw new RangeError(
      `Step must be a positive integer, got ${step} in field "${fieldName}" (context: "${context}")`
    );
  }

  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(
  segment: string,
  min: number,
  max: number,
  fieldName: string
): number[] {
  const slashIdx = segment.indexOf("/");

  if (slashIdx !== -1) {
    const rangePart = segment.slice(0, slashIdx);
    const stepRaw = segment.slice(slashIdx + 1);

    if (stepRaw.includes("/")) {
      throw new Error(
        `Multiple "/" separators in field "${fieldName}" segment "${segment}"`
      );
    }

    const step = strictParseInt(stepRaw, fieldName, segment);

    if (rangePart === "*") {
      return expandRange(min, max, step, min, max, fieldName, segment);
    }

    const dashIdx = rangePart.indexOf("-");
    if (dashIdx !== -1) {
      const start = strictParseInt(rangePart.slice(0, dashIdx), fieldName, segment);
      const end = strictParseInt(rangePart.slice(dashIdx + 1), fieldName, segment);
      return expandRange(start, end, step, min, max, fieldName, segment);
    }

    const start = strictParseInt(rangePart, fieldName, segment);
    return expandRange(start, max, step, min, max, fieldName, segment);
  }

  if (segment === "*") {
    return expandRange(min, max, 1, min, max, fieldName, segment);
  }

  const dashIdx = segment.indexOf("-");
  if (dashIdx !== -1) {
    if (dashIdx === 0 || dashIdx === segment.length - 1) {
      throw new Error(
        `Malformed range "${segment}" in field "${fieldName}"`
      );
    }
    const start = strictParseInt(segment.slice(0, dashIdx), fieldName, segment);
    const end = strictParseInt(segment.slice(dashIdx + 1), fieldName, segment);
    return expandRange(start, end, 1, min, max, fieldName, segment);
  }

  const n = strictParseInt(segment, fieldName, segment);
  assertInBounds(n, min, max, fieldName, segment);
  return [n];
}

function parseField(
  expr: string,
  min: number,
  max: number,
  fieldName: string
): number[] {
  if (expr.length === 0) {
    throw new Error(`Empty expression for field "${fieldName}"`);
  }

  const segments = expr.split(",");

  if (segments.some((s) => s.trim() !== s || s.length === 0)) {
    throw new Error(
      `Malformed comma-separated list "${expr}" in field "${fieldName}" — no whitespace or empty slots allowed`
    );
  }

  const valueSet = new Set<number>();

  for (const segment of segments) {
    for (const v of parseSegment(segment, min, max, fieldName)) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed.length === 0) {
    throw new Error("Cron expression must not be empty");
  }

  const rawFields = trimmed.split(/[ \t]+/);

  if (rawFields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), got ${rawFields.length}: "${expression}"`
    );
  }

  const result = {} as CronResult;

  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const { name, min, max } = FIELD_CONFIGS[i];
    result[name] = parseField(rawFields[i], min, max, name);
  }

  return result;
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface Waiter {
  tokens: number;
  resolve: () => void;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;

  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: Waiter[] = [];
  private drainScheduled = false;

  constructor(options: RateLimiterOptions) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError(`maxTokens must be a positive finite number, got ${options.maxTokens}`);
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate <= 0) {
      throw new RangeError(`refillRate must be a positive finite number, got ${options.refillRate}`);
    }
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0) {
      throw new RangeError(`refillIntervalMs must be a positive finite number, got ${options.refillIntervalMs}`);
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private applyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed >= this.refillIntervalMs) {
      const intervals = Math.floor(elapsed / this.refillIntervalMs);
      // Guard against floating-point overflow if somehow elapsed is enormous
      const tokensToAdd = Math.min(
        this.maxTokens - this.currentTokens,
        intervals * this.refillRate,
      );
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      // Advance lastRefillTime only by consumed intervals to preserve sub-interval remainder
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  private validateTokenAmount(tokens: number, caller: string): void {
    if (!Number.isFinite(tokens) || tokens <= 0) {
      throw new RangeError(`${caller}: tokens must be a positive finite number, got ${tokens}`);
    }
    if (!Number.isInteger(tokens)) {
      throw new RangeError(`${caller}: tokens must be an integer, got ${tokens}`);
    }
  }

  tryConsume(tokens = 1): boolean {
    this.validateTokenAmount(tokens, "tryConsume");
    this.applyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.applyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    // Give any blocked waiters a chance to re-evaluate immediately
    this.scheduleDrain();
  }

  waitForTokens(tokens = 1): Promise<void> {
    this.validateTokenAmount(tokens, "waitForTokens");

    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `waitForTokens: requested ${tokens} tokens exceeds maxTokens (${this.maxTokens}); ` +
          `bucket can never satisfy this request`,
        ),
      );
    }

    // Fast path: no queue ahead of us and we can serve immediately
    if (this.waitQueue.length === 0 && this.tryConsume(tokens)) {
      return Promise.resolve();
    }

    return new Promise<void>((resolve) => {
      this.waitQueue.push({ tokens, resolve });
      this.scheduleDrain();
    });
  }

  private scheduleDrain(): void {
    // Only one drain loop should be pending at a time to avoid redundant timers
    if (this.drainScheduled) return;

    this.drainScheduled = true;
    // Defer to allow synchronous callers to finish batching before we drain
    setTimeout(() => this.drainQueue(), 0);
  }

  private drainQueue(): void {
    this.drainScheduled = false;

    this.applyRefill();

    // Serve as many consecutive waiters as current tokens allow
    while (this.waitQueue.length > 0) {
      const next = this.waitQueue[0];

      if (this.currentTokens >= next.tokens) {
        this.currentTokens -= next.tokens;
        this.waitQueue.shift();
        // Resolve asynchronously so each waiter doesn't re-enter drain mid-loop
        next.resolve();
      } else {
        break;
      }
    }

    // If waiters remain, schedule a wake-up timed to when the next batch of
    // tokens arrives — no busy-waiting, no over-sleeping.
    if (this.waitQueue.length > 0) {
      const next = this.waitQueue[0];
      const tokensNeeded = next.tokens - this.currentTokens;
      const intervalsNeeded = Math.ceil(tokensNeeded / this.refillRate);
      const msIntoCurrentInterval = Date.now() - this.lastRefillTime;
      const msUntilNextInterval = this.refillIntervalMs - msIntoCurrentInterval;
      // Total wait: remainder of current interval + any additional full intervals
      const waitMs = msUntilNextInterval + (intervalsNeeded - 1) * this.refillIntervalMs;

      this.drainScheduled = true;
      setTimeout(() => {
        this.drainScheduled = false;
        this.drainQueue();
      }, Math.max(1, waitMs));
    }
  }
}

export default RateLimiter;

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldRange = { min: number; max: number };

const FIELD_RANGES: Record<keyof CronResult, FieldRange> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const expandRange = (start: number, end: number, step: number, range: FieldRange): number[] => {
  if (start < range.min || end > range.max || start > end) {
    throw new RangeError(`Value out of range [${range.min}-${range.max}]: ${start}-${end}`);
  }
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
};

const parseSegment = (segment: string, range: FieldRange): number[] => {
  // Step: */n or a-b/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) {
      throw new Error(`Invalid step value: ${stepStr}`);
    }
    if (rangePart === "*") {
      return expandRange(range.min, range.max, step, range);
    }
    if (rangePart.includes("-")) {
      const [startStr, endStr] = rangePart.split("-");
      return expandRange(parseInt(startStr, 10), parseInt(endStr, 10), step, range);
    }
    throw new Error(`Invalid step expression: ${segment}`);
  }

  // Wildcard
  if (segment === "*") {
    return expandRange(range.min, range.max, 1, range);
  }

  // Range: a-b
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range: ${segment}`);
    }
    return expandRange(start, end, 1, range);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid value: ${segment}`);
  }
  if (value < range.min || value > range.max) {
    throw new RangeError(`Value ${value} out of range [${range.min}-${range.max}]`);
  }
  return [value];
};

const parseField = (field: string, range: FieldRange): number[] => {
  const segments = field.split(",");
  const values = new Set<number>();
  for (const segment of segments) {
    for (const value of parseSegment(segment.trim(), range)) {
      values.add(value);
    }
  }
  return Array.from(values).sort((a, b) => a - b);
};

const parseCron = (expression: string): CronResult => {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields, got ${fields.length}`);
  }

  const [minuteField, hourField, dayOfMonthField, monthField, dayOfWeekField] = fields;
  const fieldKeys = Object.keys(FIELD_RANGES) as (keyof CronResult)[];
  const fieldValues = [minuteField, hourField, dayOfMonthField, monthField, dayOfWeekField];

  const result = {} as CronResult;
  for (let i = 0; i < fieldKeys.length; i++) {
    const key = fieldKeys[i];
    result[key] = parseField(fieldValues[i], FIELD_RANGES[key]);
  }

  return result;
};

export default parseCron;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 7],
};

function range(from: number, to: number): number[] {
  if (from > to) throw new RangeError(`Invalid range: ${from}-${to}`);
  return Array.from({ length: to - from + 1 }, (_, i) => from + i);
}

function parseField(expr: string, fieldName: keyof CronFields): number[] {
  const [min, max] = FIELD_RANGES[fieldName];

  const assertInRange = (val: number): number => {
    if (val < min || val > max) {
      throw new RangeError(
        `Value ${val} out of range [${min}-${max}] for field "${fieldName}"`
      );
    }
    return val;
  };

  // Comma-separated list — recurse on each part and flatten
  if (expr.includes(",")) {
    const values = expr
      .split(",")
      .flatMap((part) => parseField(part.trim(), fieldName));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Wildcard
  if (expr === "*") {
    return range(min, max);
  }

  // Step value: */step or start-end/step
  if (expr.includes("/")) {
    const [rangePart, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) {
      throw new RangeError(`Invalid step value "${stepStr}" in field "${fieldName}"`);
    }

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      const [fromStr, toStr] = rangePart.split("-");
      start = assertInRange(parseInt(fromStr, 10));
      end = assertInRange(parseInt(toStr, 10));
    } else {
      start = assertInRange(parseInt(rangePart, 10));
      end = max;
    }

    const result: number[] = [];
    for (let v = start; v <= end; v += step) {
      result.push(v);
    }
    return result;
  }

  // Range: start-end
  if (expr.includes("-")) {
    const [fromStr, toStr] = expr.split("-");
    const from = assertInRange(parseInt(fromStr, 10));
    const to = assertInRange(parseInt(toStr, 10));
    return range(from, to);
  }

  // Single number
  const num = parseInt(expr, 10);
  if (isNaN(num)) {
    throw new SyntaxError(`Invalid cron expression token "${expr}" in field "${fieldName}"`);
  }

  // Normalise day-of-week: 7 (Sunday alias) → 0
  const normalised = fieldName === "dayOfWeek" && num === 7 ? 0 : num;
  assertInRange(normalised);
  return [normalised];
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${parts.length}`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = parts;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(domExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dowExpr, "dayOfWeek"),
  };
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be greater than 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be greater than 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be greater than 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      const tokensToAdd = intervals * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be greater than 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens must be greater than 0"));
    if (tokens > this.maxTokens) return Promise.reject(new RangeError("tokens exceeds maxTokens and can never be satisfied"));

    return new Promise((resolve) => {
      const attempt = () => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();
        const deficit = tokens - this.currentTokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const delay = Math.max(1, intervalsNeeded * this.refillIntervalMs);

        setTimeout(attempt, delay);
      };

      attempt();
    });
  }
}

export default RateLimiter;

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronFields;

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: Record<FieldName, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_ORDER: FieldName[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Value ${value} out of range [${min}, ${max}] in field "${context}"`
    );
  }
}

function expandRange(start: number, end: number, step: number, config: FieldConfig, context: string): number[] {
  if (start > end) {
    throw new RangeError(
      `Range start ${start} exceeds end ${end} in field "${context}"`
    );
  }
  if (step < 1) {
    throw new RangeError(
      `Step value ${step} must be >= 1 in field "${context}"`
    );
  }

  assertInRange(start, config.min, config.max, context);
  assertInRange(end, config.min, config.max, context);

  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(segment: string, config: FieldConfig, context: string): number[] {
  const trimmed = segment.trim();

  if (trimmed === "") {
    throw new SyntaxError(`Empty segment in field "${context}"`);
  }

  // Step value: */n or start-end/n
  if (trimmed.includes("/")) {
    const slashParts = trimmed.split("/");
    if (slashParts.length !== 2) {
      throw new SyntaxError(`Invalid step expression "${trimmed}" in field "${context}"`);
    }

    const [rangeOrWild, rawStep] = slashParts;
    const step = Number(rawStep);

    if (!Number.isInteger(step) || step < 1) {
      throw new RangeError(`Step "${rawStep}" must be a positive integer in field "${context}"`);
    }

    if (rangeOrWild === "*") {
      return expandRange(config.min, config.max, step, config, context);
    }

    if (rangeOrWild.includes("-")) {
      const dashParts = rangeOrWild.split("-");
      if (dashParts.length !== 2) {
        throw new SyntaxError(`Invalid range in step "${trimmed}" in field "${context}"`);
      }
      const start = Number(dashParts[0]);
      const end = Number(dashParts[1]);
      if (!Number.isInteger(start) || !Number.isInteger(end)) {
        throw new SyntaxError(`Non-integer range bounds in "${trimmed}" in field "${context}"`);
      }
      return expandRange(start, end, step, config, context);
    }

    // Single value / step — e.g. "5/15": start at 5, step by 15
    const start = Number(rangeOrWild);
    if (!Number.isInteger(start)) {
      throw new SyntaxError(`Invalid step base "${rangeOrWild}" in field "${context}"`);
    }
    return expandRange(start, config.max, step, config, context);
  }

  // Wildcard
  if (trimmed === "*") {
    return expandRange(config.min, config.max, 1, config, context);
  }

  // Range: n-m
  if (trimmed.includes("-")) {
    const dashParts = trimmed.split("-");
    if (dashParts.length !== 2) {
      throw new SyntaxError(`Invalid range "${trimmed}" in field "${context}"`);
    }
    const start = Number(dashParts[0]);
    const end = Number(dashParts[1]);
    if (!Number.isInteger(start) || !Number.isInteger(end)) {
      throw new SyntaxError(`Non-integer range bounds in "${trimmed}" in field "${context}"`);
    }
    return expandRange(start, end, 1, config, context);
  }

  // Plain number
  const value = Number(trimmed);
  if (!Number.isInteger(value)) {
    throw new SyntaxError(`Non-integer value "${trimmed}" in field "${context}"`);
  }

  // Normalize dayOfWeek: treat 7 as Sunday (0)
  const normalized = context === "dayOfWeek" && value === 7 ? 0 : value;

  assertInRange(normalized, config.min, config.max, context);
  return [normalized];
}

function parseField(raw: string, config: FieldConfig, context: string): number[] {
  if (typeof raw !== "string" || raw.trim() === "") {
    throw new SyntaxError(`Missing or empty field "${context}"`);
  }

  const segments = raw.split(",");
  if (segments.length === 0) {
    throw new SyntaxError(`No segments in field "${context}"`);
  }

  const collected = new Set<number>();

  for (const segment of segments) {
    const values = parseSegment(segment, config, context);
    for (const v of values) {
      collected.add(v);
    }
  }

  return Array.from(collected).sort((a, b) => a - b);
}

export function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(`Expected a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();

  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const parts = trimmed.split(/\s+/);

  if (parts.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields, got ${parts.length}. Format: "minute hour dayOfMonth month dayOfWeek"`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    const config = FIELD_CONFIGS[fieldName];
    result[fieldName] = parseField(parts[i], config, fieldName);
  }

  return result;
}

export default parseCron;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

class RateLimiter {
