interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronExpression;

interface FieldConfig {
  readonly name: FieldName;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute",     min: 0, max: 59 },
  { name: "hour",       min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month",      min: 1, max: 12 },
  { name: "dayOfWeek",  min: 0, max: 7  }, // 0 and 7 both represent Sunday
] as const;

const INTEGER_RE = /^\d+$/;

function assertValidInt(raw: string, context: string): number {
  if (!INTEGER_RE.test(raw)) {
    throw new SyntaxError(`Expected integer, got "${raw}" in field "${context}"`);
  }
  const n = parseInt(raw, 10);
  if (!isFinite(n)) {
    throw new SyntaxError(`Non-finite integer "${raw}" in field "${context}"`);
  }
  return n;
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of valid range [${min}, ${max}] in field "${context}"`
    );
  }
}

function expandRange(start: number, end: number, step: number, context: string): number[] {
  if (start > end) {
    throw new RangeError(
      `Range start ${start} exceeds end ${end} in field "${context}"`
    );
  }
  if (step <= 0 || !isFinite(step)) {
    throw new RangeError(
      `Step must be a positive integer, got ${step} in field "${context}"`
    );
  }
  const values: number[] = [];
  for (let v = start; v <= end; v += step) {
    values.push(v);
  }
  return values;
}

function parseSegment(segment: string, config: FieldConfig): number[] {
  const { name, min, max } = config;

  // Step: */n or start-end/n or start/n
  if (segment.includes("/")) {
    const slashParts = segment.split("/");
    if (slashParts.length !== 2) {
      throw new SyntaxError(
        `Invalid step expression "${segment}" in field "${name}"`
      );
    }
    const [rangePart, stepStr] = slashParts;
    const step = assertValidInt(stepStr, name);
    if (step <= 0) {
      throw new RangeError(`Step must be > 0 in field "${name}"`);
    }

    if (rangePart === "*") {
      return expandRange(min, max, step, name);
    }

    if (rangePart.includes("-")) {
      const dashParts = rangePart.split("-");
      if (dashParts.length !== 2) {
        throw new SyntaxError(
          `Invalid range in step expression "${segment}" in field "${name}"`
        );
      }
      const start = assertValidInt(dashParts[0], name);
      const end   = assertValidInt(dashParts[1], name);
      assertInRange(start, min, max, name);
      assertInRange(end,   min, max, name);
      return expandRange(start, end, step, name);
    }

    // Bare number with step: treat as start through max
    const start = assertValidInt(rangePart, name);
    assertInRange(start, min, max, name);
    return expandRange(start, max, step, name);
  }

  // Wildcard
  if (segment === "*") {
    return expandRange(min, max, 1, name);
  }

  // Range: start-end
  if (segment.includes("-")) {
    const dashParts = segment.split("-");
    if (dashParts.length !== 2) {
      throw new SyntaxError(
        `Invalid range expression "${segment}" in field "${name}"`
      );
    }
    const start = assertValidInt(dashParts[0], name);
    const end   = assertValidInt(dashParts[1], name);
    assertInRange(start, min, max, name);
    assertInRange(end,   min, max, name);
    return expandRange(start, end, 1, name);
  }

  // Single value
  const value = assertValidInt(segment, name);
  assertInRange(value, min, max, name);
  return [value];
}

function parseField(field: string, config: FieldConfig): number[] {
  if (field.length === 0) {
    throw new SyntaxError(`Empty field for "${config.name}"`);
  }

  const segments = field.split(",");

  if (segments.some((s) => s.length === 0)) {
    throw new SyntaxError(
      `Trailing or consecutive commas in field "${config.name}"`
    );
  }

  const valueSet = new Set<number>();

  for (const segment of segments) {
    for (const v of parseSegment(segment.trim(), config)) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(`Cron expression must be a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed.length === 0) {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const config = FIELD_CONFIGS[i];
    let values = parseField(fields[i], config);

    // Normalize dayOfWeek: both 0 and 7 represent Sunday
    if (config.name === "dayOfWeek") {
      const normalized = new Set(values.map((v) => (v === 7 ? 0 : v)));
      values = Array.from(normalized).sort((a, b) => a - b);
    }

    result[config.name] = values;
  }

  return result;
}

