type CronObject = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldConfig = {
  min: number;
  max: number;
};

const FIELD_CONFIGS: Record<keyof CronObject, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const range = (start: number, end: number): number[] =>
  Array.from({ length: end - start + 1 }, (_, i) => start + i);

const validateValue = (value: number, config: FieldConfig, field: string): number => {
  if (!Number.isInteger(value) || value < config.min || value > config.max) {
    throw new RangeError(
      `Value ${value} out of range [${config.min}-${config.max}] for field "${field}"`
    );
  }
  return value;
};

const parseSegment = (segment: string, config: FieldConfig, field: string): number[] => {
  // Wildcard
  if (segment === "*") {
    return range(config.min, config.max);
  }

  // Step: */n or start/n
  if (segment.includes("/")) {
    const [base, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step < 1) {
      throw new SyntaxError(`Invalid step value "${stepStr}" in field "${field}"`);
    }

    let start = config.min;
    let end = config.max;

    if (base !== "*") {
      if (base.includes("-")) {
        const [rangeStart, rangeEnd] = base.split("-").map(Number);
        start = validateValue(rangeStart, config, field);
        end   = validateValue(rangeEnd,   config, field);
        if (start > end) {
          throw new RangeError(`Invalid range ${base} in field "${field}"`);
        }
      } else {
        start = validateValue(parseInt(base, 10), config, field);
      }
    }

    const values: number[] = [];
    for (let v = start; v <= end; v += step) {
      values.push(v);
    }
    return values;
  }

  // Range: a-b
  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2) {
      throw new SyntaxError(`Invalid range "${segment}" in field "${field}"`);
    }
    const start = validateValue(parseInt(parts[0], 10), config, field);
    const end   = validateValue(parseInt(parts[1], 10), config, field);
    if (start > end) {
      throw new RangeError(`Start of range must be <= end in field "${field}": "${segment}"`);
    }
    return range(start, end);
  }

  // Single number
  const num = parseInt(segment, 10);
  if (isNaN(num)) {
    throw new SyntaxError(`Invalid value "${segment}" in field "${field}"`);
  }
  return [validateValue(num, config, field)];
};

const parseField = (expression: string, config: FieldConfig, field: string): number[] => {
  const segments = expression.split(",");
  const valueSet = new Set<number>();

  for (const segment of segments) {
    const trimmed = segment.trim();
    if (!trimmed) {
      throw new SyntaxError(`Empty segment in field "${field}"`);
    }
    for (const v of parseSegment(trimmed, config, field)) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
};

const parseCron = (expression: string): CronObject => {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute:     parseField(minuteExpr, FIELD_CONFIGS.minute,     "minute"),
    hour:       parseField(hourExpr,   FIELD_CONFIGS.hour,       "hour"),
    dayOfMonth: parseField(domExpr,    FIELD_CONFIGS.dayOfMonth, "dayOfMonth"),
    month:      parseField(monthExpr,  FIELD_CONFIGS.month,      "month"),
    dayOfWeek:  parseField(dowExpr,    FIELD_CONFIGS.dayOfWeek,  "dayOfWeek"),
  };
};

