interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
} as const;

type FieldName = keyof typeof FIELD_RANGES;

function clampAndDedupe(values: number[], min: number, max: number): number[] {
  const filtered = [...new Set(values)].filter((v) => v >= min && v <= max);
  filtered.sort((a, b) => a - b);
  return filtered;
}

function range(start: number, end: number): number[] {
  if (start > end) throw new Error(`Invalid range: ${start}-${end}`);
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Wildcard: *
  if (segment === "*") {
    return range(min, max);
  }

  // Step with wildcard: */N
  const stepWildcardMatch = segment.match(/^\*\/(\d+)$/);
  if (stepWildcardMatch) {
    const step = parseInt(stepWildcardMatch[1], 10);
    if (step <= 0) throw new Error(`Invalid step value: ${step}`);
    const values: number[] = [];
    for (let i = min; i <= max; i += step) {
      values.push(i);
    }
    return values;
  }

  // Step with range: N-M/S
  const stepRangeMatch = segment.match(/^(\d+)-(\d+)\/(\d+)$/);
  if (stepRangeMatch) {
    const start = parseInt(stepRangeMatch[1], 10);
    const end = parseInt(stepRangeMatch[2], 10);
    const step = parseInt(stepRangeMatch[3], 10);
    if (step <= 0) throw new Error(`Invalid step value: ${step}`);
    const values: number[] = [];
    for (let i = start; i <= end; i += step) {
      values.push(i);
    }
    return clampAndDedupe(values, min, max);
  }

  // Range: N-M
  const rangeMatch = segment.match(/^(\d+)-(\d+)$/);
  if (rangeMatch) {
    const start = parseInt(rangeMatch[1], 10);
    const end = parseInt(rangeMatch[2], 10);
    return clampAndDedupe(range(start, end), min, max);
  }

  // Single number
  const numMatch = segment.match(/^(\d+)$/);
  if (numMatch) {
    const value = parseInt(numMatch[1], 10);
    if (value < min || value > max) {
      throw new Error(`Value ${value} out of range [${min}, ${max}]`);
    }
    return [value];
  }

  throw new Error(`Invalid cron segment: "${segment}"`);
}

function parseField(field: string, min: number, max: number): number[] {
  // Comma-separated list
  const parts = field.split(",");
  if (parts.length > 1) {
    const values = parts.flatMap((part) => parseSegment(part.trim(), min, max));
    return clampAndDedupe(values, min, max);
  }

  return parseSegment(field.trim(), min, max);
}

function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new Error("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Expected 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteField, hourField, domField, monthField, dowField] = fields;
  const fieldNames: FieldName[] = [
    "minute",
    "hour",
    "dayOfMonth",
    "month",
    "dayOfWeek",
  ];
  const fieldValues = [minuteField, hourField, domField, monthField, dowField];

  const result = {} as CronResult;

  for (let i = 0; i < fieldNames.length; i++) {
    const name = fieldNames[i];
    const { min, max } = FIELD_RANGES[name];
    try {
      let values = parseField(fieldValues[i], min, max);

      // Normalize dayOfWeek: treat 7 as 0 (both represent Sunday)
      if (name === "dayOfWeek") {
        values = clampAndDedupe(
          values.map((v) => (v === 7 ? 0 : v)),
          0,
          6
        );
      }

      result[name] = values;
    } catch (err) {
      throw new Error(
        `Invalid ${name} field "${fieldValues[i]}": ${(err as Error).message}`
      );
    }
  }

  return result;
}

export default parseCron;

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldConfig = {
  min: number;
  max: number;
};

const FIELD_CONFIGS: Record<keyof CronResult, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const range = (start: number, end: number, step = 1): number[] => {
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
};

const parseField = (field: string, config: FieldConfig): number[] => {
  const { min, max } = config;

  const assertInRange = (value: number, label = "Value"): void => {
    if (value < min || value > max) {
      throw new RangeError(`${label} ${value} is out of range [${min}, ${max}]`);
    }
  };

  // Wildcard
  if (field === "*") {
    return range(min, max);
  }

  // Comma-separated list — split and recursively parse each part
  if (field.includes(",")) {
    const parts = field.split(",");
    const values = new Set<number>();
    for (const part of parts) {
      for (const v of parseField(part.trim(), config)) {
        values.add(v);
      }
    }
    return Array.from(values).sort((a, b) => a - b);
  }

  // Step value: */step or start-end/step
  if (field.includes("/")) {
    const [rangePart, stepPart] = field.split("/");
    const step = parseInt(stepPart, 10);

    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: "${stepPart}"`);
    }

    let start = min;
    let end = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [startStr, endStr] = rangePart.split("-");
        start = parseInt(startStr, 10);
        end = parseInt(endStr, 10);
        if (isNaN(start) || isNaN(end)) {
          throw new Error(`Invalid range in step expression: "${rangePart}"`);
        }
        assertInRange(start, "Range start");
        assertInRange(end, "Range end");
        if (start > end) {
          throw new RangeError(`Range start ${start} is greater than end ${end}`);
        }
      } else {
        start = parseInt(rangePart, 10);
        if (isNaN(start)) {
          throw new Error(`Invalid step expression: "${field}"`);
        }
        assertInRange(start, "Step base");
        end = max;
      }
    }

    return range(start, end, step);
  }

  // Range: start-end
  if (field.includes("-")) {
    const [startStr, endStr] = field.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);

    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range: "${field}"`);
    }

    assertInRange(start, "Range start");
    assertInRange(end, "Range end");

    if (start > end) {
      throw new RangeError(`Range start ${start} is greater than end ${end}`);
    }

    return range(start, end);
  }

  // Single numeric value
  const value = parseInt(field, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid cron field value: "${field}"`);
  }
  assertInRange(value);
  return [value];
};

const parseCron = (expression: string): CronResult => {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${fields.length}`
    );
  }

  const [minuteField, hourField, domField, monthField, dowField] = fields;
  const keys = Object.keys(FIELD_CONFIGS) as (keyof CronResult)[];

  const [minute, hour, dayOfMonth, month, dayOfWeek] = [
    minuteField,
    hourField,
    domField,
    monthField,
    dowField,
  ].map((field, i) => parseField(field, FIELD_CONFIGS[keys[i]]));

  return { minute, hour, dayOfMonth, month, dayOfWeek };
};

export default parseCron;

type CronObject = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldConfig = {
  min: number;
  max: number;
};

const FIELD_CONFIGS: Record<keyof CronObject, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_NAMES = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"] as const;

function rangeArray(start: number, end: number, step = 1): number[] {
  if (step < 1) throw new Error(`Step must be >= 1, got ${step}`);
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function dedup(values: number[]): number[] {
  return [...new Set(values)].sort((a, b) => a - b);
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of range [${min}, ${max}] in field "${context}"`);
  }
}

function parseField(raw: string, fieldName: string, config: FieldConfig): number[] {
  const { min, max } = config;
  const parts = raw.split(",");

  const values: number[] = [];

  for (const part of parts) {
    const trimmed = part.trim();

    // Wildcard: *
    if (trimmed === "*") {
      values.push(...rangeArray(min, max));
      continue;
    }

    // Step with wildcard: */N
    const stepWildcardMatch = trimmed.match(/^\*\/(\d+)$/);
    if (stepWildcardMatch) {
      const step = parseInt(stepWildcardMatch[1], 10);
      if (step < 1) throw new Error(`Step must be >= 1 in field "${fieldName}"`);
      values.push(...rangeArray(min, max, step));
      continue;
    }

    // Range with optional step: N-M or N-M/S
    const rangeMatch = trimmed.match(/^(\d+)-(\d+)(?:\/(\d+))?$/);
    if (rangeMatch) {
      const rangeStart = parseInt(rangeMatch[1], 10);
      const rangeEnd   = parseInt(rangeMatch[2], 10);
      const step       = rangeMatch[3] ? parseInt(rangeMatch[3], 10) : 1;

      assertInRange(rangeStart, min, max, fieldName);
      assertInRange(rangeEnd,   min, max, fieldName);

      if (rangeStart > rangeEnd) {
        throw new Error(`Range start ${rangeStart} > end ${rangeEnd} in field "${fieldName}"`);
      }
      if (step < 1) throw new Error(`Step must be >= 1 in field "${fieldName}"`);

      values.push(...rangeArray(rangeStart, rangeEnd, step));
      continue;
    }

    // Step from value: N/S
    const stepValueMatch = trimmed.match(/^(\d+)\/(\d+)$/);
    if (stepValueMatch) {
      const start = parseInt(stepValueMatch[1], 10);
      const step  = parseInt(stepValueMatch[2], 10);

      assertInRange(start, min, max, fieldName);
      if (step < 1) throw new Error(`Step must be >= 1 in field "${fieldName}"`);

      values.push(...rangeArray(start, max, step));
      continue;
    }

    // Single number
    const numMatch = trimmed.match(/^(\d+)$/);
    if (numMatch) {
      const num = parseInt(numMatch[1], 10);
      assertInRange(num, min, max, fieldName);
      values.push(num);
      continue;
    }

    throw new Error(`Invalid cron field value "${trimmed}" in field "${fieldName}"`);
  }

  return dedup(values);
}

export default function parseCron(expression: string): CronObject {
  if (typeof expression !== "string" || expression.trim() === "") {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Expected 5 cron fields, got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronObject;

  for (let i = 0; i < FIELD_NAMES.length; i++) {
    const name = FIELD_NAMES[i];
    result[name] = parseField(fields[i], name, FIELD_CONFIGS[name]);
  }

  return result;
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
};

function assertInRange(value: number, field: CronField): void {
  const { min, max } = FIELD_RANGES[field];
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of range [${min}, ${max}] for field "${field}"`
    );
  }
}

function expandRange(start: number, end: number, field: CronField): number[] {
  if (start > end) {
    throw new RangeError(
      `Invalid range ${start}-${end} for field "${field}": start must be <= end`
    );
  }
  assertInRange(start, field);
  assertInRange(end, field);
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function parseSegment(segment: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];

  // Step: */n or range/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) {
      throw new TypeError(`Invalid step value "${stepStr}" in field "${field}"`);
    }

    let base: number[];
    if (rangePart === "*") {
      base = Array.from({ length: max - min + 1 }, (_, i) => i + min);
    } else if (rangePart.includes("-")) {
      const [startStr, endStr] = rangePart.split("-");
      base = expandRange(parseInt(startStr, 10), parseInt(endStr, 10), field);
    } else {
      const start = parseInt(rangePart, 10);
      assertInRange(start, field);
      base = Array.from({ length: max - start + 1 }, (_, i) => i + start);
    }

    return base.filter((_, i) => i % step === 0);
  }

  // Wildcard
  if (segment === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => i + min);
  }

  // Range: n-m
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    return expandRange(parseInt(startStr, 10), parseInt(endStr, 10), field);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new TypeError(`Invalid value "${segment}" in field "${field}"`);
  }
  assertInRange(value, field);
  return [value];
}

function parseField(expression: string, field: CronField): number[] {
  const segments = expression.split(",");
  const values = segments.flatMap((seg) => parseSegment(seg.trim(), field));

  // Normalize Sunday: both 0 and 7 map to 0 for dayOfWeek
  const normalized =
    field === "dayOfWeek"
      ? values.map((v) => (v === 7 ? 0 : v))
      : values;

  // Deduplicate and sort
  return [...new Set(normalized)].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new TypeError("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new TypeError(
      `Cron expression must have exactly 5 fields, got ${fields.length}`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(domExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dowExpr, "dayOfWeek"),
  };
}

export interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface Waiter {
  tokens: number;
  resolve: () => void;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;

  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: Waiter[];
  private timerScheduled: boolean;

  constructor(options: RateLimiterOptions) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError(`maxTokens must be a positive finite number, got ${options.maxTokens}`);
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate <= 0) {
      throw new RangeError(`refillRate must be a positive finite number, got ${options.refillRate}`);
    }
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0) {
      throw new RangeError(`refillIntervalMs must be a positive finite number, got ${options.refillIntervalMs}`);
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
    this.timerScheduled = false;
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = Math.max(0, now - this.lastRefillTime);

    if (elapsed === 0) return;

    const tokensToAdd = (elapsed / this.refillIntervalMs) * this.refillRate;
    this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
    this.lastRefillTime = now;
  }

  private msUntilAvailable(tokens: number): number {
    const deficit = tokens - this.currentTokens;
    if (deficit <= 0) return 0;
    return Math.ceil((deficit / this.refillRate) * this.refillIntervalMs);
  }

  private drainQueue(): void {
    this.timerScheduled = false;

    while (this.waitQueue.length > 0) {
      const waiter = this.waitQueue[0];

      this.refill();

      if (this.currentTokens >= waiter.tokens) {
        this.currentTokens -= waiter.tokens;
        this.waitQueue.shift();
        waiter.resolve();
      } else {
        if (!this.timerScheduled) {
          const delay = Math.max(1, this.msUntilAvailable(waiter.tokens));
          this.timerScheduled = true;
          setTimeout(() => this.drainQueue(), delay);
        }
        break;
      }
    }
  }

  private validateTokenCount(tokens: number, context: string): void {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError(`${context}: tokens must be a non-negative finite number, got ${tokens}`);
    }
  }

  tryConsume(tokens: number = 1): boolean {
    this.validateTokenCount(tokens, "tryConsume");

    if (tokens > this.maxTokens) return false;
    if (tokens === 0) return true;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.drainQueue();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    this.validateTokenCount(tokens, "waitForTokens");

    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `waitForTokens: requested ${tokens} tokens exceeds maxTokens (${this.maxTokens}) — this request can never be satisfied`
        )
      );
    }

    if (tokens === 0) return Promise.resolve();

    return new Promise<void>((resolve) => {
      const waiter: Waiter = { tokens, resolve };
      this.waitQueue.push(waiter);

      if (this.waitQueue.length === 1) {
        this.drainQueue();
      }
    });
  }
}

export default RateLimiter;

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_BOUNDS: Record<keyof CronExpression, readonly [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 7],
} as const;

function buildRange(start: number, end: number): number[] {
  if (start > end) throw new RangeError(`Range start ${start} exceeds end ${end}`);
  const out: number[] = [];
  for (let i = start; i <= end; i++) out.push(i);
  return out;
}

function assertInBounds(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(`${context}: value ${value} is outside valid range [${min}, ${max}]`);
  }
}

function parseSegment(token: string, min: number, max: number, depth = 0): number[] {
  // Guard against deeply nested/malformed inputs (e.g. recursive comma expansion)
  if (depth > 1) throw new Error(`Unexpected nesting in cron token: "${token}"`);

  // Allowlist: only digits, commas, hyphens, asterisks, and slashes
  if (!/^[\d,\-*/]+$/.test(token)) {
    throw new SyntaxError(`Invalid characters in cron token: "${token}"`);
  }

  // Comma-separated list — split and recurse, then merge & sort
  if (token.includes(",")) {
    const parts = token.split(",");
    if (parts.length > 128) throw new RangeError(`Excessive comma-separated values in token: "${token}"`);
    const seen = new Set<number>();
    for (const part of parts) {
      if (!part) throw new SyntaxError(`Empty value in comma-separated list: "${token}"`);
      for (const v of parseSegment(part, min, max, depth + 1)) seen.add(v);
    }
    return Array.from(seen).sort((a, b) => a - b);
  }

  // Step value: <range-or-wildcard>/<step>
  if (token.includes("/")) {
    const slashIdx = token.indexOf("/");
    const rangePart = token.slice(0, slashIdx);
    const stepPart = token.slice(slashIdx + 1);

    if (!rangePart || !stepPart) throw new SyntaxError(`Malformed step expression: "${token}"`);

    const step = Number(stepPart);
    if (!Number.isInteger(step) || step <= 0) {
      throw new RangeError(`Step must be a positive integer, got: "${stepPart}"`);
    }
    if (step > max - min + 1) {
      throw new RangeError(`Step ${step} exceeds the field range [${min}, ${max}]`);
    }

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      [start, end] = parseBoundedRange(rangePart, min, max);
    } else {
      start = Number(rangePart);
      assertInBounds(start, min, max, `step base "${token}"`);
      end = max;
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) values.push(i);
    return values;
  }

  // Wildcard — expands to full field range
  if (token === "*") {
    return buildRange(min, max);
  }

  // Bare range: start-end
  if (token.includes("-")) {
    const [start, end] = parseBoundedRange(token, min, max);
    return buildRange(start, end);
  }

  // Single numeric value
  const num = Number(token);
  if (!Number.isInteger(num)) throw new SyntaxError(`Non-integer value in cron token: "${token}"`);
  assertInBounds(num, min, max, `value "${token}"`);
  return [num];
}

function parseBoundedRange(token: string, min: number, max: number): [number, number] {
  const dashIdx = token.indexOf("-");
  if (dashIdx <= 0 || dashIdx === token.length - 1) {
    throw new SyntaxError(`Malformed range: "${token}"`);
  }
  const startStr = token.slice(0, dashIdx);
  const endStr = token.slice(dashIdx + 1);

  // Reject additional dashes (e.g. "1-5-9")
  if (endStr.includes("-")) throw new SyntaxError(`Malformed range: "${token}"`);

  const start = Number(startStr);
  const end = Number(endStr);

  if (!Number.isInteger(start)) throw new SyntaxError(`Non-integer range start: "${startStr}"`);
  if (!Number.isInteger(end)) throw new SyntaxError(`Non-integer range end: "${endStr}"`);

  assertInBounds(start, min, max, `range start in "${token}"`);
  assertInBounds(end, min, max, `range end in "${token}"`);

  if (start > end) throw new RangeError(`Range start ${start} exceeds end ${end} in "${token}"`);

  return [start, end];
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (!trimmed) throw new SyntaxError("Cron expression must not be empty");

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), got ${fields.length}`
    );
  }

  const [minuteToken, hourToken, domToken, monthToken, dowToken] = fields;
  const [minuteMin, minuteMax] = FIELD_BOUNDS.minute;
  const [hourMin, hourMax] = FIELD_BOUNDS.hour;
  const [domMin, domMax] = FIELD_BOUNDS.dayOfMonth;
  const [monthMin, monthMax] = FIELD_BOUNDS.month;
  const [dowMin, dowMax] = FIELD_BOUNDS.dayOfWeek;

  return {
    minute: parseSegment(minuteToken, minuteMin, minuteMax),
    hour: parseSegment(hourToken, hourMin, hourMax),
    dayOfMonth: parseSegment(domToken, domMin, domMax),
    month: parseSegment(monthToken, monthMin, monthMax),
    dayOfWeek: parseSegment(dowToken, dowMin, dowMax),
  };
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 7],
};

const range = (start: number, end: number): number[] =>
  Array.from({ length: end - start + 1 }, (_, i) => start + i);

const clamp = (value: number, min: number, max: number): number =>
  Math.max(min, Math.min(max, value));

const parseField = (
  field: string,
  fieldName: keyof CronFields
): number[] => {
  const [min, max] = FIELD_RANGES[fieldName];

  const parseToken = (token: string): number[] => {
    // Step value: */n or start-end/n
    if (token.includes("/")) {
      const [rangePart, stepStr] = token.split("/");
      const step = parseInt(stepStr, 10);

      if (isNaN(step) || step <= 0) {
        throw new Error(`Invalid step value in field "${fieldName}": "${token}"`);
      }

      let start = min;
      let end = max;

      if (rangePart !== "*") {
        if (rangePart.includes("-")) {
          const [s, e] = rangePart.split("-").map(Number);
          start = clamp(s, min, max);
          end = clamp(e, min, max);
        } else {
          start = clamp(parseInt(rangePart, 10), min, max);
        }
      }

      const values: number[] = [];
      for (let i = start; i <= end; i += step) {
        values.push(i);
      }
      return values;
    }

    // Wildcard
    if (token === "*") {
      return range(min, max);
    }

    // Range: start-end
    if (token.includes("-")) {
      const parts = token.split("-");
      if (parts.length !== 2) {
        throw new Error(`Invalid range in field "${fieldName}": "${token}"`);
      }
      const start = parseInt(parts[0], 10);
      const end = parseInt(parts[1], 10);

      if (isNaN(start) || isNaN(end)) {
        throw new Error(`Non-numeric range in field "${fieldName}": "${token}"`);
      }
      if (start > end) {
        throw new Error(`Range start > end in field "${fieldName}": "${token}"`);
      }

      const clampedStart = clamp(start, min, max);
      const clampedEnd = clamp(end, min, max);

      if (start < min || end > max) {
        throw new Error(
          `Range out of bounds in field "${fieldName}": "${token}" (valid: ${min}-${max})`
        );
      }

      return range(clampedStart, clampedEnd);
    }

    // Single number
    const num = parseInt(token, 10);
    if (isNaN(num)) {
      throw new Error(`Invalid value in field "${fieldName}": "${token}"`);
    }
    if (num < min || num > max) {
      throw new Error(
        `Value out of range in field "${fieldName}": ${num} (valid: ${min}-${max})`
      );
    }

    return [num];
  };

  // Comma-separated list
  const tokens = field.split(",");
  const allValues = tokens.flatMap(parseToken);

  // Normalize dayOfWeek: treat 7 as 0 (both mean Sunday)
  const normalized =
    fieldName === "dayOfWeek"
      ? allValues.map((v) => (v === 7 ? 0 : v))
      : allValues;

  // Deduplicate and sort
  return [...new Set(normalized)].sort((a, b) => a - b);
};

const parseCron = (expression: string): CronFields => {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteField, hourField, domField, monthField, dowField] = fields;

  return {
    minute: parseField(minuteField, "minute"),
    hour: parseField(hourField, "hour"),
    dayOfMonth: parseField(domField, "dayOfMonth"),
    month: parseField(monthField, "month"),
    dayOfWeek: parseField(dowField, "dayOfWeek"),
  };
};

export default parseCron;
export type { CronFields };

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface WaitEntry {
  tokens: number;
  resolve: () => void;
  reject: (err: Error) => void;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;

  private currentTokens: number;
  private lastRefillTime: number;

  private readonly waitQueue: WaitEntry[] = [];
  private drainScheduled = false;

  constructor(options: RateLimiterOptions) {
    const { maxTokens, refillRate, refillIntervalMs } = options;

    if (!Number.isFinite(maxTokens) || maxTokens <= 0) {
      throw new RangeError(`maxTokens must be a finite positive number, got ${maxTokens}`);
    }
    if (!Number.isFinite(refillRate) || refillRate < 0) {
      throw new RangeError(`refillRate must be a finite non-negative number, got ${refillRate}`);
    }
    if (!Number.isFinite(refillIntervalMs) || refillIntervalMs <= 0) {
      throw new RangeError(`refillIntervalMs must be a finite positive number, got ${refillIntervalMs}`);
    }

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.currentTokens = maxTokens;
    this.lastRefillTime = Date.now();
  }

  private applyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed <= 0 || this.refillRate === 0) return;

    const added = (elapsed / this.refillIntervalMs) * this.refillRate;
    if (added <= 0) return;

    this.currentTokens = Math.min(this.maxTokens, this.currentTokens + added);
    this.lastRefillTime = now;
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError(`tokens must be a finite non-negative number, got ${tokens}`);
    }
    if (tokens > this.maxTokens) return false;

    this.applyRefill();

    if (this.currentTokens < tokens) return false;

    this.currentTokens -= tokens;
    return true;
  }

  getTokens(): number {
    this.applyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.scheduleDrain(0);
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0) {
      return Promise.reject(
        new RangeError(`tokens must be a finite non-negative number, got ${tokens}`)
      );
    }
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds bucket capacity of ${this.maxTokens}; ` +
          `can never be satisfied`
        )
      );
    }

    // Fast path: no queue contention and enough tokens right now
    if (this.waitQueue.length === 0) {
      this.applyRefill();
      if (this.currentTokens >= tokens) {
        this.currentTokens -= tokens;
        return Promise.resolve();
      }
    }

    // Reject immediately if refill is impossible and current tokens are insufficient
    if (this.refillRate === 0 && this.currentTokens < tokens) {
      return Promise.reject(
        new Error(
          `Cannot satisfy request for ${tokens} tokens: bucket has ` +
          `${this.currentTokens} tokens and refillRate is 0`
        )
      );
    }

    return new Promise<void>((resolve, reject) => {
      this.waitQueue.push({ tokens, resolve, reject });
      if (!this.drainScheduled) {
        this.scheduleDrain(this.msUntilTokens(tokens));
      }
    });
  }

  private msUntilTokens(tokens: number): number {
    this.applyRefill();
    const deficit = tokens - this.currentTokens;
    if (deficit <= 0) return 0;
    if (this.refillRate === 0) return Infinity;
    return Math.ceil((deficit / this.refillRate) * this.refillIntervalMs);
  }

  private scheduleDrain(delayMs: number): void {
    if (this.drainScheduled || this.waitQueue.length === 0) return;
    if (!isFinite(delayMs)) return; // refillRate=0 with deficit; drain won't help

    this.drainScheduled = true;
    setTimeout(() => {
      this.drainScheduled = false;
      this.drainQueue();
    }, Math.max(0, delayMs));
  }

  private drainQueue(): void {
    this.applyRefill();

    while (this.waitQueue.length > 0) {
      const entry = this.waitQueue[0];

      if (this.currentTokens >= entry.tokens) {
        this.currentTokens -= entry.tokens;
        this.waitQueue.shift();
        entry.resolve();
      } else {
        // Not enough tokens yet — schedule next attempt
        const wait = this.msUntilTokens(entry.tokens);
        if (!isFinite(wait)) {
          // Reject this entry and every subsequent one if refill is impossible
          for (const e of this.waitQueue.splice(0)) {
            e.reject(
              new Error(
                `Cannot satisfy request for ${e.tokens} tokens: ` +
                `refillRate is 0 and insufficient tokens remain`
              )
            );
          }
          return;
        }
        this.scheduleDrain(wait);
        return;
      }
    }
  }
}

export default RateLimiter;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 7],
};

function parseField(expr: string, min: number, max: number): number[] {
  const values = new Set<number>();

  for (const part of expr.split(",")) {
    const trimmed = part.trim();

    if (trimmed === "*") {
      for (let i = min; i <= max; i++) values.add(i);
      continue;
    }

    const stepMatch = trimmed.match(/^(\*|(\d+)-(\d+))\/(\d+)$/);
    if (stepMatch) {
      const step = parseInt(stepMatch[4], 10);
      if (step <= 0) throw new Error(`Invalid step value: ${step}`);
      const rangeMin = stepMatch[1] === "*" ? min : parseInt(stepMatch[2], 10);
      const rangeMax = stepMatch[1] === "*" ? max : parseInt(stepMatch[3], 10);
      validateRange(rangeMin, rangeMax, min, max);
      for (let i = rangeMin; i <= rangeMax; i += step) values.add(i);
      continue;
    }

    const rangeMatch = trimmed.match(/^(\d+)-(\d+)$/);
    if (rangeMatch) {
      const lo = parseInt(rangeMatch[1], 10);
      const hi = parseInt(rangeMatch[2], 10);
      validateRange(lo, hi, min, max);
      for (let i = lo; i <= hi; i++) values.add(i);
      continue;
    }

    if (/^\d+$/.test(trimmed)) {
      const n = parseInt(trimmed, 10);
      if (n < min || n > max) {
        throw new Error(`Value ${n} is out of range [${min}, ${max}]`);
      }
      values.add(n);
      continue;
    }

    throw new Error(`Unrecognized cron field expression: "${trimmed}"`);
  }

  return Array.from(values).sort((a, b) => a - b);
}

function validateRange(lo: number, hi: number, min: number, max: number): void {
  if (lo > hi) throw new Error(`Invalid range: ${lo}-${hi} (start > end)`);
  if (lo < min || hi > max) {
    throw new Error(`Range ${lo}-${hi} is out of bounds [${min}, ${max}]`);
  }
}

function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new Error("Cron expression must be a string");
  }

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(
      `Expected 5 fields, got ${parts.length}: "${expression}"`
    );
  }

  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];

  const result = {} as CronFields;

  for (let i = 0; i < fieldNames.length; i++) {
    const name = fieldNames[i];
    const [min, max] = FIELD_RANGES[name];
    try {
      let values = parseField(parts[i], min, max);

      // Normalize dayOfWeek: treat 7 as 0 (both mean Sunday)
      if (name === "dayOfWeek") {
        const normalized = new Set(values.map((v) => (v === 7 ? 0 : v)));
        values = Array.from(normalized).sort((a, b) => a - b);
      }

      result[name] = values;
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      throw new Error(`Invalid ${name} field ("${parts[i]}"): ${message}`);
    }
  }

  return result;
}

