  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${fields.length}`
    );
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] =
    fields;

  return {
    minute: parseField(minuteExpr, ...FIELD_RANGES.minute),
    hour: parseField(hourExpr, ...FIELD_RANGES.hour),
    dayOfMonth: parseField(dayOfMonthExpr, ...FIELD_RANGES.dayOfMonth),
