type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: Record<CronField, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_ORDER: CronField[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}]`);
  }
  return value;
}

function range(start: number, end: number): number[] {
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function parseSegment(segment: string, config: FieldConfig): number[] {
  const { min, max } = config;

  // Step: */N or start-end/N
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) {
      throw new Error(`Invalid step value: ${stepStr}`);
    }

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      const [s, e] = rangePart.split("-").map(Number);
      start = clamp(s, min, max);
      end = clamp(e, min, max);
    } else {
      start = clamp(parseInt(rangePart, 10), min, max);
      end = max;
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) {
      values.push(i);
    }
    return values;
  }

  // Wildcard
  if (segment === "*") {
    return range(min, max);
  }

  // Range: N-M
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = clamp(parseInt(startStr, 10), min, max);
    const end = clamp(parseInt(endStr, 10), min, max);
    if (start > end) {
      throw new RangeError(`Invalid range ${segment}: start must be <= end`);
    }
    return range(start, end);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid cron segment: ${segment}`);
  }
  return [clamp(value, min, max)];
}

function parseField(field: string, config: FieldConfig): number[] {
  const segments = field.split(",");
  const values = new Set<number>();

  for (const segment of segments) {
    for (const value of parseSegment(segment.trim(), config)) {
      values.add(value);
    }
  }

  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${fields.length}`
    );
  }

  const result = {} as CronResult;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    result[fieldName] = parseField(fields[i], FIELD_CONFIGS[fieldName]);
  }

  return result;
}

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronExpression;

interface FieldConfig {
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIG: Readonly<Record<FieldName, FieldConfig>> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
} as const;

const FIELD_ORDER: readonly FieldName[] = [
  'minute', 'hour', 'dayOfMonth', 'month', 'dayOfWeek',
] as const;

function parseStrictInt(raw: string, context: string): number {
  if (!/^\d+$/.test(raw)) {
    throw new Error(`Invalid value "${raw}" in ${context}: must be a non-negative integer`);
  }
  return parseInt(raw, 10);
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new Error(
      `Value ${value} is out of range [${min}–${max}] in ${context}`
    );
  }
}

function expandRange(
  start: number,
  end: number,
  step: number,
  config: FieldConfig,
  context: string,
): number[] {
  if (step <= 0) {
    throw new Error(`Step must be a positive integer in ${context}, got ${step}`);
  }
  if (start > end) {
    throw new Error(`Range start ${start} exceeds end ${end} in ${context}`);
  }
  assertInRange(start, config.min, config.max, context);
  assertInRange(end,   config.min, config.max, context);

  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(
  segment: string,
  config: FieldConfig,
  context: string,
): number[] {
  // Wildcard: "*" or "*/n"
  if (segment === '*') {
    return expandRange(config.min, config.max, 1, config, context);
  }

  if (segment.startsWith('*/')) {
    const step = parseStrictInt(segment.slice(2), context);
    return expandRange(config.min, config.max, step, config, context);
  }

  // Range with optional step: "a-b" or "a-b/n"
  const rangeMatch = /^(\d+)-(\d+)(?:\/(\d+))?$/.exec(segment);
  if (rangeMatch !== null) {
    const start = parseStrictInt(rangeMatch[1], context);
    const end   = parseStrictInt(rangeMatch[2], context);
    const step  = rangeMatch[3] !== undefined
      ? parseStrictInt(rangeMatch[3], context)
      : 1;
    return expandRange(start, end, step, config, context);
  }

  // Plain number
  if (/^\d+$/.test(segment)) {
    const value = parseInt(segment, 10);
    assertInRange(value, config.min, config.max, context);
    return [value];
  }

  throw new Error(`Unrecognized segment "${segment}" in ${context}`);
}

function parseField(
  expression: string,
  config: FieldConfig,
  field: FieldName,
): number[] {
  if (expression.length === 0) {
    throw new Error(`Field "${field}" must not be empty`);
  }

  const segments = expression.split(',');
  const seen = new Set<number>();

  for (const raw of segments) {
    const segment = raw.trim();
    if (segment.length === 0) {
      throw new Error(`Empty segment in "${expression}" for field "${field}"`);
    }
    for (const v of parseSegment(segment, config, `field "${field}"`)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== 'string' || expression.trim().length === 0) {
    throw new Error('parseCron expects a non-empty string');
  }

  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 whitespace-separated fields, got ${parts.length}`
    );
  }

  return FIELD_ORDER.reduce<CronExpression>((acc, field, index) => {
    acc[field] = parseField(parts[index], FIELD_CONFIG[field], field);
    return acc;
  }, {} as CronExpression);
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

const range = (start: number, end: number): number[] =>
  Array.from({ length: end - start + 1 }, (_, i) => start + i);

const parseField = (field: string, min: number, max: number): number[] => {
  const allValues = range(min, max);

  if (field === "*") return allValues;

  if (field.startsWith("*/")) {
    const step = parseInt(field.slice(2), 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step value: ${field}`);
    return allValues.filter((v) => (v - min) % step === 0);
  }

  if (field.includes(",")) {
    const parts = field.split(",");
    const values = new Set<number>();
    for (const part of parts) {
      for (const v of parseField(part.trim(), min, max)) {
        values.add(v);
      }
    }
    return Array.from(values).sort((a, b) => a - b);
  }

  if (field.includes("-")) {
    const [startStr, endStr, stepStr] = field.split(/[-/]/);
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    const step = stepStr !== undefined ? parseInt(stepStr, 10) : 1;

    if (isNaN(start) || isNaN(end) || isNaN(step) || step <= 0) {
      throw new Error(`Invalid range expression: ${field}`);
    }
    if (start < min || end > max || start > end) {
      throw new Error(`Range ${field} out of bounds [${min}, ${max}]`);
    }
    return range(start, end).filter((v) => (v - start) % step === 0);
  }

  const num = parseInt(field, 10);
  if (isNaN(num)) throw new Error(`Invalid cron field value: ${field}`);
  if (num < min || num > max) throw new Error(`Value ${num} out of range [${min}, ${max}]`);
  return [num];
};

const parseCron = (expression: string): CronFields => {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(`Expected 5 fields, got ${parts.length}`);
  }

  const [minuteStr, hourStr, dayOfMonthStr, monthStr, dayOfWeekStr] = parts;
  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];
  const fieldValues = [minuteStr, hourStr, dayOfMonthStr, monthStr, dayOfWeekStr];

  return fieldNames.reduce((acc, name, i) => {
    const [min, max] = FIELD_RANGES[name];
    acc[name] = parseField(fieldValues[i], min, max);
    return acc;
  }, {} as CronFields);
};

export default parseCron;

export interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      const tokensToAdd = intervals * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens must be > 0"));
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(`Requested tokens (${tokens}) exceed maxTokens (${this.maxTokens})`)
      );
    }

    return new Promise<void>((resolve) => {
      const attempt = (): void => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();
        const deficit = tokens - this.currentTokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const waitMs = Math.max(1, intervalsNeeded * this.refillIntervalMs);

        setTimeout(attempt, waitMs);
      };

      attempt();
    });
  }
}

export default RateLimiter;

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

const range = (start: number, end: number): number[] =>
  Array.from({ length: end - start + 1 }, (_, i) => start + i);

const parseField = (field: string, min: number, max: number): number[] => {
  const allValues = range(min, max);

  if (field === "*") return allValues;

  if (field.startsWith("*/")) {
    const step = parseInt(field.slice(2), 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step value: ${field}`);
    return allValues.filter((v) => (v - min) % step === 0);
  }

  if (field.includes(",")) {
    const values = field
      .split(",")
      .flatMap((part) => parseField(part.trim(), min, max));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  if (field.includes("-")) {
    const [startStr, rest] = field.split("-");
    const [endStr, stepStr] = rest.includes("/") ? rest.split("/") : [rest, undefined];

    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);

    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: ${field}`);
    if (start < min || end > max) throw new Error(`Range out of bounds: ${field} (valid: ${min}-${max})`);
    if (start > end) throw new Error(`Invalid range: start ${start} > end ${end}`);

    const rangeValues = range(start, end);

    if (stepStr !== undefined) {
      const step = parseInt(stepStr, 10);
      if (isNaN(step) || step <= 0) throw new Error(`Invalid step in range: ${field}`);
      return rangeValues.filter((_, i) => i % step === 0);
    }

    return rangeValues;
  }

  const num = parseInt(field, 10);
  if (isNaN(num)) throw new Error(`Invalid cron field value: ${field}`);
  if (num < min || num > max) throw new Error(`Value ${num} out of bounds (valid: ${min}-${max})`);

  return [num];
};

const parseCron = (expression: string): CronResult => {
  if (typeof expression !== "string") throw new Error("Cron expression must be a string");

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) throw new Error(`Expected 5 fields, got ${parts.length}`);

  const [minuteStr, hourStr, dayOfMonthStr, monthStr, dayOfWeekStr] = parts;
  const fields = Object.keys(FIELD_RANGES) as (keyof CronResult)[];
  const values = [minuteStr, hourStr, dayOfMonthStr, monthStr, dayOfWeekStr];

  const result = {} as CronResult;

  for (let i = 0; i < fields.length; i++) {
    const key = fields[i];
    const [min, max] = FIELD_RANGES[key];
    result[key] = parseField(values[i], min, max);
  }

  return result;
};

export default parseCron;

interface RateLimiterOptions {
