interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface Waiter {
  tokens: number;
  resolve: () => void;
  reject: (reason: Error) => void;
}

export default class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;

  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waiters: Waiter[] = [];
  private scheduledCheck: ReturnType<typeof setTimeout> | null = null;

  constructor(options: RateLimiterOptions) {
    const { maxTokens, refillRate, refillIntervalMs } = options;

    if (!Number.isFinite(maxTokens) || maxTokens <= 0) {
      throw new RangeError(
        `maxTokens must be a positive finite number; received ${maxTokens}`
      );
    }
    if (!Number.isFinite(refillRate) || refillRate <= 0) {
      throw new RangeError(
        `refillRate must be a positive finite number; received ${refillRate}`
      );
    }
    if (!Number.isFinite(refillIntervalMs) || refillIntervalMs <= 0) {
      throw new RangeError(
        `refillIntervalMs must be a positive finite number; received ${refillIntervalMs}`
      );
    }

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.currentTokens = maxTokens;
    this.lastRefillTime = Date.now();
  }

  private lazyRefill(): void {
    const now = Date.now();
    const elapsed = Math.max(0, now - this.lastRefillTime);
    if (elapsed < this.refillIntervalMs) return;

    const intervals = Math.floor(elapsed / this.refillIntervalMs);
    this.currentTokens = Math.min(
      this.maxTokens,
      this.currentTokens + intervals * this.refillRate
    );
    // Advance anchor by whole intervals only — preserves fractional carry-over
    this.lastRefillTime += intervals * this.refillIntervalMs;
  }

  tryConsume(tokens = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError(
        `tokens must be a non-negative finite number; received ${tokens}`
      );
    }
    if (tokens === 0) return true;
    // A request larger than the bucket can ever hold is permanently impossible
    if (tokens > this.maxTokens) return false;

    this.lazyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }
    return false;
  }

  getTokens(): number {
    this.lazyRefill();
    return this.currentTokens;
  }

  reset(): void {
    if (this.scheduledCheck !== null) {
      clearTimeout(this.scheduledCheck);
      this.scheduledCheck = null;
    }
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.drainWaiters();
    if (this.waiters.length > 0) {
      this.scheduleWaiterCheck();
    }
  }

  async waitForTokens(tokens = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError(
        `tokens must be a non-negative finite number; received ${tokens}`
      );
    }
    if (tokens === 0) return;
    if (tokens > this.maxTokens) {
      throw new RangeError(
        `Requested ${tokens} tokens exceeds maxTokens (${this.maxTokens}); ` +
          `this request can never be satisfied`
      );
    }

    this.lazyRefill();

    // Fast path: nothing queued ahead and bucket has enough
    if (this.waiters.length === 0 && this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return;
    }

    return new Promise<void>((resolve, reject) => {
      this.waiters.push({ tokens, resolve, reject });
      if (this.scheduledCheck === null) {
        this.scheduleWaiterCheck();
      }
    });
  }

  private drainWaiters(): void {
    // FIFO: a waiter cannot jump the queue even if tokens are sufficient,
    // because the earlier waiter is accumulating toward its own threshold.
    while (this.waiters.length > 0) {
      const waiter = this.waiters[0];
      if (this.currentTokens >= waiter.tokens) {
        this.currentTokens -= waiter.tokens;
        this.waiters.shift();
        waiter.resolve();
      } else {
        break;
      }
    }
  }

  private scheduleWaiterCheck(): void {
    if (this.waiters.length === 0) return;

    const firstWaiter = this.waiters[0];
    const tokensNeeded = firstWaiter.tokens - this.currentTokens;

    if (tokensNeeded <= 0) {
      // Should have been drained already; recover defensively
      this.drainWaiters();
      if (this.waiters.length > 0) this.scheduleWaiterCheck();
      return;
    }

    const now = Date.now();
    const msIntoCurrentInterval = Math.max(0, now - this.lastRefillTime);
    const msUntilNextRefill = this.refillIntervalMs - msIntoCurrentInterval;

    // How many complete refill intervals are needed on top of the current bucket?
    const refillsNeeded = Math.ceil(tokensNeeded / this.refillRate);
    // First refill fires in msUntilNextRefill; subsequent ones every refillIntervalMs
    const msUntilSufficient =
      msUntilNextRefill + (refillsNeeded - 1) * this.refillIntervalMs;

    this.scheduledCheck = setTimeout(() => {
      this.scheduledCheck = null;
      this.lazyRefill();
      this.drainWaiters();
      if (this.waiters.length > 0) {
        this.scheduleWaiterCheck();
      }
    }, Math.max(0, msUntilSufficient));
  }
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
