export default RateLimiter;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: Record<keyof CronFields, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function buildRange(start: number, end: number, step: number): number[] {
  if (step <= 0) throw new Error(`Step must be a positive integer, got ${step}`);
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function assertInRange(value: number, config: FieldConfig, context: string): void {
  if (value < config.min || value > config.max) {
    throw new RangeError(
      `Value ${value} out of valid range [${config.min}-${config.max}] in: "${context}"`
    );
  }
}

function parseAtom(token: string, config: FieldConfig): number[] {
  const { min, max } = config;

  // Step: */n or start-end/n or start/n
  if (token.includes('/')) {
    const parts = token.split('/');
    if (parts.length !== 2) {
      throw new SyntaxError(`Malformed step expression: "${token}"`);
    }
    const [rangeOrStar, stepRaw] = parts;
    const step = parseInt(stepRaw, 10);
    if (!Number.isFinite(step) || step <= 0) {
      throw new RangeError(`Step must be a positive integer in: "${token}"`);
    }

    let start: number;
    let end: number;

    if (rangeOrStar === '*') {
      start = min;
      end = max;
    } else if (rangeOrStar.includes('-')) {
      const rangeParts = rangeOrStar.split('-');
      if (rangeParts.length !== 2) {
        throw new SyntaxError(`Malformed range in step expression: "${token}"`);
      }
      start = parseInt(rangeParts[0], 10);
      end   = parseInt(rangeParts[1], 10);
      if (!Number.isFinite(start) || !Number.isFinite(end)) {
        throw new SyntaxError(`Non-numeric range bounds in: "${token}"`);
      }
    } else {
      start = parseInt(rangeOrStar, 10);
      if (!Number.isFinite(start)) {
        throw new SyntaxError(`Non-numeric start value in: "${token}"`);
      }
      end = max;
    }

    assertInRange(start, config, token);
    assertInRange(end, config, token);
    if (start > end) {
      throw new RangeError(`Range start ${start} exceeds end ${end} in: "${token}"`);
    }

    return buildRange(start, end, step);
  }

  // Range: start-end
  if (token.includes('-')) {
    const parts = token.split('-');
    if (parts.length !== 2) {
      throw new SyntaxError(`Malformed range expression: "${token}"`);
    }
    const start = parseInt(parts[0], 10);
    const end   = parseInt(parts[1], 10);
    if (!Number.isFinite(start) || !Number.isFinite(end)) {
      throw new SyntaxError(`Non-numeric range bounds in: "${token}"`);
    }
    assertInRange(start, config, token);
    assertInRange(end,   config, token);
    if (start > end) {
      throw new RangeError(`Range start ${start} exceeds end ${end} in: "${token}"`);
    }
    return buildRange(start, end, 1);
  }

  // Wildcard
  if (token === '*') {
    return buildRange(min, max, 1);
  }

  // Literal number
  const value = parseInt(token, 10);
  if (!Number.isFinite(value) || String(value) !== token) {
    throw new SyntaxError(`Unrecognised cron token: "${token}"`);
  }
  assertInRange(value, config, token);
  return [value];
}

function parseField(field: string, config: FieldConfig): number[] {
  if (!field || typeof field !== 'string') {
    throw new TypeError(`Field must be a non-empty string, got: ${JSON.stringify(field)}`);
  }

  // Comma-separated list — each atom is parsed independently
  if (field.includes(',')) {
    const seen = new Set<number>();
    for (const atom of field.split(',')) {
      const trimmed = atom.trim();
      if (!trimmed) throw new SyntaxError(`Empty atom in comma list: "${field}"`);
      for (const v of parseAtom(trimmed, config)) {
        seen.add(v);
      }
    }
    return Array.from(seen).sort((a, b) => a - b);
  }

  return parseAtom(field, config);
}

function parseCron(expression: string): CronFields {
  if (!expression || typeof expression !== 'string') {
    throw new TypeError('Cron expression must be a non-empty string');
  }

  const tokens = expression.trim().split(/\s+/);

  if (tokens.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${tokens.length}: "${expression}"`
    );
  }

  const [minuteToken, hourToken, domToken, monthToken, dowToken] = tokens;

  return {
    minute:     parseField(minuteToken, FIELD_CONFIGS.minute),
    hour:       parseField(hourToken,   FIELD_CONFIGS.hour),
    dayOfMonth: parseField(domToken,    FIELD_CONFIGS.dayOfMonth),
    month:      parseField(monthToken,  FIELD_CONFIGS.month),
    dayOfWeek:  parseField(dowToken,    FIELD_CONFIGS.dayOfWeek),
  };
}

export default parseCron;

interface CronSchedule {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronSchedule, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function parseNumber(token: string, min: number, max: number): number {
  const n = parseInt(token, 10);
  if (isNaN(n)) throw new SyntaxError(`Invalid number: "${token}"`);
  return clamp(n, min, max);
}

function expandRange(from: number, to: number, step: number, min: number, max: number): number[] {
  if (from > to) throw new RangeError(`Range start ${from} exceeds end ${to}`);
  clamp(from, min, max);
  clamp(to, min, max);
  if (step < 1) throw new RangeError(`Step must be >= 1, got ${step}`);

  const values: number[] = [];
  for (let i = from; i <= to; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Step on wildcard: */n
  if (segment.startsWith("*/")) {
    const step = parseInt(segment.slice(2), 10);
    if (isNaN(step) || step < 1) throw new SyntaxError(`Invalid step: "${segment}"`);
    return expandRange(min, max, step, min, max);
  }

  // Wildcard: *
  if (segment === "*") {
    return expandRange(min, max, 1, min, max);
  }

  // Range with optional step: n-m or n-m/s
  if (segment.includes("-")) {
    const [rangePart, stepPart] = segment.split("/");
    const [startStr, endStr] = rangePart.split("-");
    const start = parseNumber(startStr, min, max);
    const end   = parseNumber(endStr,   min, max);
    const step  = stepPart !== undefined ? parseInt(stepPart, 10) : 1;
    if (isNaN(step) || step < 1) throw new SyntaxError(`Invalid step in segment: "${segment}"`);
    return expandRange(start, end, step, min, max);
  }

  // Plain number
  return [parseNumber(segment, min, max)];
}

function parseField(field: string, min: number, max: number): number[] {
  const parts = field.split(",");
  const values = new Set<number>();

  for (const part of parts) {
    const trimmed = part.trim();
    if (!trimmed) throw new SyntaxError(`Empty segment in field: "${field}"`);
    for (const v of parseSegment(trimmed, min, max)) {
      // Normalize dayOfWeek: treat 7 as 0 (both = Sunday)
      values.add(v);
    }
  }

  return [...values].sort((a, b) => a - b);
}

function parseCron(expression: string): CronSchedule {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteField, hourField, domField, monthField, dowField] = fields;
  const keys = Object.keys(FIELD_RANGES) as (keyof CronSchedule)[];

  const [minute, hour, dayOfMonth, month, rawDayOfWeek] = [
    minuteField, hourField, domField, monthField, dowField,
  ].map((f, i) => {
    const { min, max } = FIELD_RANGES[keys[i]];
    return parseField(f, min, max);
  });

  // Normalize dayOfWeek: map 7 → 0 (both mean Sunday), then deduplicate
  const normalizedDow = [...new Set(rawDayOfWeek.map((d) => (d === 7 ? 0 : d)))].sort(
    (a, b) => a - b
  );

  return { minute, hour, dayOfMonth, month, dayOfWeek: normalizedDow };
}

export default parseCron;

type CronObject = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldConfig = {
  min: number;
  max: number;
};

const FIELD_CONFIGS: FieldConfig[] = [
  { min: 0, max: 59 },  // minute
  { min: 0, max: 23 },  // hour
  { min: 1, max: 31 },  // dayOfMonth
  { min: 1, max: 12 },  // month
  { min: 0, max: 7 },   // dayOfWeek (0 and 7 both = Sunday)
];

const FIELD_NAMES = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"] as const;

function parseInteger(value: string, fieldName: string): number {
  const num = Number(value);
  if (!Number.isInteger(num) || value.trim() === "") {
    throw new Error(`Invalid value "${value}" in field "${fieldName}"`);
  }
  return num;
}

function expandRange(start: number, end: number, config: FieldConfig, fieldName: string): number[] {
  if (start > end) {
    throw new Error(`Invalid range ${start}-${end} in field "${fieldName}": start must be <= end`);
  }
  if (start < config.min || end > config.max) {
    throw new Error(
      `Range ${start}-${end} out of bounds [${config.min}-${config.max}] in field "${fieldName}"`
    );
  }
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function parseSegment(segment: string, config: FieldConfig, fieldName: string): number[] {
  // Step value: */step or range/step
  if (segment.includes("/")) {
    const [rangePart, stepPart] = segment.split("/");
    const step = parseInteger(stepPart, fieldName);
    if (step <= 0) {
      throw new Error(`Step value must be positive in field "${fieldName}"`);
    }

    let base: number[];
    if (rangePart === "*") {
      base = expandRange(config.min, config.max, config, fieldName);
    } else if (rangePart.includes("-")) {
      const [startStr, endStr] = rangePart.split("-");
      const start = parseInteger(startStr, fieldName);
      const end = parseInteger(endStr, fieldName);
      base = expandRange(start, end, config, fieldName);
    } else {
      const start = parseInteger(rangePart, fieldName);
      base = expandRange(start, config.max, config, fieldName);
    }

    return base.filter((_, index) => index % step === 0);
  }

  // Wildcard
  if (segment === "*") {
    return expandRange(config.min, config.max, config, fieldName);
  }

  // Range: start-end
  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2) {
      throw new Error(`Invalid range "${segment}" in field "${fieldName}"`);
    }
    const start = parseInteger(parts[0], fieldName);
    const end = parseInteger(parts[1], fieldName);
    return expandRange(start, end, config, fieldName);
  }

  // Single number
  const num = parseInteger(segment, fieldName);
  if (num < config.min || num > config.max) {
    throw new Error(
      `Value ${num} out of bounds [${config.min}-${config.max}] in field "${fieldName}"`
    );
  }
  return [num];
}

function parseField(field: string, config: FieldConfig, fieldName: string): number[] {
  const segments = field.split(",");
  if (segments.length === 0 || segments.some((s) => s.trim() === "")) {
    throw new Error(`Invalid field "${field}" in "${fieldName}"`);
  }

  const values = new Set<number>();
  for (const segment of segments) {
    for (const v of parseSegment(segment.trim(), config, fieldName)) {
      values.add(v);
    }
  }

  const result = Array.from(values).sort((a, b) => a - b);

  // Normalize dayOfWeek: treat 7 as 0 (Sunday)
  if (fieldName === "dayOfWeek") {
    const normalized = new Set(result.map((v) => (v === 7 ? 0 : v)));
    return Array.from(normalized).sort((a, b) => a - b);
  }

  return result;
}

function parseCron(expression: string): CronObject {
  if (typeof expression !== "string" || expression.trim() === "") {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronObject;
  for (let i = 0; i < 5; i++) {
    const name = FIELD_NAMES[i];
    result[name] = parseField(fields[i], FIELD_CONFIGS[i], name);
  }

  return result;
}

export default parseCron;

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type CronFieldName = keyof CronExpression;

const FIELD_RANGES: Record<CronFieldName, [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   7],
};

const FIELD_ORDER: CronFieldName[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of valid range [${min}, ${max}] in field "${context}"`
    );
  }
}

function expandStep(
  rangeStr: string,
  stepStr: string,
  fieldMin: number,
  fieldMax: number,
  fieldName: string
): number[] {
  const step = parseInt(stepStr, 10);
  if (isNaN(step) || step <= 0) {
    throw new SyntaxError(`Invalid step value "${stepStr}" in field "${fieldName}"`);
  }

  let start: number;
  let end: number;

  if (rangeStr === "*") {
    start = fieldMin;
    end = fieldMax;
  } else if (rangeStr.includes("-")) {
    const parts = rangeStr.split("-");
    if (parts.length !== 2) {
      throw new SyntaxError(`Invalid range "${rangeStr}" in field "${fieldName}"`);
    }
    start = parseInt(parts[0], 10);
    end = parseInt(parts[1], 10);
    assertInRange(start, fieldMin, fieldMax, fieldName);
    assertInRange(end, fieldMin, fieldMax, fieldName);
    if (start > end) {
      throw new RangeError(
        `Range start ${start} exceeds end ${end} in field "${fieldName}"`
      );
    }
  } else {
    start = parseInt(rangeStr, 10);
    if (isNaN(start)) {
      throw new SyntaxError(`Invalid step base "${rangeStr}" in field "${fieldName}"`);
    }
    assertInRange(start, fieldMin, fieldMax, fieldName);
    end = fieldMax;
  }

  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function expandAtom(
  token: string,
  fieldMin: number,
  fieldMax: number,
  fieldName: string
): number[] {
  if (token === "*") {
    const values: number[] = [];
    for (let i = fieldMin; i <= fieldMax; i++) {
      values.push(i);
    }
    return values;
  }

  if (token.includes("/")) {
    const slashIdx = token.indexOf("/");
    const rangeStr = token.slice(0, slashIdx);
    const stepStr = token.slice(slashIdx + 1);
    if (!rangeStr || !stepStr) {
      throw new SyntaxError(`Malformed step expression "${token}" in field "${fieldName}"`);
    }
    return expandStep(rangeStr, stepStr, fieldMin, fieldMax, fieldName);
  }

  if (token.includes("-")) {
    const parts = token.split("-");
    if (parts.length !== 2) {
      throw new SyntaxError(`Malformed range "${token}" in field "${fieldName}"`);
    }
    const start = parseInt(parts[0], 10);
    const end = parseInt(parts[1], 10);
    if (isNaN(start) || isNaN(end)) {
      throw new SyntaxError(`Non-numeric range bounds in "${token}" in field "${fieldName}"`);
    }
    assertInRange(start, fieldMin, fieldMax, fieldName);
    assertInRange(end, fieldMin, fieldMax, fieldName);
    if (start > end) {
      throw new RangeError(
        `Range start ${start} exceeds end ${end} in field "${fieldName}"`
      );
    }
    const values: number[] = [];
    for (let i = start; i <= end; i++) {
      values.push(i);
    }
    return values;
  }

  const num = parseInt(token, 10);
  if (isNaN(num) || String(num) !== token) {
    throw new SyntaxError(`Invalid token "${token}" in field "${fieldName}"`);
  }
  assertInRange(num, fieldMin, fieldMax, fieldName);
  return [num];
}

function parseField(
  raw: string,
  fieldMin: number,
  fieldMax: number,
  fieldName: string
): number[] {
  const trimmed = raw.trim();
  if (!trimmed) {
    throw new SyntaxError(`Empty value for field "${fieldName}"`);
  }

  const atoms = trimmed.split(",");
  if (atoms.some((a) => a.trim() === "")) {
    throw new SyntaxError(`Trailing or consecutive commas in field "${fieldName}"`);
  }

  const seen = new Set<number>();
  for (const atom of atoms) {
    for (const v of expandAtom(atom.trim(), fieldMin, fieldMax, fieldName)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(`Expected a string cron expression, got ${typeof expression}`);
  }

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${parts.length}: "${expression}"`
    );
  }

  const result = {} as CronExpression;
  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const name = FIELD_ORDER[i];
    const [min, max] = FIELD_RANGES[name];
    result[name] = parseField(parts[i], min, max, name);
  }

  return result;
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      const tokensToAdd = intervals * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens must be > 0"));
    if (tokens > this.maxTokens) return Promise.reject(new RangeError("tokens exceeds maxTokens capacity"));

    return new Promise((resolve) => {
      const attempt = () => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();
        const deficit = tokens - this.currentTokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const delay = Math.max(1, intervalsNeeded * this.refillIntervalMs);

        setTimeout(attempt, delay);
      };

      attempt();
    });
  }
}

export default RateLimiter;

export interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private tokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.tokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervalsElapsed = Math.floor(elapsed / this.refillIntervalMs);

    if (intervalsElapsed > 0) {
      this.tokens = Math.min(
        this.maxTokens,
        this.tokens + intervalsElapsed * this.refillRate
      );
      this.lastRefillTime += intervalsElapsed * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.tokens >= tokens) {
      this.tokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) {
      throw new RangeError(
        `Requested tokens (${tokens}) exceed maxTokens (${this.maxTokens})`
      );
    }

    while (!this.tryConsume(tokens)) {
      const deficit = tokens - this.tokens;
      const intervalsNeeded = Math.ceil(deficit / this.refillRate);
      const waitMs = intervalsNeeded * this.refillIntervalMs;
      await new Promise<void>((resolve) => setTimeout(resolve, waitMs));
    }
  }
}

export default RateLimiter;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
  name: string;
}

const FIELD_CONFIGS: Record<CronField, FieldConfig> = {
  minute:     { min: 0,  max: 59, name: "minute" },
  hour:       { min: 0,  max: 23, name: "hour" },
  dayOfMonth: { min: 1,  max: 31, name: "dayOfMonth" },
  month:      { min: 1,  max: 12, name: "month" },
  dayOfWeek:  { min: 0,  max: 7,  name: "dayOfWeek" },
};

const FIELD_ORDER: CronField[] = [
  "minute", "hour", "dayOfMonth", "month", "dayOfWeek",
];

function makeRange(start: number, end: number): number[] {
  if (start > end) throw new RangeError(`Invalid range: ${start}-${end}`);
  const out: number[] = [];
  for (let i = start; i <= end; i++) out.push(i);
  return out;
}

function assertBounds(value: number, config: FieldConfig): void {
  if (value < config.min || value > config.max) {
    throw new RangeError(
      `Value ${value} out of range for field "${config.name}" (${config.min}–${config.max})`
    );
  }
}

function parseInteger(raw: string, context: string): number {
  if (!/^\d+$/.test(raw)) {
    throw new SyntaxError(`Expected integer in "${context}", got "${raw}"`);
  }
  return parseInt(raw, 10);
}

function parseSegment(segment: string, config: FieldConfig): number[] {
  // Step: */n  or  a-b/n  or  a/n
  if (segment.includes("/")) {
    const slashCount = segment.split("/").length - 1;
    if (slashCount !== 1) {
      throw new SyntaxError(`Invalid step expression: "${segment}"`);
    }
    const slashIdx = segment.indexOf("/");
    const lhs = segment.slice(0, slashIdx);
    const rhs = segment.slice(slashIdx + 1);

    const step = parseInteger(rhs, segment);
    if (step <= 0) throw new RangeError(`Step must be > 0 in "${segment}"`);

    let base: number[];
    if (lhs === "*") {
      base = makeRange(config.min, config.max);
    } else if (lhs.includes("-")) {
      base = parseRangeLiteral(lhs, config);
    } else {
      const start = parseInteger(lhs, segment);
      assertBounds(start, config);
      base = makeRange(start, config.max);
    }

    const result: number[] = [];
    for (let i = 0; i < base.length; i += step) result.push(base[i]);
    return result;
  }

  // Wildcard
  if (segment === "*") {
    return makeRange(config.min, config.max);
  }

  // Range: a-b
  if (segment.includes("-")) {
    return parseRangeLiteral(segment, config);
  }

  // Single value
  const value = parseInteger(segment, segment);
  assertBounds(value, config);
  return [value];
}

function parseRangeLiteral(segment: string, config: FieldConfig): number[] {
  const parts = segment.split("-");
  if (parts.length !== 2) {
    throw new SyntaxError(`Invalid range expression: "${segment}"`);
  }
  const start = parseInteger(parts[0], segment);
  const end   = parseInteger(parts[1], segment);
  assertBounds(start, config);
  assertBounds(end,   config);
  if (start > end) {
    throw new RangeError(`Range start exceeds end in "${segment}"`);
  }
  return makeRange(start, end);
}

function parseField(raw: string, config: FieldConfig): number[] {
  if (!raw || raw.trim() === "") {
    throw new SyntaxError(`Empty value for field "${config.name}"`);
  }

  const parts = raw.split(",");
  if (parts.some(p => p.trim() === "")) {
    throw new SyntaxError(`Trailing or double comma in field "${config.name}": "${raw}"`);
  }

  const collected = new Set<number>();
  for (const part of parts) {
    for (const v of parseSegment(part.trim(), config)) {
      collected.add(v);
    }
  }

  return Array.from(collected).sort((a, b) => a - b);
}

function normalizeDayOfWeek(values: number[]): number[] {
  // 7 is an alias for 0 (Sunday) in most cron implementations
  const normalized = new Set(values.map(v => (v === 7 ? 0 : v)));
  return Array.from(normalized).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields; got ${fields.length}: "${trimmed}"`
    );
  }

  const result = {} as CronExpression;
  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const name   = FIELD_ORDER[i];
    const config = FIELD_CONFIGS[name];
    result[name] = parseField(fields[i], config);
  }

  result.dayOfWeek = normalizeDayOfWeek(result.dayOfWeek);

  return result;
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      const tokensToAdd = intervals * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens to consume must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens to consume must be > 0"));
    if (tokens > this.maxTokens) return Promise.reject(new RangeError("tokens requested exceed maxTokens"));

    return new Promise((resolve) => {
      const attempt = (): void => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();
        const deficit = tokens - this.currentTokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const delay = intervalsNeeded * this.refillIntervalMs;
        const waitMs = Math.max(1, delay);

        setTimeout(attempt, waitMs);
      };

      attempt();
    });
  }
}

export default RateLimiter;

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: Array<{ tokens: number; resolve: () => void }>;
  private pendingTimer: boolean;

  constructor(options: {
    maxTokens: number;
    refillRate: number;
    refillIntervalMs: number;
  }) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0)
      throw new RangeError("maxTokens must be a finite positive number");
    if (!Number.isFinite(options.refillRate) || options.refillRate < 0)
      throw new RangeError("refillRate must be a finite non-negative number");
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0)
      throw new RangeError("refillIntervalMs must be a finite positive number");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
    this.pendingTimer = false;
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed < this.refillIntervalMs) return;

    const intervals = Math.floor(elapsed / this.refillIntervalMs);
    const added = intervals * this.refillRate;

    this.currentTokens = Math.min(this.maxTokens, this.currentTokens + added);
    this.lastRefillTime += intervals * this.refillIntervalMs;
  }

  private drainQueue(): void {
    this.refill();

    while (this.waitQueue.length > 0) {
      const next = this.waitQueue[0]!;

      if (this.currentTokens >= next.tokens) {
        this.currentTokens -= next.tokens;
        this.waitQueue.shift();
        next.resolve();
      } else {
        break;
      }
    }
  }

  private scheduleNextDrain(): void {
    if (this.pendingTimer || this.waitQueue.length === 0) return;

    this.pendingTimer = true;

    const elapsed = Date.now() - this.lastRefillTime;
    const msUntilRefill = Math.max(0, this.refillIntervalMs - (elapsed % this.refillIntervalMs));

    setTimeout(() => {
      this.pendingTimer = false;
      this.drainQueue();

      if (this.waitQueue.length > 0) {
        this.scheduleNextDrain();
      }
    }, msUntilRefill);
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens <= 0)
      throw new RangeError("tokens must be a finite positive number");

    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.drainQueue();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens <= 0)
      return Promise.reject(new RangeError("tokens must be a finite positive number"));

    if (tokens > this.maxTokens)
      return Promise.reject(
        new RangeError(
          `Requested tokens (${tokens}) exceed maxTokens (${this.maxTokens}); can never be satisfied`
        )
      );

    this.refill();

    if (this.waitQueue.length === 0 && this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return Promise.resolve();
    }

    return new Promise<void>((resolve) => {
      this.waitQueue.push({ tokens, resolve });
      this.scheduleNextDrain();
    });
  }
}

export default RateLimiter;

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly min: number;
  readonly max: number;
  readonly name: string;
}

const FIELD_CONFIGS = {
  minute:     { min: 0,  max: 59, name: "minute"      },
  hour:       { min: 0,  max: 23, name: "hour"        },
  dayOfMonth: { min: 1,  max: 31, name: "dayOfMonth"  },
  month:      { min: 1,  max: 12, name: "month"       },
  dayOfWeek:  { min: 0,  max: 7,  name: "dayOfWeek"   },
} as const satisfies Record<keyof CronExpression, FieldConfig>;

function assertInteger(raw: string, config: FieldConfig): number {
  if (!/^\d+$/.test(raw)) {
    throw new RangeError(
      `[${config.name}] "${raw}" is not a valid non-negative integer`
    );
  }
  const n = parseInt(raw, 10);
  if (n < config.min || n > config.max) {
    throw new RangeError(
      `[${config.name}] value ${n} is outside valid range [${config.min}, ${config.max}]`
    );
  }
  return n;
}

function expandRange(start: number, end: number, config: FieldConfig): number[] {
  if (start > end) {
    throw new RangeError(
      `[${config.name}] range start (${start}) must not exceed end (${end})`
    );
  }
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function parseSegment(segment: string, config: FieldConfig): number[] {
  // Step: */n  |  a-b/n  |  a/n
  if (segment.includes("/")) {
    const slashPos = segment.lastIndexOf("/");
    const stepRaw  = segment.slice(slashPos + 1);
    const baseRaw  = segment.slice(0, slashPos);

    if (!/^\d+$/.test(stepRaw)) {
      throw new RangeError(
        `[${config.name}] step "${stepRaw}" is not a valid positive integer`
      );
    }
    const step = parseInt(stepRaw, 10);
    if (step === 0) {
      throw new RangeError(`[${config.name}] step value must not be zero`);
    }

    let rangeStart: number;
    let rangeEnd: number;

    if (baseRaw === "*") {
      rangeStart = config.min;
      rangeEnd   = config.max;
    } else if (baseRaw.includes("-")) {
      [rangeStart, rangeEnd] = parseRangePart(baseRaw, config);
    } else {
      rangeStart = assertInteger(baseRaw, config);
      rangeEnd   = config.max;
    }

    const values: number[] = [];
    for (let v = rangeStart; v <= rangeEnd; v += step) {
      values.push(v);
    }
    return values;
  }

  // Wildcard
  if (segment === "*") {
    return expandRange(config.min, config.max, config);
  }

  // Range: a-b
  if (segment.includes("-")) {
    const [start, end] = parseRangePart(segment, config);
    return expandRange(start, end, config);
  }

  // Plain integer
  return [assertInteger(segment, config)];
}

function parseRangePart(raw: string, config: FieldConfig): [number, number] {
  const dashPos = raw.indexOf("-");
  if (dashPos === 0 || dashPos === raw.length - 1) {
    throw new RangeError(`[${config.name}] malformed range "${raw}"`);
  }
  const start = assertInteger(raw.slice(0, dashPos), config);
  const end   = assertInteger(raw.slice(dashPos + 1), config);
  return [start, end];
}

function parseField(field: string, config: FieldConfig): number[] {
  if (!field || /^\s*$/.test(field)) {
    throw new RangeError(`[${config.name}] field must not be empty`);
  }

  const segments = field.split(",");

  if (segments.some(s => s === "")) {
    throw new RangeError(
      `[${config.name}] trailing or consecutive commas are not allowed in "${field}"`
    );
  }

  const merged = segments.flatMap(seg => parseSegment(seg.trim(), config));
  return [...new Set(merged)].sort((a, b) => a - b);
}

export function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const trimmed = expression.trim();
  if (trimmed.length === 0) {
    throw new RangeError("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new RangeError(
      `Cron expression requires exactly 5 fields (minute hour dayOfMonth month dayOfWeek), got ${fields.length}`
    );
  }

  const [minuteRaw, hourRaw, domRaw, monthRaw, dowRaw] = fields as [
    string, string, string, string, string
  ];

  // Parse dayOfWeek allowing 0–7 (7 = Sunday alias for 0); normalise after.
  const rawDow  = parseField(dowRaw, FIELD_CONFIGS.dayOfWeek);
  const normDow = [...new Set(rawDow.map(v => (v === 7 ? 0 : v)))].sort(
    (a, b) => a - b
  );

  return {
    minute:     parseField(minuteRaw, FIELD_CONFIGS.minute),
    hour:       parseField(hourRaw,   FIELD_CONFIGS.hour),
    dayOfMonth: parseField(domRaw,    FIELD_CONFIGS.dayOfMonth),
    month:      parseField(monthRaw,  FIELD_CONFIGS.month),
    dayOfWeek:  normDow,
  };
}

export default parseCron;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface Waiter {
  tokens: number;
  resolve: () => void;
  reject: (err: Error) => void;
}

export default class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waiters: Waiter[];
  private scheduledCheck: ReturnType<typeof setTimeout> | null;

  constructor(options: RateLimiterOptions) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new Error("maxTokens must be a positive finite number");
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate <= 0) {
      throw new Error("refillRate must be a positive finite number");
    }
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0) {
      throw new Error("refillIntervalMs must be a positive finite number");
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
    this.waiters = [];
    this.scheduledCheck = null;
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);
    if (intervals > 0) {
      this.currentTokens = Math.min(
        this.maxTokens,
        this.currentTokens + intervals * this.refillRate
      );
      // Advance to the exact interval boundary, not to `now`, to
      // preserve sub-interval fractional progress accurately.
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new Error("tokens must be a non-negative finite number");
    }
    // A request that can never be satisfied should never silently succeed.
    if (tokens > this.maxTokens) return false;
    this.refill();
    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }
    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    if (this.scheduledCheck !== null) {
      clearTimeout(this.scheduledCheck);
      this.scheduledCheck = null;
    }
    // Satisfy any queued waiters now that the bucket is full.
    this.processWaiters();
  }

  waitForTokens(tokens = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0) {
      return Promise.reject(
        new Error("tokens must be a non-negative finite number")
      );
    }
    // Reject requests that can never be satisfied instead of hanging forever.
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new Error(
          `Requested ${tokens} tokens exceeds maximum bucket capacity of ${this.maxTokens}`
        )
      );
    }

    // Fast-path: only bypass the queue when the queue is empty, to preserve
    // FIFO ordering and prevent starvation of large waiters.
    if (this.waiters.length === 0) {
      this.refill();
      if (this.currentTokens >= tokens) {
        this.currentTokens -= tokens;
        return Promise.resolve();
      }
    }

    return new Promise<void>((resolve, reject) => {
      this.waiters.push({ tokens, resolve, reject });
      this.scheduleNextCheck();
    });
  }

  private processWaiters(): void {
    this.refill();
    // Drain the queue front-to-back; stop at the first waiter we cannot
    // satisfy so that ordering is respected and partial drains are safe.
    while (this.waiters.length > 0) {
      const waiter = this.waiters[0]!;
      if (this.currentTokens >= waiter.tokens) {
        this.currentTokens -= waiter.tokens;
        this.waiters.shift();
        waiter.resolve();
      } else {
        break;
      }
    }

    if (this.waiters.length > 0) {
      this.scheduleNextCheck();
    }
  }

  private scheduleNextCheck(): void {
    // Only one pending timeout at a time; extra calls are no-ops.
    if (this.scheduledCheck !== null) return;

    // Wake up exactly when the next refill interval boundary is reached so
    // the check is neither premature nor unnecessarily delayed.
    const elapsed = Date.now() - this.lastRefillTime;
    const msUntilNextRefill =
      this.refillIntervalMs - (elapsed % this.refillIntervalMs);

    this.scheduledCheck = setTimeout(() => {
      this.scheduledCheck = null;
      this.processWaiters();
    }, msUntilNextRefill);
  }
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldRange {
  min: number;
  max: number;
  name: string;
}

const FIELD_RANGES: Record<keyof CronFields, FieldRange> = {
  minute:     { min: 0,  max: 59, name: "minute"     },
  hour:       { min: 0,  max: 23, name: "hour"        },
  dayOfMonth: { min: 1,  max: 31, name: "dayOfMonth"  },
  month:      { min: 1,  max: 12, name: "month"       },
  dayOfWeek:  { min: 0,  max: 7,  name: "dayOfWeek"   },
};

function assertInRange(value: number, range: FieldRange, context: string): void {
  if (!Number.isInteger(value) || value < range.min || value > range.max) {
    throw new RangeError(
      `Value ${value} is out of valid range [${range.min}–${range.max}] for field "${range.name}" (expression: "${context}")`
    );
  }
}

function expandRange(start: number, end: number, step: number, range: FieldRange, context: string): number[] {
  if (!Number.isInteger(step) || step <= 0) {
    throw new RangeError(`Step must be a positive integer in expression: "${context}"`);
  }
  if (start > end) {
    throw new RangeError(`Range start (${start}) exceeds end (${end}) in expression: "${context}"`);
  }
  assertInRange(start, range, context);
  assertInRange(end, range, context);

  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(segment: string, range: FieldRange): number[] {
  const trimmed = segment.trim();

  if (trimmed === "") {
    throw new SyntaxError(`Empty segment encountered in field "${range.name}"`);
  }

  // Step: */N, start/N, or start-end/N
  if (trimmed.includes("/")) {
    const slashIndex = trimmed.indexOf("/");
    const base = trimmed.slice(0, slashIndex);
    const stepRaw = trimmed.slice(slashIndex + 1);
    const step = Number(stepRaw);

    if (!Number.isInteger(step) || step <= 0 || stepRaw.trim() === "") {
      throw new SyntaxError(`Invalid step value "${stepRaw}" in expression: "${trimmed}"`);
    }

    if (base === "*") {
      return expandRange(range.min, range.max, step, range, trimmed);
    }

    if (base.includes("-")) {
      const [startRaw, endRaw, ...extra] = base.split("-");
      if (extra.length > 0) throw new SyntaxError(`Malformed range "${base}" in expression: "${trimmed}"`);
      const start = Number(startRaw);
      const end = Number(endRaw);
      if (!Number.isInteger(start) || !Number.isInteger(end)) {
        throw new SyntaxError(`Non-integer bounds in range "${base}" in expression: "${trimmed}"`);
      }
      return expandRange(start, end, step, range, trimmed);
    }

    const start = Number(base);
    if (!Number.isInteger(start) || base.trim() === "") {
      throw new SyntaxError(`Invalid start value "${base}" in expression: "${trimmed}"`);
    }
    return expandRange(start, range.max, step, range, trimmed);
  }

  // Range: start-end
  if (trimmed.includes("-")) {
    const [startRaw, endRaw, ...extra] = trimmed.split("-");
    if (extra.length > 0) throw new SyntaxError(`Malformed range "${trimmed}" in field "${range.name}"`);
    const start = Number(startRaw);
    const end = Number(endRaw);
    if (!Number.isInteger(start) || !Number.isInteger(end) || startRaw.trim() === "" || endRaw.trim() === "") {
      throw new SyntaxError(`Non-integer bounds in range "${trimmed}" in field "${range.name}"`);
    }
    return expandRange(start, end, 1, range, trimmed);
  }

  // Wildcard
  if (trimmed === "*") {
    return expandRange(range.min, range.max, 1, range, trimmed);
  }

  // Single integer
  const value = Number(trimmed);
  if (!Number.isInteger(value) || trimmed === "") {
    throw new SyntaxError(`Invalid value "${trimmed}" in field "${range.name}"`);
  }
  assertInRange(value, range, trimmed);
  return [value];
}

function parseField(expr: string, range: FieldRange): number[] {
  if (typeof expr !== "string" || expr.trim() === "") {
    throw new SyntaxError(`Missing or empty expression for field "${range.name}"`);
  }

  const segments = expr.split(",");
  if (segments.some((s) => s.trim() === "")) {
    throw new SyntaxError(`Empty segment in comma list for field "${range.name}": "${expr}"`);
  }

  const seen = new Set<number>();
  for (const segment of segments) {
    for (const value of parseSegment(segment, range)) {
      seen.add(value);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, received: ${typeof expression}`);
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), got ${fields.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  const minute     = parseField(minuteExpr, FIELD_RANGES.minute);
  const hour       = parseField(hourExpr,   FIELD_RANGES.hour);
  const dayOfMonth = parseField(domExpr,    FIELD_RANGES.dayOfMonth);
  const month      = parseField(monthExpr,  FIELD_RANGES.month);
  const dowRaw     = parseField(dowExpr,    FIELD_RANGES.dayOfWeek);

  // Normalize dayOfWeek: both 0 and 7 represent Sunday — merge into 0, deduplicate
  const dowNormalized = new Set(dowRaw.map((v) => (v === 7 ? 0 : v)));
  const dayOfWeek = Array.from(dowNormalized).sort((a, b) => a - b);

  return { minute, hour, dayOfMonth, month, dayOfWeek };
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      const tokensToAdd = intervals * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) {
      throw new RangeError(`Requested tokens (${tokens}) exceed maxTokens (${this.maxTokens})`);
    }

    while (!this.tryConsume(tokens)) {
      const deficit = tokens - this.currentTokens;
      const intervalsNeeded = Math.ceil(deficit / this.refillRate);
      const waitMs = intervalsNeeded * this.refillIntervalMs;
      const safeWait = Math.max(1, Math.min(waitMs, this.refillIntervalMs));
      await new Promise<void>((resolve) => setTimeout(resolve, safeWait));
    }
  }
}

export default RateLimiter;

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronResult;

const FIELD_RANGES: Readonly<Record<FieldName, readonly [number, number]>> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
} as const;

const FIELD_ORDER: readonly FieldName[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
] as const;

function expandRange(start: number, end: number): number[] {
  if (start > end) {
    throw new RangeError(`Range start (${start}) must not exceed end (${end})`);
  }
  const values: number[] = [];
  for (let i = start; i <= end; i++) {
    values.push(i);
  }
  return values;
}

function assertInBounds(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of bounds [${min}, ${max}] in segment "${context}"`
    );
  }
}

function parseInteger(raw: string, context: string): number {
  const trimmed = raw.trim();
  if (trimmed === "" || !/^\d+$/.test(trimmed)) {
    throw new SyntaxError(`Expected integer, got "${trimmed}" in segment "${context}"`);
  }
  const n = parseInt(trimmed, 10);
  if (isNaN(n)) {
    throw new SyntaxError(`Unparseable integer "${trimmed}" in segment "${context}"`);
  }
  return n;
}

function parseSegment(segment: string, min: number, max: number): number[] {
  const trimmed = segment.trim();
  if (trimmed === "") {
    throw new SyntaxError(`Empty segment encountered`);
  }

  // Step: */n  or  start-end/n  or  start/n
  if (trimmed.includes("/")) {
    const slashIndex = trimmed.indexOf("/");
    const rangePart = trimmed.slice(0, slashIndex);
    const stepPart = trimmed.slice(slashIndex + 1);

    const step = parseInteger(stepPart, trimmed);
    if (step < 1) {
      throw new RangeError(`Step value must be >= 1, got ${step} in "${trimmed}"`);
    }

    let rangeStart: number;
    let rangeEnd: number;

    if (rangePart === "*") {
      rangeStart = min;
      rangeEnd = max;
    } else if (rangePart.includes("-")) {
      const dashIndex = rangePart.indexOf("-");
      rangeStart = parseInteger(rangePart.slice(0, dashIndex), trimmed);
      rangeEnd = parseInteger(rangePart.slice(dashIndex + 1), trimmed);
      assertInBounds(rangeStart, min, max, trimmed);
      assertInBounds(rangeEnd, min, max, trimmed);
    } else {
      rangeStart = parseInteger(rangePart, trimmed);
      assertInBounds(rangeStart, min, max, trimmed);
      rangeEnd = max;
    }

    if (rangeStart > rangeEnd) {
      throw new RangeError(
        `Range start (${rangeStart}) exceeds end (${rangeEnd}) in "${trimmed}"`
      );
    }

    const values: number[] = [];
    for (let i = rangeStart; i <= rangeEnd; i += step) {
      values.push(i);
    }
    return values;
  }

  // Wildcard
  if (trimmed === "*") {
    return expandRange(min, max);
  }

  // Range: start-end
  if (trimmed.includes("-")) {
    const dashIndex = trimmed.indexOf("-");
    const start = parseInteger(trimmed.slice(0, dashIndex), trimmed);
    const end = parseInteger(trimmed.slice(dashIndex + 1), trimmed);
    assertInBounds(start, min, max, trimmed);
    assertInBounds(end, min, max, trimmed);
    return expandRange(start, end);
  }

  // Single value
  const value = parseInteger(trimmed, trimmed);
  assertInBounds(value, min, max, trimmed);
  return [value];
}

function parseField(raw: string, fieldName: FieldName): number[] {
  const [min, max] = FIELD_RANGES[fieldName];
  const segments = raw.split(",");

  if (segments.length === 0 || (segments.length === 1 && segments[0].trim() === "")) {
    throw new SyntaxError(`Field "${fieldName}" must not be empty`);
  }

  const valueSet = new Set<number>();

  for (const segment of segments) {
    const values = parseSegment(segment, min, max);
    for (const v of values) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, received ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${trimmed}"`
    );
  }

  const result = {} as CronResult;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    try {
      result[fieldName] = parseField(fields[i], fieldName);
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      throw new (err instanceof TypeError ? TypeError : err instanceof SyntaxError ? SyntaxError : RangeError)(
        `Invalid value for field "${fieldName}" (position ${i + 1}): ${message}`
      );
    }
  }

  return result;
}

export interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: Array<{ tokens: number; resolve: () => void }>;
  private scheduledTimeout: ReturnType<typeof setTimeout> | null;

  constructor(options: RateLimiterOptions) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError("maxTokens must be a positive finite number");
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate < 0) {
      throw new RangeError("refillRate must be a non-negative finite number");
    }
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0) {
      throw new RangeError("refillIntervalMs must be a positive finite number");
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
    this.scheduledTimeout = null;
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    if (elapsed >= this.refillIntervalMs) {
      const intervals = Math.floor(elapsed / this.refillIntervalMs);
      this.currentTokens = Math.min(
        this.maxTokens,
        this.currentTokens + intervals * this.refillRate
      );
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  private drainQueue(): void {
    while (this.waitQueue.length > 0) {
      const next = this.waitQueue[0]!;
      if (this.currentTokens >= next.tokens) {
        this.currentTokens -= next.tokens;
        this.waitQueue.shift();
        next.resolve();
      } else {
        break;
      }
    }
  }

  private scheduleNextRefill(): void {
    // Already scheduled or nothing waiting
    if (this.scheduledTimeout !== null || this.waitQueue.length === 0) return;
    // refillRate of 0 means tokens never replenish — waiters block forever
    if (this.refillRate === 0) return;

    const next = this.waitQueue[0]!;
    const tokensNeeded = next.tokens - this.currentTokens;

    if (tokensNeeded <= 0) {
      this.drainQueue();
      return;
    }

    const intervalsNeeded = Math.ceil(tokensNeeded / this.refillRate);
    const elapsed = Date.now() - this.lastRefillTime;
    // How long until the next interval boundary, with a floor of 1ms to avoid
    // busy-looping when elapsed is exactly on a boundary after floating-point drift
    const msUntilNextInterval = Math.max(1, this.refillIntervalMs - (elapsed % this.refillIntervalMs));
    const totalWaitMs = msUntilNextInterval + (intervalsNeeded - 1) * this.refillIntervalMs;

    this.scheduledTimeout = setTimeout(() => {
      this.scheduledTimeout = null;
      this.refill();
      this.drainQueue();
      this.scheduleNextRefill();
    }, totalWaitMs);
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError("tokens must be a non-negative finite number");
    }
    if (tokens === 0) return true;
    // A request larger than the bucket can ever hold will never succeed
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }
    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();

    // Cancel any pending wakeup — we'll re-evaluate immediately
    if (this.scheduledTimeout !== null) {
      clearTimeout(this.scheduledTimeout);
      this.scheduledTimeout = null;
    }

    // Resolve as many queued waiters as possible, then reschedule the rest
    this.drainQueue();
    this.scheduleNextRefill();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0) {
      return Promise.reject(new RangeError("tokens must be a non-negative finite number"));
    }
    if (tokens === 0) return Promise.resolve();
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds the bucket capacity of ${this.maxTokens}`
        )
      );
    }

    this.refill();

    // Fast path: no queue ahead of us and enough tokens available right now
    if (this.waitQueue.length === 0 && this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return Promise.resolve();
    }

    // Enqueue and arrange a wakeup
    return new Promise<void>((resolve) => {
      this.waitQueue.push({ tokens, resolve });
      this.scheduleNextRefill();
    });
  }
}

export default RateLimiter;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function rangeArray(from: number, to: number, step = 1): number[] {
  if (from > to) throw new RangeError(`Invalid range: ${from}-${to}`);
  const result: number[] = [];
  for (let i = from; i <= to; i += step) result.push(i);
  return result;
}

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Wildcard: *
  if (segment === "*") return rangeArray(min, max);

  // Step with wildcard: */N
  if (segment.startsWith("*/")) {
    const step = parseInt(segment.slice(2), 10);
    if (isNaN(step) || step < 1) throw new Error(`Invalid step value: ${segment}`);
    return rangeArray(min, max, step);
  }

  // Range with optional step: N-M or N-M/S
  if (segment.includes("-")) {
    const [rangePart, stepPart] = segment.split("/");
    const [startStr, endStr] = rangePart.split("-");
    const start = clamp(parseInt(startStr, 10), min, max);
    const end = clamp(parseInt(endStr, 10), min, max);
    const step = stepPart !== undefined ? parseInt(stepPart, 10) : 1;
    if (isNaN(step) || step < 1) throw new Error(`Invalid step value in: ${segment}`);
    return rangeArray(start, end, step);
  }

  // Step on a single value: N/S (treated as N-max/S)
  if (segment.includes("/")) {
    const [valuePart, stepPart] = segment.split("/");
    const start = clamp(parseInt(valuePart, 10), min, max);
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step < 1) throw new Error(`Invalid step value in: ${segment}`);
    return rangeArray(start, max, step);
  }

  // Literal number
  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new Error(`Invalid cron token: ${segment}`);
  return [clamp(value, min, max)];
}

function parseField(expr: string, field: CronField): number[] {
  const [min, max] = FIELD_RANGES[field];

  // Comma-separated list
  const parts = expr.split(",");
  const values = new Set<number>();

  for (const part of parts) {
    const parsed = parseSegment(part.trim(), min, max);
    for (const v of parsed) values.add(v);
  }

  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${fields.length}`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(domExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dowExpr, "dayOfWeek"),
  };
}

export interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type CronField = keyof ParsedCron;

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function assertInRange(value: number, min: number, max: number, label: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(`${label} value ${value} is out of bounds [${min}, ${max}]`);
  }
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Step: */n  or  start/n  or  start-end/n
  if (segment.includes("/")) {
    const slashIdx = segment.indexOf("/");
    const rangeExpr = segment.slice(0, slashIdx);
    const stepStr   = segment.slice(slashIdx + 1);

    const step = Number(stepStr);
    if (!Number.isInteger(step) || step < 1) {
      throw new TypeError(`Invalid step value: "${stepStr}"`);
    }

    let start = min;
    let end   = max;

    if (rangeExpr !== "*") {
      if (rangeExpr.includes("-")) {
        const [s, e] = rangeExpr.split("-").map(Number);
        assertInRange(s, min, max, "Step range start");
        assertInRange(e, min, max, "Step range end");
        if (s > e) throw new RangeError(`Range start ${s} exceeds end ${e}`);
        start = s;
        end   = e;
      } else {
        const s = Number(rangeExpr);
        assertInRange(s, min, max, "Step start");
        start = s;
      }
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) {
      values.push(i);
    }
    return values;
  }

  // Wildcard
  if (segment === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => min + i);
  }

  // Range: n-m
  if (segment.includes("-")) {
    const dashIdx = segment.indexOf("-");
    const start   = Number(segment.slice(0, dashIdx));
    const end     = Number(segment.slice(dashIdx + 1));
    assertInRange(start, min, max, "Range start");
    assertInRange(end,   min, max, "Range end");
    if (start > end) throw new RangeError(`Range start ${start} exceeds end ${end}`);
    return Array.from({ length: end - start + 1 }, (_, i) => start + i);
  }

  // Single number
  const value = Number(segment);
  assertInRange(value, min, max, "Value");
  return [value];
}

function parseField(expr: string, min: number, max: number, fieldName: CronField): number[] {
  if (!expr || /\s/.test(expr)) {
    throw new TypeError(`Invalid field expression: "${expr}"`);
  }

  const parts = expr.split(",");
  if (parts.length === 0 || parts.some(p => p === "")) {
    throw new TypeError(`Empty segment in comma list for field "${fieldName}"`);
  }

  const seen = new Set<number>();
  for (const part of parts) {
    for (const v of parseSegment(part, min, max)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): ParsedCron {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields; got ${fields.length}: "${expression}"`
    );
  }

  const fieldNames: CronField[] = [
    "minute", "hour", "dayOfMonth", "month", "dayOfWeek",
  ];

  const result = {} as ParsedCron;

  for (let i = 0; i < fieldNames.length; i++) {
    const name          = fieldNames[i];
    const { min, max }  = FIELD_RANGES[name];
    const expr          = fields[i];

    try {
      result[name] = parseField(expr, min, max, name);
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      throw new Error(`Invalid "${name}" field (expression: "${expr}"): ${msg}`);
    }
  }

  return result;
}

type RateLimiterOptions = {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
};

type Waiter = {
  tokens: number;
  resolve: () => void;
  reject: (err: Error) => void;
};

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waiters: Waiter[] = [];
  private scheduledWakeup: ReturnType<typeof setTimeout> | null = null;
  private destroyed = false;

  constructor(options: RateLimiterOptions) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0)
      throw new RangeError("maxTokens must be a finite positive number");
    if (!Number.isFinite(options.refillRate) || options.refillRate <= 0)
      throw new RangeError("refillRate must be a finite positive number");
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0)
      throw new RangeError("refillIntervalMs must be a finite positive number");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    if (elapsed > 0) {
      const added = (elapsed / this.refillIntervalMs) * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + added);
      this.lastRefillTime = now;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (this.destroyed) throw new Error("RateLimiter has been destroyed");
    if (!Number.isFinite(tokens) || tokens < 0)
      throw new RangeError("tokens must be a finite non-negative number");
    if (tokens === 0) return true;
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }
    return false;
  }

  getTokens(): number {
    if (this.destroyed) throw new Error("RateLimiter has been destroyed");
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    if (this.destroyed) throw new Error("RateLimiter has been destroyed");
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.processWaiters();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (this.destroyed) return Promise.reject(new Error("RateLimiter has been destroyed"));
    if (!Number.isFinite(tokens) || tokens < 0)
      return Promise.reject(new RangeError("tokens must be a finite non-negative number"));
    if (tokens === 0) return Promise.resolve();
    if (tokens > this.maxTokens)
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds maxTokens capacity of ${this.maxTokens}`
        )
      );

    // Only skip the queue if no one is waiting ahead of us — preserves FIFO fairness.
    if (this.waiters.length === 0 && this.tryConsume(tokens)) {
      return Promise.resolve();
    }

    return new Promise<void>((resolve, reject) => {
      this.waiters.push({ tokens, resolve, reject });
      this.scheduleWakeup();
    });
  }

  destroy(): void {
    if (this.destroyed) return;
    this.destroyed = true;

    if (this.scheduledWakeup !== null) {
      clearTimeout(this.scheduledWakeup);
      this.scheduledWakeup = null;
    }

    const pending = this.waiters.splice(0);
    for (const waiter of pending) {
      waiter.reject(new Error("RateLimiter has been destroyed"));
    }
  }

  private processWaiters(): void {
    while (this.waiters.length > 0) {
      this.refill();
      const waiter = this.waiters[0];

      if (this.currentTokens >= waiter.tokens) {
        this.currentTokens -= waiter.tokens;
        this.waiters.shift();
        waiter.resolve();
      } else {
        // Head-of-line is still blocked; stop processing to preserve order.
        break;
      }
    }

    if (this.waiters.length > 0) {
      this.scheduleWakeup();
    }
  }

  private scheduleWakeup(): void {
    // Only one timer outstanding at a time.
    if (this.scheduledWakeup !== null || this.waiters.length === 0) return;

    this.refill();
    const deficit = this.waiters[0].tokens - this.currentTokens;

    if (deficit <= 0) {
      // Tokens are already available — dispatch synchronously via microtask
      // to avoid re-entrant processing inside a caller's stack frame.
      this.scheduledWakeup = setTimeout(() => {
        this.scheduledWakeup = null;
        this.processWaiters();
      }, 0);
      return;
    }

    const msPerToken = this.refillIntervalMs / this.refillRate;
    // Add a small buffer (+1 ms) to avoid waking up a hair too early and
    // spinning due to floating-point rounding in the refill calculation.
    const delayMs = Math.ceil(deficit * msPerToken) + 1;

    this.scheduledWakeup = setTimeout(() => {
      this.scheduledWakeup = null;
      this.processWaiters();
    }, delayMs);
  }
}

export default RateLimiter;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface Waiter {
  tokens: number;
  resolve: () => void;
  reject: (err: Error) => void;
}

export default class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: Waiter[];
  private scheduledCheck: ReturnType<typeof setTimeout> | null;

  constructor(options: RateLimiterOptions) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError("maxTokens must be a finite positive number");
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate <= 0) {
      throw new RangeError("refillRate must be a finite positive number");
    }
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0) {
      throw new RangeError("refillIntervalMs must be a finite positive number");
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
    this.scheduledCheck = null;
  }

  private applyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed < this.refillIntervalMs) {
      return;
    }

    const intervals = Math.floor(elapsed / this.refillIntervalMs);
    const tokensToAdd = intervals * this.refillRate;

    this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
    // Advance lastRefillTime by whole intervals only — preserves partial interval
    this.lastRefillTime += intervals * this.refillIntervalMs;
  }

  private msUntilSatisfiable(needed: number): number {
    // Must be called after applyRefill()
    if (this.currentTokens >= needed) return 0;

    const deficit = needed - this.currentTokens;
    const intervalsNeeded = Math.ceil(deficit / this.refillRate);
    const msSinceLastRefill = Date.now() - this.lastRefillTime;
    const msUntilNextRefill = Math.max(0, this.refillIntervalMs - msSinceLastRefill);

    // First interval brings us to the next refill; subsequent ones are full intervals
    return msUntilNextRefill + (intervalsNeeded - 1) * this.refillIntervalMs;
  }

  private drainQueue(): void {
    this.applyRefill();

    while (this.waitQueue.length > 0) {
      const waiter = this.waitQueue[0];

      if (this.currentTokens >= waiter.tokens) {
        this.waitQueue.shift();
        this.currentTokens -= waiter.tokens;
        waiter.resolve();
      } else {
        // Head of queue cannot be served yet — stop to preserve FIFO ordering
        break;
      }
    }

    if (this.waitQueue.length > 0) {
      this.scheduleNextCheck();
    }
  }

  private scheduleNextCheck(): void {
    if (this.scheduledCheck !== null) return;

    const head = this.waitQueue[0];
    if (head === undefined) return;

    this.applyRefill();

    if (this.currentTokens >= head.tokens) {
      // Satisfy synchronously via microtask to avoid re-entrancy issues
      this.scheduledCheck = setTimeout(() => {
        this.scheduledCheck = null;
        this.drainQueue();
      }, 0);
      return;
    }

    const delay = this.msUntilSatisfiable(head.tokens);

    this.scheduledCheck = setTimeout(() => {
      this.scheduledCheck = null;
      this.drainQueue();
    }, delay);
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens <= 0) {
      throw new RangeError("tokens must be a finite positive number");
    }
    if (!Number.isInteger(tokens)) {
      throw new RangeError("tokens must be an integer");
    }

    // Requests that can never be satisfied
    if (tokens > this.maxTokens) return false;

    // Block tryConsume while waiters are queued to prevent starvation
    if (this.waitQueue.length > 0) return false;

    this.applyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.applyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();

    // Clear any pending check and immediately process the queue with fresh tokens
    if (this.scheduledCheck !== null) {
      clearTimeout(this.scheduledCheck);
      this.scheduledCheck = null;
    }

    if (this.waitQueue.length > 0) {
      this.scheduleNextCheck();
    }
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens <= 0) {
      return Promise.reject(new RangeError("tokens must be a finite positive number"));
    }
    if (!Number.isInteger(tokens)) {
      return Promise.reject(new RangeError("tokens must be an integer"));
    }
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested tokens (${tokens}) exceed maxTokens (${this.maxTokens}) — can never be satisfied`
        )
      );
    }

    // Fast path: no waiters ahead of us and bucket has enough
    if (this.waitQueue.length === 0) {
      this.applyRefill();
      if (this.currentTokens >= tokens) {
        this.currentTokens -= tokens;
        return Promise.resolve();
      }
    }

    return new Promise<void>((resolve, reject) => {
      this.waitQueue.push({ tokens, resolve, reject });
      this.scheduleNextCheck();
    });
  }
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
};

function clamp(values: number[], min: number, max: number): number[] {
  return values.filter((v) => v >= min && v <= max);
}

function unique(values: number[]): number[] {
  return [...new Set(values)].sort((a, b) => a - b);
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Step: */n or a-b/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: "${stepStr}"`);
    }
    let start = min;
    let end = max;
    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        [start, end] = parseRangeBounds(rangePart, min, max);
      } else {
        start = parseInt(rangePart, 10);
        end = max;
        if (isNaN(start)) throw new Error(`Invalid value: "${rangePart}"`);
      }
    }
    const result: number[] = [];
    for (let i = start; i <= end; i += step) {
      result.push(i);
    }
    return clamp(result, min, max);
  }

  // Wildcard
  if (segment === "*") {
    const result: number[] = [];
    for (let i = min; i <= max; i++) {
      result.push(i);
    }
    return result;
  }

  // Range: a-b
  if (segment.includes("-")) {
    const [start, end] = parseRangeBounds(segment, min, max);
    const result: number[] = [];
    for (let i = start; i <= end; i++) {
      result.push(i);
    }
    return clamp(result, min, max);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid cron value: "${segment}"`);
  }
  if (value < min || value > max) {
    throw new Error(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return [value];
}

function parseRangeBounds(
  rangePart: string,
  min: number,
  max: number
): [number, number] {
  const parts = rangePart.split("-");
  if (parts.length !== 2) {
    throw new Error(`Invalid range: "${rangePart}"`);
  }
  const start = parseInt(parts[0], 10);
  const end = parseInt(parts[1], 10);
  if (isNaN(start) || isNaN(end)) {
    throw new Error(`Invalid range bounds: "${rangePart}"`);
  }
  if (start < min || end > max) {
    throw new Error(
      `Range "${rangePart}" is out of bounds [${min}, ${max}]`
    );
  }
  if (start > end) {
    throw new Error(`Range start ${start} is greater than end ${end}`);
  }
  return [start, end];
}

function parseField(expression: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];
  const segments = expression.split(",");
  const values: number[] = [];

  for (const segment of segments) {
    const trimmed = segment.trim();
    if (!trimmed) throw new Error(`Empty segment in field "${field}"`);
    values.push(...parseSegment(trimmed, min, max));
  }

  let result = unique(values);

  // Normalize dayOfWeek: treat 7 as 0 (Sunday)
  if (field === "dayOfWeek") {
    result = unique(result.map((v) => (v === 7 ? 0 : v)));
  }

  return result;
}

export function parseCron(expression: string): CronResult {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Expected 5 fields but got ${fields.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(domExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dowExpr, "dayOfWeek"),
  };
}

export default parseCron;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface Waiter {
  tokens: number;
  resolve: () => void;
  reject: (err: Error) => void;
}

export default class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waiters: Waiter[] = [];
  private timerHandle: ReturnType<typeof setTimeout> | null = null;

  constructor(options: RateLimiterOptions) {
    const { maxTokens, refillRate, refillIntervalMs } = options;

    if (!Number.isFinite(maxTokens) || maxTokens <= 0)
      throw new RangeError(`maxTokens must be a positive finite number, got ${maxTokens}`);
    if (!Number.isFinite(refillRate) || refillRate <= 0)
      throw new RangeError(`refillRate must be a positive finite number, got ${refillRate}`);
    if (!Number.isFinite(refillIntervalMs) || refillIntervalMs <= 0)
      throw new RangeError(`refillIntervalMs must be a positive finite number, got ${refillIntervalMs}`);

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.currentTokens = maxTokens;
    this.lastRefillTime = Date.now();
  }

  private lazyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    if (elapsed <= 0) return;

    const added = (elapsed / this.refillIntervalMs) * this.refillRate;
    this.currentTokens = Math.min(this.maxTokens, this.currentTokens + added);
    this.lastRefillTime = now;
  }

  private validateTokenArg(tokens: number, label = "tokens"): void {
    if (!Number.isFinite(tokens) || tokens < 0)
      throw new RangeError(`${label} must be a non-negative finite number, got ${tokens}`);
  }

  tryConsume(tokens = 1): boolean {
    this.validateTokenArg(tokens);
    if (tokens === 0) return true;

    this.lazyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }
    return false;
  }

  getTokens(): number {
    this.lazyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.drainWaiters();
  }

  waitForTokens(tokens = 1): Promise<void> {
    this.validateTokenArg(tokens);

    if (tokens === 0) return Promise.resolve();

    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds maxTokens (${this.maxTokens}); ` +
            `this promise would never resolve`
        )
      );
    }

    if (this.waiters.length === 0 && this.tryConsume(tokens)) {
      return Promise.resolve();
    }

    return new Promise<void>((resolve, reject) => {
      this.waiters.push({ tokens, resolve, reject });
      this.scheduleNextCheck();
    });
  }

  private msUntilTokensAvailable(tokensNeeded: number): number {
    const deficit = tokensNeeded - this.currentTokens;
    if (deficit <= 0) return 0;
    return Math.ceil((deficit / this.refillRate) * this.refillIntervalMs);
  }

  private drainWaiters(): void {
    this.lazyRefill();

    while (this.waiters.length > 0) {
      const waiter = this.waiters[0];
      if (this.currentTokens < waiter.tokens) break;
      this.waiters.shift();
      this.currentTokens -= waiter.tokens;
      waiter.resolve();
    }

    if (this.waiters.length > 0) {
      this.scheduleNextCheck();
    }
  }

  private scheduleNextCheck(): void {
    if (this.timerHandle !== null || this.waiters.length === 0) return;

    this.lazyRefill();
    const delay = this.msUntilTokensAvailable(this.waiters[0].tokens);

    this.timerHandle = setTimeout(() => {
      this.timerHandle = null;
      this.drainWaiters();
    }, delay);
  }
}

