export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: Waiter[];
  private drainTimer: ReturnType<typeof setTimeout> | null;

  constructor(options: RateLimiterOptions) {
    const { maxTokens, refillRate, refillIntervalMs } = options;

    if (!Number.isFinite(maxTokens) || maxTokens <= 0) {
      throw new RangeError(`maxTokens must be a finite positive number, got ${maxTokens}`);
    }
    if (!Number.isFinite(refillRate) || refillRate <= 0) {
      throw new RangeError(`refillRate must be a finite positive number, got ${refillRate}`);
    }
    if (!Number.isFinite(refillIntervalMs) || refillIntervalMs <= 0) {
      throw new RangeError(`refillIntervalMs must be a finite positive number, got ${refillIntervalMs}`);
    }

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.currentTokens = maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
    this.drainTimer = null;
  }

  private applyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    if (elapsed > 0) {
      const added = (elapsed / this.refillIntervalMs) * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + added);
      this.lastRefillTime = now;
    }
  }

  private validateTokenArg(tokens: number, context: string): void {
    if (!Number.isFinite(tokens) || tokens <= 0) {
      throw new RangeError(`${context}: tokens must be a finite positive number, got ${tokens}`);
    }
  }

  tryConsume(tokens: number = 1): boolean {
    this.validateTokenArg(tokens, "tryConsume");

    // A request for more than the bucket's capacity can never succeed.
    if (tokens > this.maxTokens) return false;

    this.applyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }
    return false;
  }

  getTokens(): number {
    this.applyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    // Unblock any queued waiters that can now be served.
    this.drainQueue();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    this.validateTokenArg(tokens, "waitForTokens");

    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `waitForTokens: requested ${tokens} tokens exceeds bucket capacity of ${this.maxTokens}`
        )
      );
    }

    // Fast path: no contention and enough tokens right now.
    if (this.waitQueue.length === 0 && this.tryConsume(tokens)) {
      return Promise.resolve();
    }

    return new Promise<void>((resolve, reject) => {
      this.waitQueue.push({ tokens, resolve, reject });
      this.scheduleNextDrain();
    });
  }

  /**
   * Schedule a drain at the earliest moment the front waiter could be served.
   * Uses elapsed-time projection rather than a fixed polling interval so the
   * timer fires exactly when tokens become available, not a tick late.
   */
  private scheduleNextDrain(): void {
    if (this.drainTimer !== null || this.waitQueue.length === 0) return;

    const front = this.waitQueue[0];

    // Snapshot current tokens after a refill so the projection is accurate.
    this.applyRefill();
    const deficit = front.tokens - this.currentTokens;

    let delayMs: number;
    if (deficit <= 0) {
      // Already sufficient — defer to the next microtask via a zero timeout so
      // we don't recurse synchronously inside an in-progress drain.
      delayMs = 0;
    } else {
      // Time (ms) to accumulate `deficit` more tokens at the current fill rate.
      const msPerToken = this.refillIntervalMs / this.refillRate;
      delayMs = Math.ceil(deficit * msPerToken);
    }

    this.drainTimer = setTimeout(() => {
      this.drainTimer = null;
      this.drainQueue();
    }, delayMs);
  }

  private drainQueue(): void {
    this.applyRefill();

    while (this.waitQueue.length > 0) {
      const front = this.waitQueue[0];
      if (this.currentTokens >= front.tokens) {
        this.waitQueue.shift();
        this.currentTokens -= front.tokens;
        front.resolve();
      } else {
        // Not enough tokens for the front waiter yet; stop — preserving FIFO
        // order means we must not skip ahead to a smaller waiter.
        break;
      }
    }

    // If waiters remain, schedule the next drain for when the front can be served.
    if (this.waitQueue.length > 0) {
      this.scheduleNextDrain();
    }
  }
}

