      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) {
      throw new RangeError(`Requested tokens (${tokens}) exceed maxTokens (${this.maxTokens})`);
    }

    while (true) {
      this.refill();

      if (this.currentTokens >= tokens) {
        this.currentTokens -= tokens;
        return;
      }

      const deficit = tokens - this.currentTokens;
      const intervalsNeeded = Math.ceil(deficit / this.refillRate);
      const timeUntilRefill = this.refillIntervalMs - (Date.now() - this.lastRefillTime);
      const waitMs = (intervalsNeeded - 1) * this.refillIntervalMs + timeUntilRefill;

      await new Promise<void>((resolve) => setTimeout(resolve, Math.max(0, waitMs)));
    }
  }
}

export default RateLimiter;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervalsElapsed = Math.floor(elapsed / this.refillIntervalMs);

    if (intervalsElapsed > 0) {
      const tokensToAdd = intervalsElapsed * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervalsElapsed * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) {
      throw new RangeError(`Requested tokens (${tokens}) exceed maxTokens (${this.maxTokens})`);
    }

    while (!this.tryConsume(tokens)) {
      this.refill();
      const deficit = tokens - this.currentTokens;
      const intervalsNeeded = Math.ceil(deficit / this.refillRate);
      const waitMs = intervalsNeeded * this.refillIntervalMs;
      await new Promise<void>((resolve) => setTimeout(resolve, Math.max(waitMs, 1)));
    }
  }
}

export default RateLimiter;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(from: number, to: number): number[] {
  if (from > to) throw new RangeError(`Invalid range: ${from}-${to}`);
  return Array.from({ length: to - from + 1 }, (_, i) => from + i);
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] in field "${context}"`);
  }
}

function parseField(expr: string, min: number, max: number, fieldName: string): number[] {
  // Comma-separated list — recurse on each part and flatten
  if (expr.includes(",")) {
    const parts = expr.split(",");
    if (parts.some((p) => p.trim() === ""))
      throw new SyntaxError(`Empty segment in list for field "${fieldName}"`);
    return [...new Set(parts.flatMap((p) => parseField(p.trim(), min, max, fieldName)))].sort(
      (a, b) => a - b,
    );
  }

  // Step value: */n  or  a-b/n
  if (expr.includes("/")) {
    const [rangePart, stepPart] = expr.split("/");
    if (!stepPart || stepPart === "")
      throw new SyntaxError(`Missing step value in "${expr}" for field "${fieldName}"`);
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0)
      throw new RangeError(`Step must be a positive integer in "${expr}" for field "${fieldName}"`);

    let base: number[];
    if (rangePart === "*") {
      base = range(min, max);
    } else if (rangePart.includes("-")) {
      const [lo, hi] = rangePart.split("-").map((s) => parseInt(s, 10));
      if (isNaN(lo) || isNaN(hi))
        throw new SyntaxError(`Invalid range "${rangePart}" for field "${fieldName}"`);
      assertInRange(lo, min, max, fieldName);
      assertInRange(hi, min, max, fieldName);
      base = range(lo, hi);
    } else {
      const start = parseInt(rangePart, 10);
      if (isNaN(start))
        throw new SyntaxError(`Invalid start value "${rangePart}" for field "${fieldName}"`);
      assertInRange(start, min, max, fieldName);
      base = range(start, max);
    }

    return base.filter((_, i) => i % step === 0);
  }

  // Range: a-b
  if (expr.includes("-")) {
    const parts = expr.split("-");
    if (parts.length !== 2)
      throw new SyntaxError(`Invalid range expression "${expr}" for field "${fieldName}"`);
    const lo = parseInt(parts[0], 10);
    const hi = parseInt(parts[1], 10);
    if (isNaN(lo) || isNaN(hi))
      throw new SyntaxError(`Non-numeric range "${expr}" for field "${fieldName}"`);
    assertInRange(lo, min, max, fieldName);
    assertInRange(hi, min, max, fieldName);
    return range(lo, hi);
  }

  // Wildcard
  if (expr === "*") {
    return range(min, max);
  }

  // Plain number
  const value = parseInt(expr, 10);
  if (isNaN(value))
    throw new SyntaxError(`Unrecognised token "${expr}" for field "${fieldName}"`);
  assertInRange(value, min, max, fieldName);
  return [value];
}

export function parseCron(expression: string): CronFields {
  if (typeof expression !== "string" || expression.trim() === "") {
    throw new TypeError("Cron expression must be a non-empty string");
  }

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields but got ${parts.length}: "${expression}"`,
    );
  }

  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];

  const result = {} as CronFields;
  for (let i = 0; i < fieldNames.length; i++) {
    const name = fieldNames[i];
    const [min, max] = FIELD_RANGES[name];
    result[name] = parseField(parts[i], min, max, name);
  }

  return result;
}

export default parseCron;

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type CronField = keyof CronExpression;

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   6],
};

const FIELD_ORDER: CronField[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of valid range [${min}, ${max}] in "${context}"`
    );
  }
}

function parseStep(token: string, min: number, max: number): number[] {
  const slashIndex = token.indexOf("/");
  const stepStr = token.slice(slashIndex + 1);
  const step = parseInt(stepStr, 10);

  if (!Number.isInteger(step) || isNaN(step) || step <= 0) {
    throw new TypeError(`Invalid step value "${stepStr}" — must be a positive integer`);
  }

  const rangeToken = token.slice(0, slashIndex);
  let rangeMin = min;
  let rangeMax = max;

  if (rangeToken !== "*") {
    const dashIndex = rangeToken.indexOf("-");
    if (dashIndex !== -1) {
      rangeMin = parseInt(rangeToken.slice(0, dashIndex), 10);
      rangeMax = parseInt(rangeToken.slice(dashIndex + 1), 10);
    } else {
      rangeMin = parseInt(rangeToken, 10);
    }
    assertInRange(rangeMin, min, max, token);
    assertInRange(rangeMax, min, max, token);
    if (rangeMin > rangeMax) {
      throw new RangeError(`Range start ${rangeMin} exceeds end ${rangeMax} in "${token}"`);
    }
  }

  const values: number[] = [];
  for (let v = rangeMin; v <= rangeMax; v += step) {
    values.push(v);
  }
  return values;
}

function parseSingleToken(token: string, min: number, max: number): number[] {
  // Wildcard
  if (token === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => min + i);
  }

  // Step value: */n or start-end/n or start/n
  if (token.includes("/")) {
    return parseStep(token, min, max);
  }

  // Range: start-end
  if (token.includes("-")) {
    const dashIndex = token.indexOf("-");
    const start = parseInt(token.slice(0, dashIndex), 10);
    const end   = parseInt(token.slice(dashIndex + 1), 10);

    if (isNaN(start) || isNaN(end)) {
      throw new TypeError(`Non-numeric boundary in range "${token}"`);
    }
    assertInRange(start, min, max, token);
    assertInRange(end, min, max, token);
    if (start > end) {
      throw new RangeError(`Range start ${start} exceeds end ${end} in "${token}"`);
    }

    return Array.from({ length: end - start + 1 }, (_, i) => start + i);
  }

  // Single number
  const num = parseInt(token, 10);
  if (isNaN(num) || String(num) !== token.trim()) {
    throw new TypeError(`Unrecognised token "${token}" — expected number, wildcard, range, or step`);
  }
  assertInRange(num, min, max, token);
  return [num];
}

function parseField(raw: string, min: number, max: number): number[] {
  if (typeof raw !== "string" || raw.trim() === "") {
    throw new TypeError(`Field must be a non-empty string, got: ${JSON.stringify(raw)}`);
  }

  const token = raw.trim();

  // Comma-separated list — split first so inner tokens can still be ranges/steps
  if (token.includes(",")) {
    const seen = new Set<number>();
    for (const part of token.split(",")) {
      const trimmed = part.trim();
      if (trimmed === "") {
        throw new TypeError(`Empty segment in comma list "${token}"`);
      }
      for (const v of parseSingleToken(trimmed, min, max)) {
        seen.add(v);
      }
    }
    return Array.from(seen).sort((a, b) => a - b);
  }

  return parseSingleToken(token, min, max);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, received ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new TypeError("Cron expression must not be empty");
  }

  const parts = trimmed.split(/\s+/);
  if (parts.length !== 5) {
    throw new RangeError(
      `Cron expression must have exactly 5 fields, received ${parts.length}: "${trimmed}"`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const field = FIELD_ORDER[i];
    const [min, max] = FIELD_RANGES[field];
    try {
      result[field] = parseField(parts[i], min, max);
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      throw new Error(`Invalid ${field} field (position ${i + 1}) "${parts[i]}": ${msg}`);
    }
  }

  return result;
}

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
  name: string;
}

const FIELD_CONFIGS: [keyof CronExpression, FieldConfig][] = [
  ["minute",     { min: 0,  max: 59, name: "minute"     }],
  ["hour",       { min: 0,  max: 23, name: "hour"       }],
  ["dayOfMonth", { min: 1,  max: 31, name: "dayOfMonth" }],
  ["month",      { min: 1,  max: 12, name: "month"      }],
  ["dayOfWeek",  { min: 0,  max: 6,  name: "dayOfWeek"  }],
];

function assertInRange(value: number, config: FieldConfig): void {
  if (!Number.isInteger(value) || value < config.min || value > config.max) {
    throw new RangeError(
      `Value ${value} is out of valid range [${config.min}–${config.max}] for field "${config.name}"`
    );
  }
}

function expandStep(start: number, end: number, step: number, config: FieldConfig): number[] {
  if (!Number.isInteger(step) || step <= 0) {
    throw new RangeError(`Step value must be a positive integer in field "${config.name}", got ${step}`);
  }
  assertInRange(start, config);
  assertInRange(end, config);
  if (start > end) {
    throw new RangeError(`Range start ${start} exceeds end ${end} in field "${config.name}"`);
  }
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function expandRange(start: number, end: number, config: FieldConfig): number[] {
  assertInRange(start, config);
  assertInRange(end, config);
  if (start > end) {
    throw new RangeError(`Range start ${start} exceeds end ${end} in field "${config.name}"`);
  }
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function parseToken(token: string, config: FieldConfig): number[] {
  const t = token.trim();
  if (t === "") {
    throw new SyntaxError(`Empty token encountered in field "${config.name}"`);
  }

  // Step: */n or start-end/n or start/n (start to max)
  if (t.includes("/")) {
    const slashIdx = t.indexOf("/");
    const base = t.slice(0, slashIdx);
    const stepRaw = t.slice(slashIdx + 1);
    const step = Number(stepRaw);
    if (!Number.isInteger(step) || step <= 0 || String(step) !== stepRaw.trim()) {
      throw new SyntaxError(`Invalid step "${stepRaw}" in field "${config.name}"`);
    }
    if (base === "*") {
      return expandStep(config.min, config.max, step, config);
    }
    if (base.includes("-")) {
      const [s, e] = base.split("-");
      return expandStep(Number(s), Number(e), step, config);
    }
    const start = Number(base);
    if (!Number.isInteger(start) || String(start) !== base.trim()) {
      throw new SyntaxError(`Invalid step base "${base}" in field "${config.name}"`);
    }
    return expandStep(start, config.max, step, config);
  }

  // Wildcard
  if (t === "*") {
    return Array.from({ length: config.max - config.min + 1 }, (_, i) => config.min + i);
  }

  // Range: n-m
  if (t.includes("-")) {
    const dashIdx = t.indexOf("-");
    const s = t.slice(0, dashIdx);
    const e = t.slice(dashIdx + 1);
    const start = Number(s);
    const end = Number(e);
    if (!Number.isInteger(start) || String(start) !== s.trim()) {
      throw new SyntaxError(`Invalid range start "${s}" in field "${config.name}"`);
    }
    if (!Number.isInteger(end) || String(end) !== e.trim()) {
      throw new SyntaxError(`Invalid range end "${e}" in field "${config.name}"`);
    }
    return expandRange(start, end, config);
  }

  // Single number
  const num = Number(t);
  if (!Number.isInteger(num) || String(num) !== t) {
    throw new SyntaxError(`Invalid value "${t}" in field "${config.name}"`);
  }

  // dayOfWeek: treat 7 as alias for 0 (Sunday)
  const normalized = config.name === "dayOfWeek" && num === 7 ? 0 : num;
  assertInRange(normalized, config);
  return [normalized];
}

function parseField(raw: string, config: FieldConfig): number[] {
  if (raw === undefined || raw === null || raw.trim() === "") {
    throw new SyntaxError(`Missing or empty value for field "${config.name}"`);
  }

  const tokens = raw.split(",");
  if (tokens.some((t) => t.trim() === "")) {
    throw new SyntaxError(`Trailing or double comma in field "${config.name}": "${raw}"`);
  }

  const seen = new Set<number>();
  for (const token of tokens) {
    for (const v of parseToken(token, config)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, received ${typeof expression}`);
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const [key, config] = FIELD_CONFIGS[i];
    result[key] = parseField(fields[i], config);
  }

  return result;
}

export default parseCron;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervalsElapsed = Math.floor(elapsed / this.refillIntervalMs);

    if (intervalsElapsed > 0) {
      const tokensToAdd = intervalsElapsed * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervalsElapsed * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) {
      throw new RangeError(`Requested tokens (${tokens}) exceed maxTokens (${this.maxTokens})`);
    }

    while (!this.tryConsume(tokens)) {
      const tokensNeeded = tokens - this.currentTokens;
      const intervalsNeeded = Math.ceil(tokensNeeded / this.refillRate);
      const waitMs = intervalsNeeded * this.refillIntervalMs;
      const timeUntilNextRefill = this.refillIntervalMs - (Date.now() - this.lastRefillTime) % this.refillIntervalMs;
      const delay = Math.max(1, Math.min(waitMs, timeUntilNextRefill));

      await new Promise<void>((resolve) => setTimeout(resolve, delay));
    }
  }
}

export default RateLimiter;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronFields;

const FIELD_RANGES: Record<FieldName, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

const FIELD_ORDER: FieldName[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function rangeArray(start: number, end: number, step = 1): number[] {
  if (step < 1) throw new Error(`Step must be >= 1, got ${step}`);
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function assertInRange(value: number, min: number, max: number, field: string): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} out of range [${min}, ${max}] for field "${field}"`
    );
  }
}

function parseSegment(segment: string, field: FieldName): number[] {
  const { min, max } = FIELD_RANGES[field];

  // Wildcard: *
  if (segment === "*") {
    return rangeArray(min, max);
  }

  // Step on wildcard: */N
  const stepWildcardMatch = segment.match(/^\*\/(\d+)$/);
  if (stepWildcardMatch) {
    const step = parseInt(stepWildcardMatch[1], 10);
    if (step < 1) throw new RangeError(`Step must be >= 1 in "${segment}" for field "${field}"`);
    return rangeArray(min, max, step);
  }

  // Range with optional step: N-M or N-M/S
  const rangeMatch = segment.match(/^(\d+)-(\d+)(?:\/(\d+))?$/);
  if (rangeMatch) {
    const start = parseInt(rangeMatch[1], 10);
    const end   = parseInt(rangeMatch[2], 10);
    const step  = rangeMatch[3] !== undefined ? parseInt(rangeMatch[3], 10) : 1;

    assertInRange(start, min, max, field);
    assertInRange(end,   min, max, field);

    if (start > end) {
      throw new RangeError(`Range start ${start} > end ${end} for field "${field}"`);
    }
    if (step < 1) {
      throw new RangeError(`Step must be >= 1 in "${segment}" for field "${field}"`);
    }

    return rangeArray(start, end, step);
  }

  // Plain number
  const numMatch = segment.match(/^(\d+)$/);
  if (numMatch) {
    const value = parseInt(numMatch[1], 10);
    // Normalize dayOfWeek: 7 is treated as Sunday (0)
    const normalized = field === "dayOfWeek" && value === 7 ? 0 : value;
    assertInRange(normalized, min, max, field);
    return [normalized];
  }

  throw new SyntaxError(`Invalid cron segment "${segment}" for field "${field}"`);
}

function parseField(token: string, field: FieldName): number[] {
  const segments = token.split(",");
  if (segments.length === 0) {
    throw new SyntaxError(`Empty token for field "${field}"`);
  }

  const values = new Set<number>();
  for (const segment of segments) {
    const parsed = parseSegment(segment.trim(), field);
    for (const v of parsed) {
      values.add(v);
    }
  }

  return [...values].sort((a, b) => a - b);
}

function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const tokens = expression.trim().split(/\s+/);

  if (tokens.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields in cron expression, got ${tokens.length}: "${expression}"`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const field = FIELD_ORDER[i];
    result[field] = parseField(tokens[i], field);
  }

  return result;
}

export default parseCron;
export type { CronFields };

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

function validateValue(value: number, field: CronField): number {
  const { min, max } = FIELD_RANGES[field];
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of range for field "${field}" (${min}-${max})`
    );
  }
  // Normalize dayOfWeek: treat 7 as Sunday (0)
  if (field === "dayOfWeek" && value === 7) return 0;
  return value;
}

function range(from: number, to: number): number[] {
  if (from > to) throw new RangeError(`Invalid range: ${from}-${to}`);
  return Array.from({ length: to - from + 1 }, (_, i) => from + i);
}

function unique(values: number[]): number[] {
  return [...new Set(values)].sort((a, b) => a - b);
}

function parseSegment(segment: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];

  // Step: */n or start-end/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) {
      throw new Error(`Invalid step value "${stepStr}" in field "${field}"`);
    }

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      const [fromStr, toStr] = rangePart.split("-");
      start = validateValue(parseInt(fromStr, 10), field);
      end   = validateValue(parseInt(toStr,   10), field);
    } else {
      start = validateValue(parseInt(rangePart, 10), field);
      end   = max;
    }

    const values: number[] = [];
    for (let v = start; v <= end; v += step) {
      values.push(field === "dayOfWeek" && v === 7 ? 0 : v);
    }
    return values;
  }

  // Wildcard: *
  if (segment === "*") {
    return range(min, max);
  }

  // Range: n-m
  if (segment.includes("-")) {
    const [fromStr, toStr] = segment.split("-");
    const from = validateValue(parseInt(fromStr, 10), field);
    const to   = validateValue(parseInt(toStr,   10), field);
    return range(from, to).map(v =>
      field === "dayOfWeek" && v === 7 ? 0 : v
    );
  }

  // Single number
  const num = parseInt(segment, 10);
  if (isNaN(num)) {
    throw new Error(`Invalid value "${segment}" in field "${field}"`);
  }
  return [validateValue(num, field)];
}

function parseField(expression: string, field: CronField): number[] {
  const segments = expression.split(",");
  const values = segments.flatMap(seg => parseSegment(seg.trim(), field));
  return unique(values);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${parts.length}`
    );
  }

  const fields: CronField[] = [
    "minute",
    "hour",
    "dayOfMonth",
    "month",
    "dayOfWeek",
  ];

  const result = {} as CronResult;
  for (let i = 0; i < fields.length; i++) {
    result[fields[i]] = parseField(parts[i], fields[i]);
  }

  return result;
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      this.currentTokens = Math.min(
        this.maxTokens,
        this.currentTokens + intervals * this.refillRate
      );
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens must be > 0"));
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(`Requested tokens (${tokens}) exceed maxTokens (${this.maxTokens})`)
      );
    }

    return new Promise((resolve) => {
      const attempt = (): void => {
        this.refill();

        if (this.currentTokens >= tokens) {
          this.currentTokens -= tokens;
          resolve();
          return;
        }

        const deficit = tokens - this.currentTokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const msUntilRefill =
          this.refillIntervalMs - (Date.now() - this.lastRefillTime) % this.refillIntervalMs;
        const waitMs = (intervalsNeeded - 1) * this.refillIntervalMs + msUntilRefill;

        setTimeout(attempt, Math.max(0, waitMs));
      };

      attempt();
    });
  }
}

export default RateLimiter;

interface RateLimiterOptions {
