    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      const tokensToAdd = intervals * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens to consume must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens to consume must be > 0"));
    if (tokens > this.maxTokens) return Promise.reject(new RangeError("requested tokens exceed maxTokens"));

    return new Promise((resolve) => {
      const attempt = (): void => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();
        const deficit = tokens - this.currentTokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const delay = intervalsNeeded * this.refillIntervalMs;

        setTimeout(attempt, Math.max(delay, 1));
      };

      attempt();
    });
  }
}

export default RateLimiter;

export interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldRange {
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: ReadonlyArray<[keyof CronResult, FieldRange]> = [
  ["minute",     { min: 0,  max: 59 }],
  ["hour",       { min: 0,  max: 23 }],
  ["dayOfMonth", { min: 1,  max: 31 }],
  ["month",      { min: 1,  max: 12 }],
  ["dayOfWeek",  { min: 0,  max: 6  }],
];

function buildRange(start: number, end: number, step: number): number[] {
  if (step < 1) throw new Error(`Step must be >= 1, got ${step}`);
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function assertInRange(value: number, { min, max }: FieldRange, fieldName: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new Error(
      `Value ${value} is out of valid range [${min}, ${max}] for field "${fieldName}"`
    );
  }
}

function parseInteger(raw: string, context: string): number {
  const n = Number(raw);
  if (!Number.isInteger(n) || raw.trim() === "") {
    throw new Error(`Expected integer, got "${raw}" in ${context}`);
  }
  return n;
}

function parseSegment(segment: string, range: FieldRange, fieldName: string): number[] {
  // Wildcard-only
  if (segment === "*") {
    return buildRange(range.min, range.max, 1);
  }

  // Step on wildcard: */N
  if (segment.startsWith("*/")) {
    const step = parseInteger(segment.slice(2), `field "${fieldName}" step`);
    if (step < 1) throw new Error(`Step must be >= 1 in field "${fieldName}"`);
    return buildRange(range.min, range.max, step);
  }

  // Range, optionally with step: N-M or N-M/S
  if (segment.includes("-")) {
    const slashIdx = segment.indexOf("/");
    const rangePart = slashIdx === -1 ? segment : segment.slice(0, slashIdx);
    const stepPart  = slashIdx === -1 ? null    : segment.slice(slashIdx + 1);

    const dashIdx = rangePart.indexOf("-");
    if (dashIdx <= 0 || dashIdx === rangePart.length - 1) {
      throw new Error(`Malformed range "${segment}" in field "${fieldName}"`);
    }

    const start = parseInteger(rangePart.slice(0, dashIdx), `field "${fieldName}" range start`);
    const end   = parseInteger(rangePart.slice(dashIdx + 1), `field "${fieldName}" range end`);
    const step  = stepPart !== null
      ? parseInteger(stepPart, `field "${fieldName}" step`)
      : 1;

    assertInRange(start, range, fieldName);
    assertInRange(end,   range, fieldName);

    if (start > end) {
      throw new Error(
        `Range start ${start} exceeds end ${end} in field "${fieldName}"`
      );
    }
    if (step < 1) {
      throw new Error(`Step must be >= 1 in field "${fieldName}"`);
    }

    return buildRange(start, end, step);
  }

  // Step on a bare number: N/S (every S from N to max)
  if (segment.includes("/")) {
    const [startStr, stepStr] = segment.split("/");
    const start = parseInteger(startStr, `field "${fieldName}" step-start`);
    const step  = parseInteger(stepStr,  `field "${fieldName}" step`);
    assertInRange(start, range, fieldName);
    if (step < 1) throw new Error(`Step must be >= 1 in field "${fieldName}"`);
    return buildRange(start, range.max, step);
  }

  // Plain integer
  const value = parseInteger(segment, `field "${fieldName}"`);
  assertInRange(value, range, fieldName);
  return [value];
}

function parseField(expression: string, range: FieldRange, fieldName: string): number[] {
  if (!expression || expression.trim() === "") {
    throw new Error(`Field "${fieldName}" is empty`);
  }

  const segments = expression.split(",");
  const seen = new Set<number>();

  for (const raw of segments) {
    const segment = raw.trim();
    if (segment === "") {
      throw new Error(`Empty segment in comma-separated list for field "${fieldName}"`);
    }
    for (const v of parseSegment(segment, range, fieldName)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError(`Cron expression must be a string, got ${typeof expression}`);
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronResult;

  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const [fieldName, range] = FIELD_CONFIGS[i];
    result[fieldName] = parseField(fields[i], range, fieldName);
  }

  return result;
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export default class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError(`maxTokens must be a finite positive number, got: ${options.maxTokens}`);
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate <= 0) {
      throw new RangeError(`refillRate must be a finite positive number, got: ${options.refillRate}`);
    }
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0) {
      throw new RangeError(`refillIntervalMs must be a finite positive number, got: ${options.refillIntervalMs}`);
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed <= 0) return;

    const tokensToAdd = (elapsed / this.refillIntervalMs) * this.refillRate;
    this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
    this.lastRefillTime = now;
  }

  private assertValidTokenCount(tokens: number, label = "tokens"): void {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError(`${label} must be a finite non-negative number, got: ${tokens}`);
    }
  }

  tryConsume(tokens = 1): boolean {
    this.assertValidTokenCount(tokens);

    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens = 1): Promise<void> {
    this.assertValidTokenCount(tokens);

    if (tokens > this.maxTokens) {
      throw new RangeError(
        `Requested ${tokens} tokens exceeds bucket capacity of ${this.maxTokens} — will never be satisfiable`,
      );
    }

    // Single-threaded JS event loop means the loop body is atomic between
    // awaits: no two concurrent callers can both pass the guard and double-consume.
    while (true) {
      this.refill();

      if (this.currentTokens >= tokens) {
        this.currentTokens -= tokens;
        return;
      }

      const deficit = tokens - this.currentTokens;
      const msPerToken = this.refillIntervalMs / this.refillRate;
      const waitMs = Math.ceil(deficit * msPerToken);

      await new Promise<void>((resolve) => setTimeout(resolve, Math.max(1, waitMs)));
    }
  }
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 7],
};

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function dedupe(values: number[]): number[] {
  return [...new Set(values)].sort((a, b) => a - b);
}

function clampDayOfWeek(values: number[]): number[] {
  return dedupe(values.map((v) => (v === 7 ? 0 : v)));
}

function parseSegment(segment: string, min: number, max: number): number[] {
  if (segment === "*") return range(min, max);

  if (segment.startsWith("*/")) {
    const step = parseInt(segment.slice(2), 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step: ${segment}`);
    const result: number[] = [];
    for (let i = min; i <= max; i += step) result.push(i);
    return result;
  }

  if (segment.includes("/")) {
    const [rangePart, stepPart] = segment.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step: ${segment}`);
    let start = min;
    let end = max;
    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [s, e] = rangePart.split("-").map(Number);
        start = s;
        end = e;
      } else {
        start = parseInt(rangePart, 10);
      }
    }
    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
    return result;
  }

  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: ${segment}`);
    if (start > end) throw new Error(`Range start > end: ${segment}`);
    return range(start, end);
  }

  if (segment.includes(",")) {
    return segment.split(",").flatMap((part) => parseSegment(part.trim(), min, max));
  }

  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new Error(`Invalid value: ${segment}`);
  return [value];
}

function validateRange(values: number[], min: number, max: number, field: string): number[] {
  for (const v of values) {
    if (v < min || v > max) {
      throw new Error(`Value ${v} out of range [${min}, ${max}] for field "${field}"`);
    }
  }
  return values;
}

function parseCron(expression: string): CronFields {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(`Expected 5 fields, got ${parts.length}`);
  }

  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];
  const result = {} as CronFields;

  for (let i = 0; i < fieldNames.length; i++) {
    const field = fieldNames[i];
    const [min, max] = FIELD_RANGES[field];
    let values = parseSegment(parts[i], min, max);
    validateRange(values, min, max, field);
    if (field === "dayOfWeek") values = clampDayOfWeek(values);
    result[field] = dedupe(values);
  }

  return result;
}

export default parseCron;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 7],
};

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function unique(values: number[]): number[] {
  return [...new Set(values)].sort((a, b) => a - b);
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] in field "${context}"`);
  }
}

function parseSegment(segment: string, min: number, max: number, fieldName: string): number[] {
  // Step value: */n or a-b/n
  if (segment.includes("/")) {
    const [rangePart, stepPart] = segment.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) {
      throw new SyntaxError(`Invalid step value "${stepPart}" in field "${fieldName}"`);
    }

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      const [lo, hi] = rangePart.split("-").map((v) => parseInt(v, 10));
      if (isNaN(lo) || isNaN(hi)) {
        throw new SyntaxError(`Invalid range "${rangePart}" in field "${fieldName}"`);
      }
      assertInRange(lo, min, max, fieldName);
      assertInRange(hi, min, max, fieldName);
      if (lo > hi) throw new RangeError(`Range start ${lo} exceeds end ${hi} in field "${fieldName}"`);
      start = lo;
      end = hi;
    } else {
      start = parseInt(rangePart, 10);
      if (isNaN(start)) throw new SyntaxError(`Invalid step base "${rangePart}" in field "${fieldName}"`);
      assertInRange(start, min, max, fieldName);
      end = max;
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) values.push(i);
    return values;
  }

  // Range: a-b
  if (segment.includes("-")) {
    const [lo, hi] = segment.split("-").map((v) => parseInt(v, 10));
    if (isNaN(lo) || isNaN(hi)) {
      throw new SyntaxError(`Invalid range "${segment}" in field "${fieldName}"`);
    }
    assertInRange(lo, min, max, fieldName);
    assertInRange(hi, min, max, fieldName);
    if (lo > hi) throw new RangeError(`Range start ${lo} exceeds end ${hi} in field "${fieldName}"`);
    return range(lo, hi);
  }

  // Wildcard
  if (segment === "*") {
    return range(min, max);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Invalid token "${segment}" in field "${fieldName}"`);
  }
  assertInRange(value, min, max, fieldName);
  return [value];
}

function parseField(expression: string, min: number, max: number, fieldName: string): number[] {
  const segments = expression.split(",");
  if (segments.length === 0) {
    throw new SyntaxError(`Empty field "${fieldName}"`);
  }

  const values = segments.flatMap((seg) => parseSegment(seg.trim(), min, max, fieldName));
  const result = unique(values);

  // Normalize dayOfWeek: treat 7 as 0 (both represent Sunday)
  if (fieldName === "dayOfWeek") {
    const normalized = unique(result.map((v) => (v === 7 ? 0 : v)));
    return normalized;
  }

  return result;
}

export function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new SyntaxError(`Expected 5 fields, got ${parts.length}: "${expression}"`);
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] = parts;
  const fieldNames = Object.keys(FIELD_RANGES) as Array<keyof CronFields>;

  return {
    minute: parseField(minuteExpr, ...FIELD_RANGES.minute, fieldNames[0]),
    hour: parseField(hourExpr, ...FIELD_RANGES.hour, fieldNames[1]),
    dayOfMonth: parseField(dayOfMonthExpr, ...FIELD_RANGES.dayOfMonth, fieldNames[2]),
    month: parseField(monthExpr, ...FIELD_RANGES.month, fieldNames[3]),
    dayOfWeek: parseField(dayOfWeekExpr, ...FIELD_RANGES.dayOfWeek, fieldNames[4]),
  };
}

export default parseCron;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronFields;

interface FieldConfig {
  readonly name: FieldName;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute",     min: 0, max: 59 },
  { name: "hour",       min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month",      min: 1, max: 12 },
  { name: "dayOfWeek",  min: 0, max: 7  },
] as const;

function intRange(start: number, end: number): number[] {
  if (start > end) return [];
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Value ${value} out of valid range [${min}, ${max}] in field: ${context}`
    );
  }
}

function parseIntStrict(str: string, context: string): number {
  if (!/^-?\d+$/.test(str)) {
    throw new SyntaxError(`Expected integer but got "${str}" in field: ${context}`);
  }
  return parseInt(str, 10);
}

function parseSingleToken(token: string, config: FieldConfig): number[] {
  const { min, max, name } = config;

  // Step: */N or start/N or start-end/N
  if (token.includes("/")) {
    const slashIdx = token.indexOf("/");
    const base = token.slice(0, slashIdx);
    const stepStr = token.slice(slashIdx + 1);

    if (!stepStr || stepStr.includes("/")) {
      throw new SyntaxError(`Invalid step expression "${token}" in field: ${name}`);
    }

    const step = parseIntStrict(stepStr, name);
    if (step < 1) {
      throw new RangeError(`Step must be >= 1, got ${step} in field: ${name}`);
    }

    let start: number;
    let end: number;

    if (base === "*") {
      start = min;
      end = max;
    } else if (base.includes("-")) {
      [start, end] = parseRangeToken(base, config);
    } else {
      start = parseIntStrict(base, name);
      assertInRange(start, min, max, name);
      end = max;
    }

    const values: number[] = [];
    for (let v = start; v <= end; v += step) {
      values.push(v);
    }
    return values;
  }

  // Wildcard
  if (token === "*") {
    return intRange(min, max);
  }

  // Range: N-M
  if (token.includes("-")) {
    const [start, end] = parseRangeToken(token, config);
    return intRange(start, end);
  }

  // Single integer
  const value = parseIntStrict(token, name);
  assertInRange(value, min, max, name);
  return [value];
}

function parseRangeToken(token: string, config: FieldConfig): [number, number] {
  const { min, max, name } = config;
  const parts = token.split("-");

  if (parts.length !== 2 || !parts[0] || !parts[1]) {
    throw new SyntaxError(`Invalid range "${token}" in field: ${name}`);
  }

  const start = parseIntStrict(parts[0], name);
  const end = parseIntStrict(parts[1], name);

  assertInRange(start, min, max, name);
  assertInRange(end, min, max, name);

  if (start > end) {
    throw new RangeError(
      `Range start (${start}) must be <= end (${end}) in field: ${name}`
    );
  }

  return [start, end];
}

function parseField(raw: string, config: FieldConfig): number[] {
  if (!raw || raw.trim() === "") {
    throw new SyntaxError(`Empty field value for: ${config.name}`);
  }

  const tokens = raw.split(",");

  if (tokens.some((t) => t.trim() === "")) {
    throw new SyntaxError(
      `Trailing or consecutive commas in field: ${config.name}`
    );
  }

  const seen = new Set<number>();

  for (const token of tokens) {
    for (const value of parseSingleToken(token.trim(), config)) {
      seen.add(value);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(`Cron expression must be a string, got: ${typeof expression}`);
  }

  const trimmed = expression.trim();

  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const parts = trimmed.split(/\s+/);

  if (parts.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${parts.length}: "${trimmed}"`
    );
  }

  return {
    minute:     parseField(parts[0], FIELD_CONFIGS[0]),
    hour:       parseField(parts[1], FIELD_CONFIGS[1]),
    dayOfMonth: parseField(parts[2], FIELD_CONFIGS[2]),
    month:      parseField(parts[3], FIELD_CONFIGS[3]),
    dayOfWeek:  parseField(parts[4], FIELD_CONFIGS[4]),
  };
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waiters: Array<{ tokens: number; resolve: () => void }> = [];
  private scheduledDrain: ReturnType<typeof setTimeout> | null = null;

  constructor(options: {
    maxTokens: number;
    refillRate: number;
    refillIntervalMs: number;
  }) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError("maxTokens must be a positive finite number");
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate <= 0) {
      throw new RangeError("refillRate must be a positive finite number");
    }
    if (
      !Number.isFinite(options.refillIntervalMs) ||
      options.refillIntervalMs <= 0
    ) {
      throw new RangeError("refillIntervalMs must be a positive finite number");
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private lazyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    if (elapsed <= 0) return;

    const intervals = Math.floor(elapsed / this.refillIntervalMs);
    if (intervals > 0) {
      this.currentTokens = Math.min(
        this.maxTokens,
        this.currentTokens + intervals * this.refillRate
      );
      // Advance lastRefillTime only by consumed intervals to preserve sub-interval remainder
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  private drainWaiters(): void {
    this.lazyRefill();

    while (
      this.waiters.length > 0 &&
      this.currentTokens >= this.waiters[0].tokens
    ) {
      const waiter = this.waiters.shift()!;
      this.currentTokens -= waiter.tokens;
      waiter.resolve();
    }

    if (this.waiters.length > 0) {
      this.scheduleNextDrain();
    }
  }

  private scheduleNextDrain(): void {
    if (this.scheduledDrain !== null) return;

    const needed = this.waiters[0].tokens - this.currentTokens;
    const intervalsNeeded = Math.ceil(needed / this.refillRate);
    const elapsedInCurrentInterval = Date.now() - this.lastRefillTime;
    const waitMs = Math.max(
      0,
      intervalsNeeded * this.refillIntervalMs - elapsedInCurrentInterval
    );

    this.scheduledDrain = setTimeout(() => {
      this.scheduledDrain = null;
      this.drainWaiters();
    }, waitMs);
  }

  /**
   * Attempts to consume `tokens` (default 1) immediately.
   * Returns false if there are queued waiters (to prevent starvation),
   * or if insufficient tokens are available, or if the request exceeds maxTokens.
   */
  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens <= 0) {
      throw new RangeError("tokens must be a positive finite number");
    }
    if (tokens > this.maxTokens) return false;
    // Honour FIFO fairness: don't skip ahead of queued waiters
    if (this.waiters.length > 0) return false;

    this.lazyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }
    return false;
  }

  getTokens(): number {
    this.lazyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();

    if (this.scheduledDrain !== null) {
      clearTimeout(this.scheduledDrain);
      this.scheduledDrain = null;
    }

    this.drainWaiters();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens <= 0) {
      throw new RangeError("tokens must be a positive finite number");
    }
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds maxTokens (${this.maxTokens}) and can never be satisfied`
        )
      );
    }

    this.lazyRefill();

    // Fast path: no queue and enough tokens available right now
    if (this.waiters.length === 0 && this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return Promise.resolve();
    }

    return new Promise<void>((resolve) => {
      this.waiters.push({ tokens, resolve });
      if (this.scheduledDrain === null) {
        this.scheduleNextDrain();
      }
    });
  }
}

export default RateLimiter;

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  if (start > end) throw new RangeError(`Invalid range: ${start}-${end}`);
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function assertInRange(value: number, min: number, max: number, field: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] for field "${field}"`);
  }
}

function parseField(expr: string, field: keyof CronFields): number[] {
  const [min, max] = FIELD_RANGES[field];

  // Comma-separated list — recurse on each part and flatten
  if (expr.includes(",")) {
    const values = expr
      .split(",")
      .flatMap((part) => parseField(part.trim(), field));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Wildcard
  if (expr === "*") {
    return range(min, max);
  }

  // Step value: */n or start-end/n
  if (expr.includes("/")) {
    const [rangePart, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new SyntaxError(`Invalid step value in "${expr}" for field "${field}"`);
    }

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      const [s, e] = rangePart.split("-").map((v) => parseInt(v, 10));
      if (isNaN(s) || isNaN(e)) {
        throw new SyntaxError(`Invalid range in "${expr}" for field "${field}"`);
      }
      assertInRange(s, min, max, field);
      assertInRange(e, min, max, field);
      start = s;
      end = e;
    } else {
      const s = parseInt(rangePart, 10);
      if (isNaN(s)) {
        throw new SyntaxError(`Invalid step expression "${expr}" for field "${field}"`);
      }
      assertInRange(s, min, max, field);
      start = s;
      end = max;
    }

    const values: number[] = [];
    for (let v = start; v <= end; v += step) {
      values.push(v);
    }
    return values;
  }

  // Range: start-end
  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);

    if (isNaN(start) || isNaN(end)) {
      throw new SyntaxError(`Invalid range "${expr}" for field "${field}"`);
    }
    assertInRange(start, min, max, field);
    assertInRange(end, min, max, field);

    return range(start, end);
  }

  // Single number
  const value = parseInt(expr, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Invalid value "${expr}" for field "${field}"`);
  }
  assertInRange(value, min, max, field);

  return [value];
}

export function parseCron(expression: string): CronFields {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new SyntaxError("Cron expression must be a non-empty string");
  }

  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields but got ${parts.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = parts;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(domExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dowExpr, "dayOfWeek"),
  };
}

export default parseCron;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      const tokensToAdd = intervals * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens must be > 0"));
    if (tokens > this.maxTokens) return Promise.reject(new RangeError("tokens exceeds maxTokens capacity"));

    return new Promise((resolve) => {
      const attempt = (): void => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();
        const deficit = tokens - this.currentTokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const delay = Math.max(1, intervalsNeeded * this.refillIntervalMs);

        setTimeout(attempt, delay);
      };

      attempt();
    });
  }
}

export default RateLimiter;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface Waiter {
  tokens: number;
  resolve: () => void;
  reject: (err: Error) => void;
}

export default class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: Waiter[];
  private scheduledWakeup: ReturnType<typeof setTimeout> | null;

  constructor(options: RateLimiterOptions) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError("maxTokens must be a finite positive number");
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate < 0) {
      throw new RangeError("refillRate must be a finite non-negative number");
    }
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0) {
      throw new RangeError("refillIntervalMs must be a finite positive number");
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
    this.scheduledWakeup = null;
  }

  private applyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    if (elapsed > 0 && this.refillRate > 0) {
      const tokensToAdd = (elapsed / this.refillIntervalMs) * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
    }
    // Always advance time to prevent elapsed time from accumulating during
    // periods where refillRate is 0, avoiding a sudden burst on rate change.
    this.lastRefillTime = now;
  }

  private msUntilSufficient(needed: number): number {
    const deficit = needed - this.currentTokens;
    if (deficit <= 0) return 0;
    if (this.refillRate === 0) return Infinity;
    return (deficit / this.refillRate) * this.refillIntervalMs;
  }

  private processQueue(): void {
    this.applyRefill();

    while (this.waitQueue.length > 0) {
      const waiter = this.waitQueue[0];
      if (this.currentTokens >= waiter.tokens) {
        this.currentTokens -= waiter.tokens;
        this.waitQueue.shift()!.resolve();
      } else {
        break;
      }
    }

    if (this.waitQueue.length > 0) {
      this.scheduleNextWakeup();
    }
  }

  private scheduleNextWakeup(): void {
    if (this.scheduledWakeup !== null) return;

    const next = this.waitQueue[0];
    if (next === undefined) return;

    const delay = this.msUntilSufficient(next.tokens);

    if (!Number.isFinite(delay)) {
      // refillRate is 0 and bucket can never fill enough — reject all waiters
      const drained = this.waitQueue.splice(0);
      for (const w of drained) {
        w.reject(
          new Error(
            `Cannot acquire ${w.tokens} token(s): refill rate is 0 and current supply (${this.currentTokens}) is insufficient`
          )
        );
      }
      return;
    }

    this.scheduledWakeup = setTimeout(() => {
      this.scheduledWakeup = null;
      this.processQueue();
    }, Math.ceil(delay));
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError("tokens must be a finite non-negative number");
    }
    if (tokens === 0) return true;

    this.applyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }
    return false;
  }

  getTokens(): number {
    this.applyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();

    if (this.scheduledWakeup !== null) {
      clearTimeout(this.scheduledWakeup);
      this.scheduledWakeup = null;
    }

    // Drain the queue now that the bucket is full
    this.processQueue();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0) {
      return Promise.reject(
        new RangeError("tokens must be a finite non-negative number")
      );
    }
    if (tokens === 0) return Promise.resolve();
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} token(s) exceeds maxTokens (${this.maxTokens}); request can never be satisfied`
        )
      );
    }

    // Only bypass the queue if no one is already waiting, to preserve FIFO fairness.
    if (this.waitQueue.length === 0) {
      this.applyRefill();
      if (this.currentTokens >= tokens) {
        this.currentTokens -= tokens;
        return Promise.resolve();
      }
    }

    return new Promise<void>((resolve, reject) => {
      this.waitQueue.push({ tokens, resolve, reject });
      // Only schedule if we just added the first waiter (queue was empty before push)
      if (this.waitQueue.length === 1 && this.scheduledWakeup === null) {
        this.scheduleNextWakeup();
      }
    });
  }
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervalsElapsed = Math.floor(elapsed / this.refillIntervalMs);

    if (intervalsElapsed > 0) {
      const tokensToAdd = intervalsElapsed * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervalsElapsed * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) {
      throw new RangeError(`Requested tokens (${tokens}) exceed maxTokens (${this.maxTokens})`);
    }

    while (!this.tryConsume(tokens)) {
      const deficit = tokens - this.currentTokens;
      const intervalsNeeded = Math.ceil(deficit / this.refillRate);
      const timeUntilRefill = this.refillIntervalMs - (Date.now() - this.lastRefillTime);
      const waitMs = Math.max(0, timeUntilRefill + (intervalsNeeded - 1) * this.refillIntervalMs);
      await new Promise<void>((resolve) => setTimeout(resolve, waitMs));
    }
  }
}

export default RateLimiter;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
};

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) {
    result.push(i);
  }
  return result;
}

function parseField(token: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];

  // Handle comma-separated list
  if (token.includes(",")) {
    const values = token
      .split(",")
      .flatMap((part) => parseField(part.trim(), field));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Handle wildcard
  if (token === "*") {
    return range(min, max);
  }

  // Handle step value
  if (token.includes("/")) {
    const [base, stepStr] = token.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) {
      throw new SyntaxError(`Invalid step value in token: ${token}`);
    }
    let start = min;
    let end = max;
    if (base !== "*") {
      if (base.includes("-")) {
        const [rangeStart, rangeEnd] = base.split("-").map(Number);
        start = clamp(rangeStart, min, max);
        end = clamp(rangeEnd, min, max);
        if (start > end) {
          throw new RangeError(`Invalid range ${base}: start > end`);
        }
      } else {
        start = clamp(parseInt(base, 10), min, max);
      }
    }
    const result: number[] = [];
    for (let i = start; i <= end; i += step) {
      result.push(i);
    }
    return result;
  }

  // Handle range
  if (token.includes("-")) {
    const [startStr, endStr] = token.split("-");
    const start = clamp(parseInt(startStr, 10), min, max);
    const end = clamp(parseInt(endStr, 10), min, max);
    if (start > end) {
      throw new RangeError(`Invalid range ${token}: start > end`);
    }
    return range(start, end);
  }

  // Handle plain number
  const value = parseInt(token, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Invalid token: ${token}`);
  }

  // Normalize day-of-week: both 0 and 7 represent Sunday
  if (field === "dayOfWeek" && value === 7) {
    return [0];
  }

  return [clamp(value, min, max)];
}

function parseCron(expression: string): CronResult {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new SyntaxError("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${fields.length}`
    );
  }

  const [minuteToken, hourToken, domToken, monthToken, dowToken] = fields;
  const fieldNames: CronField[] = [
    "minute",
    "hour",
    "dayOfMonth",
    "month",
    "dayOfWeek",
  ];
  const tokens = [minuteToken, hourToken, domToken, monthToken, dowToken];

  const parsed = fieldNames.reduce<Partial<CronResult>>((acc, field, i) => {
    acc[field] = parseField(tokens[i], field);
    return acc;
  }, {});

  return parsed as CronResult;
}

export default parseCron;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface Waiter {
  tokens: number;
  resolve: () => void;
  reject: (err: Error) => void;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waiters: Waiter[];
  private scheduledDrain: ReturnType<typeof setTimeout> | null;

  constructor(options: RateLimiterOptions) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError("maxTokens must be a finite positive number");
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate <= 0) {
      throw new RangeError("refillRate must be a finite positive number");
    }
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0) {
      throw new RangeError("refillIntervalMs must be a finite positive number");
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
    this.waiters = [];
    this.scheduledDrain = null;
  }

  private applyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed <= 0) return;

    const tokensToAdd = (elapsed / this.refillIntervalMs) * this.refillRate;
    this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
    this.lastRefillTime = now;
  }

  private msUntilAvailable(needed: number): number {
    this.applyRefill();
    const deficit = needed - this.currentTokens;
    if (deficit <= 0) return 0;
    const tokensPerMs = this.refillRate / this.refillIntervalMs;
    // Add 1ms ceiling buffer to avoid floating-point near-misses on retry
    return Math.ceil(deficit / tokensPerMs) + 1;
  }

  private scheduleDrain(): void {
    if (this.scheduledDrain !== null || this.waiters.length === 0) return;

    const delay = this.msUntilAvailable(this.waiters[0].tokens);

    this.scheduledDrain = setTimeout(() => {
      this.scheduledDrain = null;
      this.drainWaiters();
    }, delay);
  }

  private drainWaiters(): void {
    while (this.waiters.length > 0) {
      const waiter = this.waiters[0];
      this.applyRefill();

      if (this.currentTokens >= waiter.tokens) {
        this.currentTokens -= waiter.tokens;
        this.waiters.shift();
        waiter.resolve();
      } else {
        // Head of queue still can't be satisfied; reschedule
        this.scheduleDrain();
        break;
      }
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError("tokens must be a finite non-negative number");
    }
    if (tokens === 0) return true;
    if (tokens > this.maxTokens) return false;

    this.applyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.applyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();

    // Clear any pending drain timer; drainWaiters will reschedule if needed
    if (this.scheduledDrain !== null) {
      clearTimeout(this.scheduledDrain);
      this.scheduledDrain = null;
    }

    this.drainWaiters();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0) {
      return Promise.reject(new RangeError("tokens must be a finite non-negative number"));
    }
    if (tokens === 0) return Promise.resolve();
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds bucket capacity of ${this.maxTokens}`
        )
      );
    }

    // Fast path: satisfy immediately if no one is ahead in queue
    if (this.waiters.length === 0 && this.tryConsume(tokens)) {
      return Promise.resolve();
    }

    // Enqueue and wait — preserves FIFO ordering for fairness
    return new Promise<void>((resolve, reject) => {
      this.waiters.push({ tokens, resolve, reject });
      this.scheduleDrain();
    });
  }
}

export default RateLimiter;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      const tokensToAdd = intervals * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) {
      throw new RangeError(`Requested tokens (${tokens}) exceed maxTokens (${this.maxTokens})`);
    }

    while (!this.tryConsume(tokens)) {
      const waitMs = this.estimateWaitMs(tokens);
      await new Promise<void>((resolve) => setTimeout(resolve, waitMs));
    }
  }

  private estimateWaitMs(tokens: number): number {
    this.refill();
    const deficit = tokens - this.currentTokens;
    if (deficit <= 0) return 0;

    const intervalsNeeded = Math.ceil(deficit / this.refillRate);
    const elapsed = Date.now() - this.lastRefillTime;
    const remainingInCurrentInterval = this.refillIntervalMs - (elapsed % this.refillIntervalMs);

    return remainingInCurrentInterval + (intervalsNeeded - 1) * this.refillIntervalMs;
  }
}

export default RateLimiter;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

function assertInRange(value: number, min: number, max: number, fieldName: string): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} out of range [${min}, ${max}] for field "${fieldName}"`
    );
  }
}

function generateRange(start: number, end: number): number[] {
  if (start > end) {
    throw new RangeError(`Range start ${start} is greater than end ${end}`);
  }
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function parseSegment(segment: string, min: number, max: number, fieldName: string): number[] {
  // Wildcard: "*"
  if (segment === "*") {
    return generateRange(min, max);
  }

  // Step: "*/n" or "a-b/n"
  if (segment.includes("/")) {
    const [rangePart, stepPart] = segment.split("/");
    const step = parseInt(stepPart, 10);

    if (isNaN(step) || step <= 0) {
      throw new SyntaxError(`Invalid step value in "${segment}" for field "${fieldName}"`);
    }

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      const [s, e] = rangePart.split("-").map(Number);
      if (isNaN(s) || isNaN(e)) {
        throw new SyntaxError(`Invalid range "${rangePart}" for field "${fieldName}"`);
      }
      assertInRange(s, min, max, fieldName);
      assertInRange(e, min, max, fieldName);
      start = s;
      end = e;
    } else {
      const val = parseInt(rangePart, 10);
      if (isNaN(val)) {
        throw new SyntaxError(`Invalid step expression "${segment}" for field "${fieldName}"`);
      }
      assertInRange(val, min, max, fieldName);
      start = val;
      end = max;
    }

    const results: number[] = [];
    for (let i = start; i <= end; i += step) {
      results.push(i);
    }
    return results;
  }

  // Range: "a-b"
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);

    if (isNaN(start) || isNaN(end)) {
      throw new SyntaxError(`Invalid range "${segment}" for field "${fieldName}"`);
    }
    assertInRange(start, min, max, fieldName);
    assertInRange(end, min, max, fieldName);
    return generateRange(start, end);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Invalid value "${segment}" for field "${fieldName}"`);
  }
  assertInRange(value, min, max, fieldName);
  return [value];
}

function parseField(expression: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];

  // Comma-separated list
  const segments = expression.split(",");
  const values = new Set<number>();

  for (const segment of segments) {
    const parsed = parseSegment(segment.trim(), min, max, field);
    for (const v of parsed) {
      // Normalize dayOfWeek: treat 7 as 0 (Sunday)
      const normalized = field === "dayOfWeek" && v === 7 ? 0 : v;
      values.add(normalized);
    }
  }

  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields in cron expression, got ${fields.length}`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute:     parseField(minuteExpr, "minute"),
    hour:       parseField(hourExpr, "hour"),
    dayOfMonth: parseField(domExpr, "dayOfMonth"),
    month:      parseField(monthExpr, "month"),
    dayOfWeek:  parseField(dowExpr, "dayOfWeek"),
  };
}

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronExpression;

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: Record<FieldName, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_ORDER: FieldName[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function assertInRange(value: number, config: FieldConfig, context: string): void {
  if (value < config.min || value > config.max) {
    throw new RangeError(
      `Value ${value} out of valid range [${config.min}, ${config.max}] in "${context}"`
    );
  }
}

function parseInteger(raw: string, context: string): number {
  if (!/^-?\d+$/.test(raw)) {
    throw new SyntaxError(`Expected an integer, got "${raw}" in "${context}"`);
  }
  return parseInt(raw, 10);
}

function expandStep(token: string, config: FieldConfig): number[] {
  const slashIndex = token.indexOf("/");
  const rangePart = token.slice(0, slashIndex);
  const stepStr  = token.slice(slashIndex + 1);

  if (stepStr === "" || stepStr.includes("/")) {
    throw new SyntaxError(`Malformed step expression: "${token}"`);
  }

  const step = parseInteger(stepStr, token);
  if (step <= 0) {
    throw new RangeError(`Step must be a positive integer in "${token}"`);
  }

  let start: number;
  let end: number;

  if (rangePart === "*") {
    start = config.min;
    end   = config.max;
  } else if (rangePart.includes("-")) {
    const [s, e] = rangePart.split("-");
    start = parseInteger(s, token);
    end   = parseInteger(e, token);
    assertInRange(start, config, token);
    assertInRange(end,   config, token);
    if (start > end) {
      throw new RangeError(`Range start exceeds end in "${token}"`);
    }
  } else {
    start = parseInteger(rangePart, token);
    assertInRange(start, config, token);
    end = config.max;
  }

  const values: number[] = [];
  for (let v = start; v <= end; v += step) {
    values.push(v);
  }
  return values;
}

function expandRange(token: string, config: FieldConfig): number[] {
  const parts = token.split("-");
  if (parts.length !== 2) {
    throw new SyntaxError(`Malformed range expression: "${token}"`);
  }
  const start = parseInteger(parts[0], token);
  const end   = parseInteger(parts[1], token);
  assertInRange(start, config, token);
  assertInRange(end,   config, token);
  if (start > end) {
    throw new RangeError(`Range start exceeds end in "${token}"`);
  }
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function parseToken(token: string, config: FieldConfig): number[] {
  if (token === "") {
    throw new SyntaxError(`Empty token encountered`);
  }

  if (token === "*") {
    return Array.from({ length: config.max - config.min + 1 }, (_, i) => config.min + i);
  }

  if (token.includes("/")) {
    return expandStep(token, config);
  }

  if (token.includes("-")) {
    return expandRange(token, config);
  }

  const value = parseInteger(token, token);
  assertInRange(value, config, token);
  return [value];
}

function parseField(raw: string, config: FieldConfig): number[] {
  if (raw.includes(",")) {
    const segments = raw.split(",");
    if (segments.some((s) => s === "")) {
      throw new SyntaxError(`Empty segment in list expression: "${raw}"`);
    }
    const all = segments.flatMap((segment) => parseToken(segment, config));
    const unique = [...new Set(all)].sort((a, b) => a - b);
    return unique;
  }

  return parseToken(raw, config);
}

export function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string" || expression.trim() === "") {
    throw new TypeError("Cron expression must be a non-empty string");
  }

  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${parts.length}: "${expression}"`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const name   = FIELD_ORDER[i];
    const config = FIELD_CONFIGS[name];
    const raw    = parts[i];
    result[name] = parseField(raw, config);
  }

  return result;
}

export default parseCron;

