type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldRange {
  min: number;
  max: number;
}

const FIELD_RANGES: Record<CronField, FieldRange> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function generateRange(start: number, end: number, step: number = 1): number[] {
  if (!Number.isInteger(step) || step <= 0) {
    throw new Error(`Step must be a positive integer, got: ${step}`);
  }
  if (!Number.isInteger(start) || !Number.isInteger(end)) {
    throw new Error(`Range bounds must be integers, got: ${start}-${end}`);
  }
  if (start > end) {
    throw new Error(`Range start (${start}) must not exceed range end (${end})`);
  }
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(segment: string, range: FieldRange): number[] {
  const trimmed = segment.trim();

  if (trimmed === "") {
    throw new Error("Empty segment encountered");
  }

  // Step expression: * /n  or  start-end/n  or  start/n
  const slashIndex = trimmed.indexOf("/");
  if (slashIndex !== -1) {
    const left    = trimmed.slice(0, slashIndex);
    const right   = trimmed.slice(slashIndex + 1);
    const step    = Number(right);

    if (!Number.isInteger(step) || step <= 0 || right.trim() === "") {
      throw new Error(`Invalid step value: "${right}"`);
    }

    if (left === "*") {
      return generateRange(range.min, range.max, step);
    }

    const dashIndex = left.indexOf("-");
    if (dashIndex !== -1) {
      const start = Number(left.slice(0, dashIndex));
      const end   = Number(left.slice(dashIndex + 1));
      if (!Number.isInteger(start) || !Number.isInteger(end)) {
        throw new Error(`Invalid range in step expression: "${left}"`);
      }
      return generateRange(start, end, step);
    }

    const start = Number(left);
    if (!Number.isInteger(start) || left.trim() === "") {
      throw new Error(`Invalid start value in step expression: "${left}"`);
    }
    return generateRange(start, range.max, step);
  }

  // Wildcard
  if (trimmed === "*") {
    return generateRange(range.min, range.max);
  }

  // Range: n-m
  const dashIndex = trimmed.indexOf("-");
  if (dashIndex !== -1) {
    const startStr = trimmed.slice(0, dashIndex);
    const endStr   = trimmed.slice(dashIndex + 1);
    const start    = Number(startStr);
    const end      = Number(endStr);

    if (!Number.isInteger(start) || startStr.trim() === "") {
      throw new Error(`Invalid range start: "${startStr}"`);
    }
    if (!Number.isInteger(end) || endStr.trim() === "") {
      throw new Error(`Invalid range end: "${endStr}"`);
    }
    return generateRange(start, end);
  }

  // Single number
  const value = Number(trimmed);
  if (!Number.isInteger(value) || trimmed === "") {
    throw new Error(`Invalid value: "${trimmed}"`);
  }
  return [value];
}

function parseField(field: string, range: FieldRange): number[] {
  if (field === undefined || field === null || field.trim() === "") {
    throw new Error("Field must be a non-empty string");
  }

  const parts  = field.split(",");
  const values = new Set<number>();

  for (const part of parts) {
    const segment = parseSegment(part.trim(), range);
    for (const v of segment) {
      if (v < range.min || v > range.max) {
        throw new Error(
          `Value ${v} is outside the valid range [${range.min}, ${range.max}]`
        );
      }
      values.add(v);
    }
  }

  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string" || expression.trim() === "") {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields; got ${fields.length}: "${expression}"`
    );
  }

  const fieldNames: CronField[] = [
    "minute",
    "hour",
    "dayOfMonth",
    "month",
    "dayOfWeek",
  ];

  const result = {} as CronExpression;

  for (let i = 0; i < fieldNames.length; i++) {
    const name  = fieldNames[i];
    const token = fields[i];
    try {
      result[name] = parseField(token, FIELD_RANGES[name]);
    } catch (err) {
      throw new Error(
        `Invalid ${name} field ("${token}"): ${(err as Error).message}`
      );
    }
  }

  return result;
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface Waiter {
  tokens: number;
  resolve: () => void;
  reject: (err: Error) => void;
}

export default class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: Waiter[] = [];
  private draining = false;

  constructor(options: RateLimiterOptions) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError("maxTokens must be a finite positive number");
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate <= 0) {
      throw new RangeError("refillRate must be a finite positive number");
    }
    if (
      !Number.isFinite(options.refillIntervalMs) ||
      options.refillIntervalMs <= 0
    ) {
      throw new RangeError("refillIntervalMs must be a finite positive number");
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private applyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    if (elapsed <= 0) return;

    const added = (elapsed / this.refillIntervalMs) * this.refillRate;
    this.currentTokens = Math.min(this.maxTokens, this.currentTokens + added);
    this.lastRefillTime = now;
  }

  private msUntilTokens(tokens: number): number {
    if (this.currentTokens >= tokens) return 0;
    const deficit = tokens - this.currentTokens;
    return (deficit / this.refillRate) * this.refillIntervalMs;
  }

  private validateTokenRequest(tokens: number, context: string): void {
    if (!Number.isFinite(tokens) || tokens <= 0) {
      throw new RangeError(`${context}: tokens must be a finite positive number`);
    }
    if (tokens > this.maxTokens) {
      throw new RangeError(
        `${context}: requested ${tokens} tokens exceeds bucket capacity of ${this.maxTokens}`
      );
    }
  }

  tryConsume(tokens = 1): boolean {
    this.validateTokenRequest(tokens, "tryConsume");
    this.applyRefill();

    if (this.currentTokens < tokens) {
      return false;
    }

    this.currentTokens -= tokens;
    return true;
  }

  getTokens(): number {
    this.applyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens = 1): Promise<void> {
    this.validateTokenRequest(tokens, "waitForTokens");

    return new Promise<void>((resolve, reject) => {
      this.waitQueue.push({ tokens, resolve, reject });
      this.drainQueue();
    });
  }

  private drainQueue(): void {
    if (this.draining) return;
    this.draining = true;
    this.scheduleNextDrain();
  }

  private scheduleNextDrain(): void {
    this.applyRefill();

    // Purge any fulfilled waiters at the head of the queue in order (FIFO)
    while (this.waitQueue.length > 0) {
      const head = this.waitQueue[0];
      if (this.currentTokens >= head.tokens) {
        this.currentTokens -= head.tokens;
        this.waitQueue.shift();
        head.resolve();
      } else {
        // Not enough tokens yet — schedule a wake-up when they will be ready
        const delay = Math.max(1, this.msUntilTokens(head.tokens));
        setTimeout(() => this.scheduleNextDrain(), delay);
        return;
      }
    }

    this.draining = false;
  }
}

export interface CronObject {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronObject;

interface FieldBounds {
  min: number;
  max: number;
}

const FIELD_BOUNDS: Record<FieldName, FieldBounds> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_ORDER: FieldName[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

const MAX_EXPRESSION_LENGTH = 256;

function safeParseInt(raw: string, context: string): number {
  const trimmed = raw.trim();
  if (trimmed === "" || !/^[0-9]+$/.test(trimmed)) {
    throw new Error(`Non-numeric value in ${context}: "${raw}"`);
  }
  const n = parseInt(trimmed, 10);
  if (!Number.isInteger(n) || isNaN(n)) {
    throw new Error(`Failed to parse integer in ${context}: "${raw}"`);
  }
  return n;
}

function assertInBounds(n: number, bounds: FieldBounds, context: string): void {
  if (n < bounds.min || n > bounds.max) {
    throw new RangeError(
      `Value ${n} out of valid range [${bounds.min}, ${bounds.max}] in ${context}`
    );
  }
}

function expandRange(rangeMin: number, rangeMax: number, step: number, bounds: FieldBounds, context: string): number[] {
  assertInBounds(rangeMin, bounds, context);
  assertInBounds(rangeMax, bounds, context);
  if (rangeMin > rangeMax) {
    throw new RangeError(`Range start ${rangeMin} exceeds range end ${rangeMax} in ${context}`);
  }
  const values: number[] = [];
  for (let i = rangeMin; i <= rangeMax; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(segment: string, bounds: FieldBounds, context: string): number[] {
  if (segment.includes("/")) {
    const parts = segment.split("/");
    if (parts.length !== 2) {
      throw new Error(`Invalid step expression in ${context}: "${segment}"`);
    }
    const [rangePart, stepStr] = parts;
    const step = safeParseInt(stepStr, `${context} step`);
    if (step <= 0) {
      throw new RangeError(`Step value must be positive in ${context}: got ${step}`);
    }

    if (rangePart === "*") {
      return expandRange(bounds.min, bounds.max, step, bounds, context);
    }

    if (rangePart.includes("-")) {
      const [startStr, endStr] = rangePart.split("-");
      if (rangePart.split("-").length !== 2) {
        throw new Error(`Invalid range in step expression in ${context}: "${rangePart}"`);
      }
      const rangeStart = safeParseInt(startStr, `${context} range-start`);
      const rangeEnd = safeParseInt(endStr, `${context} range-end`);
      return expandRange(rangeStart, rangeEnd, step, bounds, context);
    }

    const start = safeParseInt(rangePart, `${context} step-start`);
    return expandRange(start, bounds.max, step, bounds, context);
  }

  if (segment === "*") {
    return expandRange(bounds.min, bounds.max, 1, bounds, context);
  }

  if (segment.includes("-")) {
    const dashParts = segment.split("-");
    if (dashParts.length !== 2) {
      throw new Error(`Invalid range expression in ${context}: "${segment}"`);
    }
    const rangeStart = safeParseInt(dashParts[0], `${context} range-start`);
    const rangeEnd = safeParseInt(dashParts[1], `${context} range-end`);
    return expandRange(rangeStart, rangeEnd, 1, bounds, context);
  }

  const num = safeParseInt(segment, context);
  assertInBounds(num, bounds, context);
  return [num];
}

function parseField(raw: string, bounds: FieldBounds, fieldName: string): number[] {
  const segments = raw.split(",");
  if (segments.length === 0 || segments.some((s) => s.trim() === "")) {
    throw new Error(`Empty or malformed segment in field "${fieldName}": "${raw}"`);
  }

  const accumulated = new Set<number>();
  for (const segment of segments) {
    const trimmed = segment.trim();
    if (trimmed === "") {
      throw new Error(`Empty segment in comma-list for field "${fieldName}"`);
    }
    const values = parseSegment(trimmed, bounds, `field "${fieldName}"`);
    for (const v of values) {
      accumulated.add(v);
    }
  }

  return Array.from(accumulated).sort((a, b) => a - b);
}

export function parseCron(expression: string): CronObject {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, received ${typeof expression}`);
  }
  if (expression.length === 0) {
    throw new Error("Cron expression must not be empty");
  }
  if (expression.length > MAX_EXPRESSION_LENGTH) {
    throw new Error(
      `Cron expression length ${expression.length} exceeds maximum of ${MAX_EXPRESSION_LENGTH} characters`
    );
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), got ${fields.length}`
    );
  }

  const result = {} as CronObject;
  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const name = FIELD_ORDER[i];
    result[name] = parseField(fields[i], FIELD_BOUNDS[name], name);
  }

  return result;
}

export default parseCron;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface WaitEntry {
  tokens: number;
  resolve: () => void;
  reject: (err: Error) => void;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;

  private currentTokens: number;
  private lastRefillTime: number;

  private readonly waitQueue: WaitEntry[] = [];
  private drainTimer: ReturnType<typeof setTimeout> | null = null;

  constructor(options: RateLimiterOptions) {
    const { maxTokens, refillRate, refillIntervalMs } = options;

    if (!Number.isFinite(maxTokens) || maxTokens <= 0) {
      throw new RangeError(`maxTokens must be a positive finite number, got ${maxTokens}`);
    }
    if (!Number.isFinite(refillRate) || refillRate <= 0) {
      throw new RangeError(`refillRate must be a positive finite number, got ${refillRate}`);
    }
    if (!Number.isFinite(refillIntervalMs) || refillIntervalMs <= 0) {
      throw new RangeError(`refillIntervalMs must be a positive finite number, got ${refillIntervalMs}`);
    }

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.currentTokens = maxTokens;
    this.lastRefillTime = Date.now();
  }

  private applyLazyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed >= this.refillIntervalMs) {
      const completedIntervals = Math.floor(elapsed / this.refillIntervalMs);
      const added = completedIntervals * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + added);
      // Advance lastRefillTime by completed intervals only — preserves fractional elapsed time
      this.lastRefillTime += completedIntervals * this.refillIntervalMs;
    }
  }

  private validateTokenArg(tokens: number, label = "tokens"): void {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError(`${label} must be a non-negative finite number, got ${tokens}`);
    }
  }

  /**
   * Attempts to consume tokens immediately. Returns false if the queue has
   * pending waiters (to prevent starvation) or if insufficient tokens exist.
   */
  tryConsume(tokens = 1): boolean {
    this.validateTokenArg(tokens);

    if (tokens > this.maxTokens) {
      // Can never be satisfied even on a full bucket
      return false;
    }

    if (tokens === 0) return true;

    this.applyLazyRefill();

    // Honour queue order — don't skip ahead of waiting callers
    if (this.waitQueue.length > 0) return false;

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.applyLazyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.drainWaitQueue();
  }

  waitForTokens(tokens = 1): Promise<void> {
    this.validateTokenArg(tokens);

    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds maxTokens (${this.maxTokens}) — can never be satisfied`
        )
      );
    }

    if (tokens === 0) return Promise.resolve();

    // Fast path — no queue contention
    if (this.waitQueue.length === 0) {
      this.applyLazyRefill();
      if (this.currentTokens >= tokens) {
        this.currentTokens -= tokens;
        return Promise.resolve();
      }
    }

    return new Promise<void>((resolve, reject) => {
      this.waitQueue.push({ tokens, resolve, reject });
      this.scheduleNextDrain();
    });
  }

  private scheduleNextDrain(): void {
    if (this.drainTimer !== null) return;

    const head = this.waitQueue[0];
    if (!head) return;

    this.applyLazyRefill();

    const deficit = head.tokens - this.currentTokens;

    let delayMs: number;
    if (deficit <= 0) {
      delayMs = 0;
    } else {
      const intervalsNeeded = Math.ceil(deficit / this.refillRate);
      const elapsedInCurrentInterval = Date.now() - this.lastRefillTime;
      const remainingInCurrentInterval = Math.max(0, this.refillIntervalMs - elapsedInCurrentInterval);
      // First interval covers remainingInCurrentInterval; rest are full intervals
      delayMs = remainingInCurrentInterval + (intervalsNeeded - 1) * this.refillIntervalMs;
    }

    this.drainTimer = setTimeout(() => {
      this.drainTimer = null;
      this.drainWaitQueue();
    }, Math.max(0, delayMs));
  }

  private drainWaitQueue(): void {
    this.applyLazyRefill();

    while (this.waitQueue.length > 0) {
      const head = this.waitQueue[0];

      if (this.currentTokens < head.tokens) {
        // Not enough yet — reschedule for when the bucket will have enough
        break;
      }

      this.currentTokens -= head.tokens;
      this.waitQueue.shift();
      head.resolve();
    }

    if (this.waitQueue.length > 0) {
      this.scheduleNextDrain();
    }
  }
}

export default RateLimiter;

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldMeta {
  name: keyof CronExpression;
  min: number;
  max: number;
}

const FIELDS: FieldMeta[] = [
  { name: "minute",     min: 0,  max: 59 },
  { name: "hour",       min: 0,  max: 23 },
  { name: "dayOfMonth", min: 1,  max: 31 },
  { name: "month",      min: 1,  max: 12 },
  { name: "dayOfWeek",  min: 0,  max: 7  },
];

function toStrictInt(raw: string, context: string): number {
  if (!/^\d+$/.test(raw)) {
    throw new Error(`Invalid integer "${raw}" in ${context}`);
  }
  return parseInt(raw, 10);
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of range [${min}, ${max}] in ${context}`);
  }
}

function expandRange(start: number, end: number, step: number): number[] {
  if (start > end) {
    throw new Error(`Range start ${start} exceeds end ${end}`);
  }
  if (step <= 0) {
    throw new Error(`Step must be a positive integer, got ${step}`);
  }
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(segment: string, min: number, max: number, fieldName: string): number[] {
  const ctx = `field "${fieldName}", segment "${segment}"`;

  // Step expression: */n  |  start/n  |  start-end/n
  if (segment.includes("/")) {
    const slashIdx = segment.lastIndexOf("/");
    const leftPart = segment.slice(0, slashIdx);
    const stepRaw  = segment.slice(slashIdx + 1);

    const step = toStrictInt(stepRaw, ctx);
    if (step <= 0) throw new Error(`Step must be positive in ${ctx}`);

    let start: number;
    let end: number;

    if (leftPart === "*") {
      start = min;
      end   = max;
    } else if (leftPart.includes("-")) {
      const [s, e] = leftPart.split("-");
      start = toStrictInt(s, ctx);
      end   = toStrictInt(e, ctx);
    } else {
      start = toStrictInt(leftPart, ctx);
      end   = max;
    }

    assertInRange(start, min, max, ctx);
    assertInRange(end,   min, max, ctx);
    return expandRange(start, end, step);
  }

  // Wildcard
  if (segment === "*") {
    return expandRange(min, max, 1);
  }

  // Range: n-m
  if (segment.includes("-")) {
    const dashIdx = segment.indexOf("-");
    const startRaw = segment.slice(0, dashIdx);
    const endRaw   = segment.slice(dashIdx + 1);
    const start = toStrictInt(startRaw, ctx);
    const end   = toStrictInt(endRaw,   ctx);
    assertInRange(start, min, max, ctx);
    assertInRange(end,   min, max, ctx);
    return expandRange(start, end, 1);
  }

  // Single value
  const value = toStrictInt(segment, ctx);
  assertInRange(value, min, max, ctx);
  return [value];
}

function parseField(raw: string, meta: FieldMeta): number[] {
  const { name, min, max } = meta;

  if (!raw || raw.trim().length === 0) {
    throw new Error(`Empty expression for field "${name}"`);
  }

  const seen = new Set<number>();
  for (const segment of raw.split(",")) {
    const trimmed = segment.trim();
    if (!trimmed) throw new Error(`Empty segment in field "${name}"`);
    for (const v of parseSegment(trimmed, min, max, name)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(`Expected a string, got ${typeof expression}`);
  }

  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${parts.length}: "${expression}"`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELDS.length; i++) {
    const meta = FIELDS[i];
    result[meta.name] = parseField(parts[i], meta);
  }

  return result;
}

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldConfig = {
  min: number;
  max: number;
};

const FIELD_NAMES = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
] as const;

const FIELD_CONFIGS: Record<keyof CronResult, FieldConfig> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 }, // 0 and 7 both represent Sunday
};

function buildRange(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function assertInBounds(
  n: number,
  min: number,
  max: number,
  context: string
): void {
  if (!Number.isInteger(n) || n < min || n > max) {
    throw new RangeError(
      `Value ${n} is out of valid range [${min}–${max}] in "${context}"`
    );
  }
}

function parseRangePart(
  token: string,
  min: number,
  max: number
): [number, number] {
  const dashIndex = token.indexOf("-");
  if (dashIndex <= 0 || dashIndex === token.length - 1) {
    throw new SyntaxError(`Malformed range: "${token}"`);
  }
  const startStr = token.slice(0, dashIndex);
  const endStr = token.slice(dashIndex + 1);
  const start = parseInt(startStr, 10);
  const end = parseInt(endStr, 10);
  if (isNaN(start) || isNaN(end)) {
    throw new SyntaxError(`Non-numeric bounds in range: "${token}"`);
  }
  assertInBounds(start, min, max, token);
  assertInBounds(end, min, max, token);
  if (start > end) {
    throw new RangeError(`Range start exceeds end in "${token}"`);
  }
  return [start, end];
}

function parseToken(token: string, min: number, max: number): number[] {
  if (token === "") {
    throw new SyntaxError("Empty token encountered");
  }

  // Step expression: */n  |  a-b/n  |  a/n
  if (token.includes("/")) {
    const slashCount = (token.match(/\//g) ?? []).length;
    if (slashCount !== 1) {
      throw new SyntaxError(`Multiple slashes in token: "${token}"`);
    }
    const slashIndex = token.indexOf("/");
    const basePart = token.slice(0, slashIndex);
    const stepStr = token.slice(slashIndex + 1);

    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) {
      throw new RangeError(`Step must be a positive integer in "${token}"`);
    }

    let start: number;
    let end: number;

    if (basePart === "*") {
      start = min;
      end = max;
    } else if (basePart.includes("-")) {
      [start, end] = parseRangePart(basePart, min, max);
    } else {
      start = parseInt(basePart, 10);
      if (isNaN(start)) {
        throw new SyntaxError(`Invalid base in step expression: "${token}"`);
      }
      assertInBounds(start, min, max, token);
      end = max;
    }

    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
    return result;
  }

  // Range expression: a-b
  if (token.includes("-")) {
    const [start, end] = parseRangePart(token, min, max);
    return buildRange(start, end);
  }

  // Wildcard
  if (token === "*") {
    return buildRange(min, max);
  }

  // Bare integer
  const n = parseInt(token, 10);
  if (isNaN(n) || String(n) !== token) {
    throw new SyntaxError(`Unrecognized token: "${token}"`);
  }
  assertInBounds(n, min, max, token);
  return [n];
}

function parseField(raw: string, min: number, max: number): number[] {
  if (raw === "") {
    throw new SyntaxError("Empty field encountered");
  }

  // Reject leading/trailing/doubled commas
  if (/^,|,$|,,/.test(raw)) {
    throw new SyntaxError(`Malformed comma list: "${raw}"`);
  }

  const parts = raw.split(",");
  const seen = new Set<number>();

  for (const part of parts) {
    for (const value of parseToken(part, min, max)) {
      seen.add(value);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string" || expression.trim() === "") {
    throw new TypeError("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronResult;

  for (let i = 0; i < FIELD_NAMES.length; i++) {
    const name = FIELD_NAMES[i];
    const { min, max } = FIELD_CONFIGS[name];
    try {
      result[name] = parseField(fields[i], min, max);
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      throw new (err instanceof TypeError ? TypeError : err instanceof RangeError ? RangeError : SyntaxError)(
        `Field "${name}" (position ${i + 1}): ${msg}`
      );
    }
  }

  return result;
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervalsElapsed = Math.floor(elapsed / this.refillIntervalMs);

    if (intervalsElapsed > 0) {
      this.currentTokens = Math.min(
        this.maxTokens,
        this.currentTokens + intervalsElapsed * this.refillRate
      );
      this.lastRefillTime += intervalsElapsed * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens must be > 0"));
    if (tokens > this.maxTokens) return Promise.reject(new RangeError("tokens exceeds maxTokens"));

    return new Promise((resolve) => {
      const attempt = (): void => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();
        const deficit = tokens - this.currentTokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const delayMs = intervalsNeeded * this.refillIntervalMs;
        const clampedDelay = Math.max(1, delayMs);

        setTimeout(attempt, clampedDelay);
      };

      attempt();
    });
  }
}

export default RateLimiter;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface Waiter {
  tokens: number;
  resolve: () => void;
  reject: (err: Error) => void;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: Waiter[] = [];
  private scheduledCheck: ReturnType<typeof setTimeout> | null = null;

  constructor(options: RateLimiterOptions) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError("maxTokens must be a finite positive number");
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate < 0) {
      throw new RangeError("refillRate must be a finite non-negative number");
    }
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0) {
      throw new RangeError("refillIntervalMs must be a finite positive number");
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = Math.max(0, now - this.lastRefillTime);
    if (elapsed === 0) return;

    this.lastRefillTime = now;

    if (this.refillRate > 0) {
      const tokensToAdd = (elapsed / this.refillIntervalMs) * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
    }
  }

  private msUntilTokens(needed: number): number {
    const deficit = needed - this.currentTokens;
    if (deficit <= 0) return 0;
    if (this.refillRate <= 0) return Infinity;
    const tokensPerMs = this.refillRate / this.refillIntervalMs;
    return deficit / tokensPerMs;
  }

  private processQueue(): void {
    this.refill();

    while (this.waitQueue.length > 0) {
      const next = this.waitQueue[0];
      if (this.currentTokens >= next.tokens) {
        this.waitQueue.shift();
        this.currentTokens -= next.tokens;
        next.resolve();
      } else {
        break;
      }
    }

    if (this.waitQueue.length > 0) {
      this.scheduleNextCheck();
    }
  }

  private scheduleNextCheck(): void {
    if (this.scheduledCheck !== null || this.waitQueue.length === 0) return;

    this.refill();
    const next = this.waitQueue[0];
    const delay = this.msUntilTokens(next.tokens);

    if (!isFinite(delay)) {
      const err = new Error(
        `Tokens will never be available: refillRate is 0 and current tokens (${this.currentTokens}) are insufficient`
      );
      while (this.waitQueue.length > 0) {
        this.waitQueue.shift()!.reject(err);
      }
      return;
    }

    this.scheduledCheck = setTimeout(() => {
      this.scheduledCheck = null;
      this.processQueue();
    }, Math.ceil(delay));
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError("tokens must be a finite non-negative number");
    }
    if (tokens === 0) return true;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    if (this.scheduledCheck !== null) {
      clearTimeout(this.scheduledCheck);
      this.scheduledCheck = null;
    }

    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();

    if (this.waitQueue.length > 0) {
      this.processQueue();
    }
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0) {
      return Promise.reject(new RangeError("tokens must be a finite non-negative number"));
    }
    if (tokens === 0) return Promise.resolve();
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds maxTokens (${this.maxTokens}); can never be satisfied`
        )
      );
    }

    // Only bypass the queue if no one is waiting ahead of us — preserves FIFO fairness
    if (this.waitQueue.length === 0 && this.tryConsume(tokens)) {
      return Promise.resolve();
    }

    return new Promise<void>((resolve, reject) => {
      this.waitQueue.push({ tokens, resolve, reject });
      this.scheduleNextCheck();
    });
  }
}

export default RateLimiter;

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronExpression;

interface FieldConfig {
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: Record<FieldName, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  }, // 7 = Sunday alias, normalized to 0
} as const;

const FIELD_ORDER: FieldName[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

function strictParseInt(raw: string, context: string): number {
  if (!/^\d+$/.test(raw)) {
    throw new Error(`Invalid integer "${raw}" in ${context}`);
  }
  const n = Number(raw);
  if (!Number.isSafeInteger(n)) {
    throw new Error(`Integer overflow "${raw}" in ${context}`);
  }
  return n;
}

function assertInRange(value: number, config: FieldConfig, context: string): void {
  if (value < config.min || value > config.max) {
    throw new Error(
      `Value ${value} out of range [${config.min}-${config.max}] in ${context}`
    );
  }
}

function expandStep(start: number, end: number, step: number, config: FieldConfig, context: string): number[] {
  if (step < 1) throw new Error(`Step must be >= 1, got ${step} in ${context}`);
  assertInRange(start, config, context);
  assertInRange(end, config, context);
  if (start > end) {
    throw new Error(`Range start ${start} > end ${end} in ${context}`);
  }
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSinglePart(part: string, config: FieldConfig, context: string): number[] {
  const trimmed = part.trim();
  if (trimmed === "") {
    throw new Error(`Empty segment in ${context}`);
  }

  // Step: */n, a-b/n, or n/n
  if (trimmed.includes("/")) {
    const slashCount = (trimmed.match(/\//g) ?? []).length;
    if (slashCount !== 1) {
      throw new Error(`Multiple "/" in "${trimmed}" in ${context}`);
    }
    const slashIdx = trimmed.indexOf("/");
    const rangePart = trimmed.slice(0, slashIdx);
    const stepPart  = trimmed.slice(slashIdx + 1);
    const step = strictParseInt(stepPart, context);
    if (step < 1) throw new Error(`Step must be >= 1 in ${context}`);

    if (rangePart === "*") {
      return expandStep(config.min, config.max, step, config, context);
    }

    if (rangePart.includes("-")) {
      const [s, e, ...rest] = rangePart.split("-");
      if (rest.length > 0) throw new Error(`Invalid range "${rangePart}" in ${context}`);
      return expandStep(
        strictParseInt(s, context),
        strictParseInt(e, context),
        step,
        config,
        context
      );
    }

    // n/step → from n to max
    const start = strictParseInt(rangePart, context);
    assertInRange(start, config, context);
    return expandStep(start, config.max, step, config, context);
  }

  // Wildcard
  if (trimmed === "*") {
    return expandStep(config.min, config.max, 1, config, context);
  }

  // Range: a-b
  if (trimmed.includes("-")) {
    const [s, e, ...rest] = trimmed.split("-");
    if (rest.length > 0) throw new Error(`Invalid range "${trimmed}" in ${context}`);
    return expandStep(
      strictParseInt(s, context),
      strictParseInt(e, context),
      1,
      config,
      context
    );
  }

  // Single value
  const value = strictParseInt(trimmed, context);
  assertInRange(value, config, context);
  return [value];
}

function parseField(raw: string, config: FieldConfig, name: string): number[] {
  if (raw === "" || raw.trim() === "") {
    throw new Error(`Field "${name}" is empty`);
  }

  const seen = new Set<number>();

  if (raw.includes(",")) {
    const parts = raw.split(",");
    if (parts.some(p => p.trim() === "")) {
      throw new Error(`Empty segment in comma list for field "${name}"`);
    }
    for (const part of parts) {
      for (const v of parseSinglePart(part, config, name)) {
        seen.add(v);
      }
    }
  } else {
    for (const v of parseSinglePart(raw, config, name)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(`Cron expression must be a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("Cron expression must not be empty");
  }

  const parts = trimmed.split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${parts.length}: "${trimmed}"`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const name   = FIELD_ORDER[i];
    const config = FIELD_CONFIGS[name];
    const raw    = parts[i];

    let values = parseField(raw, config, name);

    // dayOfWeek: normalize 7 (Sunday alias) → 0, then deduplicate
    if (name === "dayOfWeek") {
      const normalized = new Set(values.map(v => (v === 7 ? 0 : v)));
      values = Array.from(normalized).sort((a, b) => a - b);
    }

    result[name] = values;
  }

  return result;
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export default class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError(`maxTokens must be a finite positive number, got ${options.maxTokens}`);
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate < 0) {
      throw new RangeError(`refillRate must be a finite non-negative number, got ${options.refillRate}`);
    }
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0) {
      throw new RangeError(`refillIntervalMs must be a finite positive number, got ${options.refillIntervalMs}`);
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private applyRefill(): void {
    if (this.refillRate === 0) return;

    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed <= 0) return;

    const tokensToAdd = (elapsed / this.refillIntervalMs) * this.refillRate;
    this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
    this.lastRefillTime = now;
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError(`tokens must be a finite non-negative number, got ${tokens}`);
    }

    if (tokens === 0) return true;

    this.applyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.applyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError(`tokens must be a finite non-negative number, got ${tokens}`);
    }

    if (tokens === 0) return;

    if (tokens > this.maxTokens) {
      throw new RangeError(
        `Requested ${tokens} tokens exceeds bucket capacity of ${this.maxTokens} — this will never be satisfiable`
      );
    }

    if (this.refillRate === 0) {
      // No refill possible; only satisfiable if tokens are already present
      this.applyRefill();
      if (this.currentTokens >= tokens) {
        this.currentTokens -= tokens;
        return;
      }
      throw new Error(
        `refillRate is 0 and current tokens (${this.currentTokens}) are insufficient for request of ${tokens}`
      );
    }

    // eslint-disable-next-line no-constant-condition
    while (true) {
      this.applyRefill();

      if (this.currentTokens >= tokens) {
        this.currentTokens -= tokens;
        return;
      }

      // Compute the minimum wait until we have enough tokens, then sleep
      // precisely that long rather than polling on an arbitrary interval.
      const deficit = tokens - this.currentTokens;
      const msPerToken = this.refillIntervalMs / this.refillRate;
      const waitMs = Math.ceil(deficit * msPerToken);

      // Guard: if the calculation somehow yields a non-positive wait we still
      // yield the event loop to avoid a busy-spin.
      await new Promise<void>((resolve) => setTimeout(resolve, Math.max(1, waitMs)));
    }
  }
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      this.currentTokens = Math.min(
        this.maxTokens,
        this.currentTokens + intervals * this.refillRate
      );
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens must be > 0"));
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(`Requested tokens (${tokens}) exceed maxTokens (${this.maxTokens})`)
      );
    }

    return new Promise((resolve) => {
      const attempt = (): void => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();

        const deficit = tokens - this.currentTokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const msUntilReady = Math.max(
          1,
          intervalsNeeded * this.refillIntervalMs -
            (Date.now() - this.lastRefillTime) % this.refillIntervalMs
        );

        setTimeout(attempt, msUntilReady);
      };

      attempt();
    });
  }
}

export default RateLimiter;

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly name: keyof CronExpression;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 6 },
];

function parseNonNegativeInteger(raw: string, context: string): number {
  if (!/^\d+$/.test(raw)) {
    throw new Error(`Invalid token "${raw}" in field "${context}": expected a non-negative integer`);
  }
  const value = parseInt(raw, 10);
  if (!Number.isSafeInteger(value)) {
    throw new Error(`Value "${raw}" in field "${context}" exceeds safe integer range`);
  }
  return value;
}

function assertInBounds(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new Error(`Value ${value} is out of range [${min}-${max}] for field "${context}"`);
  }
}

function expandRange(start: number, end: number, step: number, context: string): number[] {
  if (step <= 0) {
    throw new Error(`Step value must be a positive integer in field "${context}", got ${step}`);
  }
  if (start > end) {
    throw new Error(`Range start ${start} exceeds range end ${end} in field "${context}"`);
  }
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(segment: string, min: number, max: number, fieldName: string): number[] {
  // Step expression: base/step  (base may be *, a number, or a range)
  const slashIdx = segment.indexOf("/");
  if (slashIdx !== -1) {
    const basePart = segment.slice(0, slashIdx);
    const stepPart = segment.slice(slashIdx + 1);

    if (basePart === "" || stepPart === "") {
      throw new Error(`Malformed step expression "${segment}" in field "${fieldName}"`);
    }
    if (segment.indexOf("/", slashIdx + 1) !== -1) {
      throw new Error(`Multiple "/" in segment "${segment}" in field "${fieldName}"`);
    }

    const step = parseNonNegativeInteger(stepPart, fieldName);

    if (basePart === "*") {
      return expandRange(min, max, step, fieldName);
    }

    const dashIdx = basePart.indexOf("-");
    if (dashIdx !== -1) {
      const [startStr, endStr] = [basePart.slice(0, dashIdx), basePart.slice(dashIdx + 1)];
      if (startStr === "" || endStr === "") {
        throw new Error(`Malformed range "${basePart}" in field "${fieldName}"`);
      }
      const start = parseNonNegativeInteger(startStr, fieldName);
      const end = parseNonNegativeInteger(endStr, fieldName);
      assertInBounds(start, min, max, fieldName);
      assertInBounds(end, min, max, fieldName);
      return expandRange(start, end, step, fieldName);
    }

    const start = parseNonNegativeInteger(basePart, fieldName);
    assertInBounds(start, min, max, fieldName);
    return expandRange(start, max, step, fieldName);
  }

  // Wildcard
  if (segment === "*") {
    return expandRange(min, max, 1, fieldName);
  }

  // Range: start-end
  const dashIdx = segment.indexOf("-");
  if (dashIdx !== -1) {
    const startStr = segment.slice(0, dashIdx);
    const endStr = segment.slice(dashIdx + 1);
    if (startStr === "" || endStr === "") {
      throw new Error(`Malformed range "${segment}" in field "${fieldName}"`);
    }
    if (endStr.includes("-")) {
      throw new Error(`Multiple "-" in range "${segment}" in field "${fieldName}"`);
    }
    const start = parseNonNegativeInteger(startStr, fieldName);
    const end = parseNonNegativeInteger(endStr, fieldName);
    assertInBounds(start, min, max, fieldName);
    assertInBounds(end, min, max, fieldName);
    return expandRange(start, end, 1, fieldName);
  }

  // Single value
  const value = parseNonNegativeInteger(segment, fieldName);
  assertInBounds(value, min, max, fieldName);
  return [value];
}

function parseField(expr: string, min: number, max: number, fieldName: string): number[] {
  if (expr === "") {
    throw new Error(`Field "${fieldName}" is empty`);
  }

  const segments = expr.split(",");
  if (segments.some((s) => s === "")) {
    throw new Error(`Empty segment in comma-separated list for field "${fieldName}"`);
  }

  const valueSet = new Set<number>();
  for (const segment of segments) {
    for (const v of parseSegment(segment, min, max, fieldName)) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new Error("Cron expression must be a string");
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), got ${fields.length}`
    );
  }

  const result = {} as CronExpression;
  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const { name, min, max } = FIELD_CONFIGS[i];
    result[name] = parseField(fields[i], min, max, name);
  }

  return result;
}

export default parseCron;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 7],
};

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseField(
  expr: string,
  fieldName: keyof CronFields
): number[] {
  const [min, max] = FIELD_RANGES[fieldName];

  const validate = (n: number): number => {
    if (!Number.isInteger(n) || n < min || n > max) {
      throw new RangeError(
        `Value ${n} out of range [${min}, ${max}] for field "${fieldName}"`
      );
    }
    return n;
  };

  // Comma-separated list — split and recurse
  if (expr.includes(",")) {
    const values = expr
      .split(",")
      .flatMap((part) => parseField(part.trim(), fieldName));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Wildcard
  if (expr === "*") {
    return range(min, max);
  }

  // Step value: */step or start-end/step
  if (expr.includes("/")) {
    const [rangePart, stepPart] = expr.split("/");
    const step = parseInt(stepPart, 10);

    if (!Number.isInteger(step) || step <= 0) {
      throw new SyntaxError(`Invalid step value "${stepPart}" in "${expr}"`);
    }

    let start = min;
    let end = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [s, e] = rangePart.split("-").map((n) => parseInt(n, 10));
        start = validate(s);
        end = validate(e);
        if (start > end) {
          throw new RangeError(
            `Range start ${start} > end ${end} in field "${fieldName}"`
          );
        }
      } else {
        start = validate(parseInt(rangePart, 10));
      }
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) values.push(i);
    return values;
  }

  // Range: start-end
  if (expr.includes("-")) {
    const parts = expr.split("-");
    if (parts.length !== 2) {
      throw new SyntaxError(`Invalid range expression "${expr}"`);
    }
    const start = validate(parseInt(parts[0], 10));
    const end = validate(parseInt(parts[1], 10));
    if (start > end) {
      throw new RangeError(
        `Range start ${start} > end ${end} in field "${fieldName}"`
      );
    }
    return range(start, end);
  }

  // Single numeric value
  const n = parseInt(expr, 10);
  if (isNaN(n)) {
    throw new SyntaxError(`Invalid token "${expr}" in field "${fieldName}"`);
  }
  validate(n);

  // Normalize Sunday: both 0 and 7 map to 0
  if (fieldName === "dayOfWeek" && n === 7) return [0];
  return [n];
}

function parseCron(expression: string): CronFields {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new SyntaxError("Cron expression must be a non-empty string");
  }

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields, got ${parts.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = parts;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(domExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dowExpr, "dayOfWeek"),
  };
}

export default parseCron;
export { parseCron, type CronFields };

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: {
    maxTokens: number;
    refillRate: number;
    refillIntervalMs: number;
  }) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError("maxTokens must be a positive finite number");
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate < 0) {
      throw new RangeError("refillRate must be a non-negative finite number");
    }
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0) {
      throw new RangeError("refillIntervalMs must be a positive finite number");
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed <= 0) return;

    const tokensToAdd = (elapsed / this.refillIntervalMs) * this.refillRate;
    this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
    this.lastRefillTime = now;
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError("tokens must be a non-negative finite number");
    }
    if (tokens === 0) return true;
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0) {
      return Promise.reject(
        new RangeError("tokens must be a non-negative finite number")
      );
    }
    if (tokens === 0) return Promise.resolve();
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested tokens (${tokens}) exceed maxTokens (${this.maxTokens}) — request can never be satisfied`
        )
      );
    }
    if (this.refillRate === 0) {
      // Tokens will never replenish; only satisfy if currently available
      this.refill();
      if (this.currentTokens >= tokens) {
        this.currentTokens -= tokens;
        return Promise.resolve();
      }
      return Promise.reject(
        new Error(
          `Cannot wait for tokens: refillRate is 0 and insufficient tokens available (${this.currentTokens} < ${tokens})`
        )
      );
    }

    return new Promise<void>((resolve) => {
      const attempt = (): void => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();
        const deficit = tokens - this.currentTokens;
        const tokensPerMs = this.refillRate / this.refillIntervalMs;
        // Guard against degenerate tokensPerMs — already handled refillRate=0 above,
        // but protect against floating-point edge cases producing 0 or negative.
        const waitMs = tokensPerMs > 0 ? Math.ceil(deficit / tokensPerMs) : 10;
        setTimeout(attempt, Math.max(1, waitMs));
      };

      attempt();
    });
  }
}

export default RateLimiter;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_CONFIGS = [
  { min: 0,  max: 59, name: "minute"     },
  { min: 0,  max: 23, name: "hour"       },
  { min: 1,  max: 31, name: "dayOfMonth" },
  { min: 1,  max: 12, name: "month"      },
  { min: 0,  max: 7,  name: "dayOfWeek"  }, // 0 and 7 both = Sunday
] as const;

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of valid range [${min}, ${max}] in field "${context}"`
    );
  }
}

function buildRange(start: number, end: number, step: number): number[] {
  if (start > end) throw new RangeError(`Range start ${start} exceeds end ${end}`);
  if (step <= 0)   throw new RangeError(`Step must be a positive integer, got ${step}`);
  const values: number[] = [];
  for (let i = start; i <= end; i += step) values.push(i);
  return values;
}

function parseSegment(segment: string, min: number, max: number, fieldName: string): number[] {
  // Step expression: <base>/<step>  where base is *, n, or n-m
  const stepMatch = segment.match(/^([^/]+)\/(\d+)$/);
  if (stepMatch) {
    const step = parseInt(stepMatch[2], 10);
    if (step <= 0) throw new RangeError(`Step must be positive, got ${step} in "${segment}"`);

    let rangeMin: number;
    let rangeMax: number;

    if (stepMatch[1] === "*") {
      rangeMin = min;
      rangeMax = max;
    } else {
      const rangeMatch = stepMatch[1].match(/^(\d+)-(\d+)$/);
      if (rangeMatch) {
        rangeMin = parseInt(rangeMatch[1], 10);
        rangeMax = parseInt(rangeMatch[2], 10);
        assertInRange(rangeMin, min, max, fieldName);
        assertInRange(rangeMax, min, max, fieldName);
        if (rangeMin > rangeMax) {
          throw new RangeError(`Range start ${rangeMin} > end ${rangeMax} in "${segment}"`);
        }
      } else if (/^\d+$/.test(stepMatch[1])) {
        rangeMin = parseInt(stepMatch[1], 10);
        assertInRange(rangeMin, min, max, fieldName);
        rangeMax = max;
      } else {
        throw new SyntaxError(`Invalid step base "${stepMatch[1]}" in field "${fieldName}"`);
      }
    }

    return buildRange(rangeMin, rangeMax, step);
  }

  // Wildcard
  if (segment === "*") {
    return buildRange(min, max, 1);
  }

  // Range: n-m
  const rangeMatch = segment.match(/^(\d+)-(\d+)$/);
  if (rangeMatch) {
    const start = parseInt(rangeMatch[1], 10);
    const end   = parseInt(rangeMatch[2], 10);
    assertInRange(start, min, max, fieldName);
    assertInRange(end,   min, max, fieldName);
    if (start > end) {
      throw new RangeError(`Range start ${start} > end ${end} in field "${fieldName}"`);
    }
    return buildRange(start, end, 1);
  }

  // Single integer
  if (/^\d+$/.test(segment)) {
    const num = parseInt(segment, 10);
    assertInRange(num, min, max, fieldName);
    return [num];
  }

  throw new SyntaxError(`Unrecognized cron segment "${segment}" in field "${fieldName}"`);
}

function parseField(raw: string, min: number, max: number, fieldName: string): number[] {
  const parts = raw.split(",");

  if (parts.some(p => p.trim() === "")) {
    throw new SyntaxError(`Empty or trailing comma in field "${fieldName}": "${raw}"`);
  }

  const valueSet = new Set<number>();

  for (const part of parts) {
    for (const v of parseSegment(part.trim(), min, max, fieldName)) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, received ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const rawFields = trimmed.split(/\s+/);
  if (rawFields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields (got ${rawFields.length}): "${expression}"`
    );
  }

  const [minuteRaw, hourRaw, domRaw, monthRaw, dowRaw] = rawFields;

  const minute     = parseField(minuteRaw, 0,  59, "minute");
  const hour       = parseField(hourRaw,   0,  23, "hour");
  const dayOfMonth = parseField(domRaw,    1,  31, "dayOfMonth");
  const month      = parseField(monthRaw,  1,  12, "month");

  // Parse dayOfWeek (0–7), then normalize 7 → 0 (both represent Sunday)
  const rawDow = parseField(dowRaw, 0, 7, "dayOfWeek");
  const dowNormalized = new Set(rawDow.map(v => (v === 7 ? 0 : v)));
  const dayOfWeek = Array.from(dowNormalized).sort((a, b) => a - b);

  return { minute, hour, dayOfMonth, month, dayOfWeek };
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be greater than 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be greater than 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be greater than 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervalsElapsed = Math.floor(elapsed / this.refillIntervalMs);

    if (intervalsElapsed > 0) {
      const tokensToAdd = intervalsElapsed * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervalsElapsed * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be greater than 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) throw new RangeError("tokens must be greater than 0");
    if (tokens > this.maxTokens) {
      throw new RangeError(`Requested tokens (${tokens}) exceed maxTokens (${this.maxTokens})`);
    }

    while (!this.tryConsume(tokens)) {
      this.refill();
      const deficit = tokens - this.currentTokens;
      const intervalsNeeded = Math.ceil(deficit / this.refillRate);
      const waitMs = Math.max(1, intervalsNeeded * this.refillIntervalMs);
      await new Promise<void>((resolve) => setTimeout(resolve, waitMs));
    }
  }
}

export default RateLimiter;

type CronField = {
  values: number[];
};

type ParsedCron = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldConfig = {
  min: number;
  max: number;
};

const FIELD_CONFIGS: FieldConfig[] = [
  { min: 0, max: 59 },   // minute
  { min: 0, max: 23 },   // hour
  { min: 1, max: 31 },   // dayOfMonth
  { min: 1, max: 12 },   // month
  { min: 0, max: 7 },    // dayOfWeek (0 and 7 both = Sunday)
];

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] in field: ${context}`);
  }
}

function parseNumber(token: string, min: number, max: number): number {
  const n = Number(token);
  if (!Number.isInteger(n) || isNaN(n)) {
    throw new TypeError(`Expected integer, got: "${token}"`);
  }
  assertInRange(n, min, max, token);
  return n;
}

function expandRange(start: number, end: number, step: number, min: number, max: number): number[] {
  if (start > end) {
    throw new RangeError(`Range start ${start} is greater than end ${end}`);
  }
  assertInRange(start, min, max, `range start ${start}`);
  assertInRange(end, min, max, `range end ${end}`);
  if (step < 1) {
    throw new RangeError(`Step must be >= 1, got: ${step}`);
  }
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseFieldToken(token: string, config: FieldConfig): number[] {
  const { min, max } = config;

  // Step with wildcard: */n
  if (token.startsWith("*/")) {
    const step = Number(token.slice(2));
    if (!Number.isInteger(step) || isNaN(step) || step < 1) {
      throw new TypeError(`Invalid step value in token: "${token}"`);
    }
    return expandRange(min, max, step, min, max);
  }

  // Range with optional step: start-end or start-end/step
  if (token.includes("-")) {
    const [rangePart, stepPart] = token.split("/");
    const [startStr, endStr] = rangePart.split("-");
    const start = parseNumber(startStr, min, max);
    const end = parseNumber(endStr, min, max);
    const step = stepPart !== undefined ? Number(stepPart) : 1;
    if (!Number.isInteger(step) || isNaN(step) || step < 1) {
      throw new TypeError(`Invalid step value in token: "${token}"`);
    }
    return expandRange(start, end, step, min, max);
  }

  // Plain number
  if (token !== "*") {
    const n = parseNumber(token, min, max);
    return [n];
  }

  // Wildcard: *
  return expandRange(min, max, 1, min, max);
}

function parseField(expression: string, config: FieldConfig): number[] {
  const tokens = expression.split(",");
  const allValues = new Set<number>();

  for (const token of tokens) {
    const trimmed = token.trim();
    if (!trimmed) {
      throw new SyntaxError(`Empty token in expression: "${expression}"`);
    }
    for (const v of parseFieldToken(trimmed, config)) {
      allValues.add(v);
    }
  }

  return Array.from(allValues).sort((a, b) => a - b);
}

function normalizeDayOfWeek(values: number[]): number[] {
  // Treat 7 as Sunday (0)
  const normalized = new Set<number>();
  for (const v of values) {
    normalized.add(v === 7 ? 0 : v);
  }
  return Array.from(normalized).sort((a, b) => a - b);
}

function parseCron(expression: string): ParsedCron {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new TypeError("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields in cron expression, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  const minute = parseField(minuteExpr, FIELD_CONFIGS[0]);
  const hour = parseField(hourExpr, FIELD_CONFIGS[1]);
  const dayOfMonth = parseField(domExpr, FIELD_CONFIGS[2]);
  const month = parseField(monthExpr, FIELD_CONFIGS[3]);
  const dayOfWeek = normalizeDayOfWeek(parseField(dowExpr, FIELD_CONFIGS[4]));

  return { minute, hour, dayOfMonth, month, dayOfWeek };
}

export default parseCron;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervalsElapsed = Math.floor(elapsed / this.refillIntervalMs);

    if (intervalsElapsed > 0) {
      const tokensToAdd = intervalsElapsed * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervalsElapsed * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) {
      throw new RangeError(`Requested tokens (${tokens}) exceed maxTokens (${this.maxTokens})`);
    }

    while (!this.tryConsume(tokens)) {
      const waitMs = this.estimateWaitMs(tokens);
      await new Promise<void>((resolve) => setTimeout(resolve, waitMs));
    }
  }

  private estimateWaitMs(tokens: number): number {
    this.refill();
    const tokensNeeded = tokens - this.currentTokens;

    if (tokensNeeded <= 0) return 0;

    const intervalsNeeded = Math.ceil(tokensNeeded / this.refillRate);
    const timeUntilNextRefill = this.refillIntervalMs - (Date.now() - this.lastRefillTime);

    return Math.max(1, timeUntilNextRefill + (intervalsNeeded - 1) * this.refillIntervalMs);
  }
}

export default RateLimiter;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface Waiter {
  tokens: number;
  resolve: () => void;
  reject: (err: Error) => void;
}

export default class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waiters: Waiter[] = [];
  private drainTimer: ReturnType<typeof setTimeout> | null = null;

  constructor(options: RateLimiterOptions) {
    const { maxTokens, refillRate, refillIntervalMs } = options;

    if (!Number.isFinite(maxTokens) || maxTokens <= 0)
      throw new RangeError("maxTokens must be a positive finite number");
    if (!Number.isFinite(refillRate) || refillRate < 0)
      throw new RangeError("refillRate must be a non-negative finite number");
    if (!Number.isFinite(refillIntervalMs) || refillIntervalMs <= 0)
      throw new RangeError("refillIntervalMs must be a positive finite number");

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.currentTokens = maxTokens;
    this.lastRefillTime = Date.now();
  }

  private applyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed > 0 && this.refillRate > 0) {
      const tokensToAdd = (elapsed / this.refillIntervalMs) * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
    }

    this.lastRefillTime = now;
  }

  private assertValidTokenCount(tokens: number): void {
    if (!Number.isFinite(tokens) || tokens <= 0)
      throw new RangeError("tokens must be a positive finite number");
  }

  tryConsume(tokens: number = 1): boolean {
    this.assertValidTokenCount(tokens);

    // A request exceeding the bucket capacity can never succeed.
    if (tokens > this.maxTokens) return false;

    this.applyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.applyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.flushWaiters();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    this.assertValidTokenCount(tokens);

    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds bucket capacity of ${this.maxTokens}; ` +
            `this promise would never resolve`
        )
      );
    }

    this.applyRefill();

    // Maintain FIFO fairness: only fast-path if no one is already waiting.
    if (this.waiters.length === 0 && this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return Promise.resolve();
    }

    return new Promise<void>((resolve, reject) => {
      this.waiters.push({ tokens, resolve, reject });
      this.scheduleDrain();
    });
  }

  private scheduleDrain(): void {
    // Only one pending drain timer at a time.
    if (this.drainTimer !== null || this.waiters.length === 0) return;

    // With no refill, waiters can only be unblocked by reset().
    if (this.refillRate <= 0) return;

    this.applyRefill();

    const firstWaiter = this.waiters[0];
    const deficit = firstWaiter.tokens - this.currentTokens;

    let delayMs: number;

    if (deficit <= 0) {
      // Already satisfiable — yield to let any synchronous callers finish first.
      delayMs = 0;
    } else {
      const tokensPerMs = this.refillRate / this.refillIntervalMs;
      // Add 1 ms of headroom to account for timer jitter / integer rounding.
      delayMs = Math.ceil(deficit / tokensPerMs) + 1;
    }

    this.drainTimer = setTimeout(() => {
      this.drainTimer = null;
      this.flushWaiters();
    }, delayMs);
  }

  private flushWaiters(): void {
    this.applyRefill();

    while (this.waiters.length > 0) {
      const waiter = this.waiters[0];

      if (this.currentTokens >= waiter.tokens) {
        this.currentTokens -= waiter.tokens;
        this.waiters.shift();
        waiter.resolve();
      } else {
        // Remaining head of queue cannot be satisfied yet; re-schedule.
        break;
      }
    }

    if (this.waiters.length > 0) {
      this.scheduleDrain();
    }
  }
}

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldConfig = {
  min: number;
  max: number;
  name: string;
};

const FIELD_CONFIGS = {
  minute:     { min: 0,  max: 59, name: "minute"     },
  hour:       { min: 0,  max: 23, name: "hour"        },
  dayOfMonth: { min: 1,  max: 31, name: "dayOfMonth"  },
  month:      { min: 1,  max: 12, name: "month"       },
  dayOfWeek:  { min: 0,  max: 6,  name: "dayOfWeek"   },
} as const satisfies Record<keyof CronResult, FieldConfig>;

function generateRange(start: number, end: number, step: number): number[] {
  if (step <= 0) throw new Error(`Step must be positive, got ${step}`);
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function assertInRange(value: number, config: FieldConfig): void {
  if (!Number.isInteger(value) || value < config.min || value > config.max) {
    throw new RangeError(
      `${config.name} value ${value} is out of valid range [${config.min}, ${config.max}]`
    );
  }
}

function parseInteger(raw: string, context: string): number {
  const trimmed = raw.trim();
  if (!/^-?\d+$/.test(trimmed)) {
    throw new SyntaxError(`Expected integer in ${context}, got "${trimmed}"`);
  }
  return parseInt(trimmed, 10);
}

function parseSingleSegment(segment: string, config: FieldConfig): number[] {
  // Step: */N or start-end/N or start/N
  if (segment.includes("/")) {
    const slashIndex = segment.lastIndexOf("/");
    const left = segment.slice(0, slashIndex);
    const stepRaw = segment.slice(slashIndex + 1);

    const step = parseInteger(stepRaw, `step expression "${segment}"`);
    if (step <= 0) {
      throw new RangeError(`Step value must be a positive integer in "${segment}", got ${step}`);
    }

    if (left === "*") {
      return generateRange(config.min, config.max, step);
    }

    if (left.includes("-")) {
      const [startRaw, endRaw] = left.split("-");
      const start = parseInteger(startRaw, `range "${segment}"`);
      const end   = parseInteger(endRaw,   `range "${segment}"`);
      assertInRange(start, config);
      assertInRange(end, config);
      if (start > end) {
        throw new RangeError(`Range start ${start} > end ${end} in "${segment}"`);
      }
      return generateRange(start, end, step);
    }

    // single/N: treat as start with step up to max
    const start = parseInteger(left, `step expression "${segment}"`);
    assertInRange(start, config);
    return generateRange(start, config.max, step);
  }

  // Wildcard
  if (segment === "*") {
    return generateRange(config.min, config.max, 1);
  }

  // Range: start-end
  if (segment.includes("-")) {
    const dashIndex = segment.indexOf("-");
    // Protect against negative numbers — only split on the first dash after position 0
    const startRaw = segment.slice(0, dashIndex);
    const endRaw   = segment.slice(dashIndex + 1);

    if (startRaw === "" || endRaw === "") {
      throw new SyntaxError(`Malformed range "${segment}"`);
    }

    const start = parseInteger(startRaw, `range "${segment}"`);
    const end   = parseInteger(endRaw,   `range "${segment}"`);
    assertInRange(start, config);
    assertInRange(end, config);
    if (start > end) {
      throw new RangeError(`Range start ${start} > end ${end} in "${segment}"`);
    }
    return generateRange(start, end, 1);
  }

  // Single number
  const value = parseInteger(segment, `${config.name} field`);
  assertInRange(value, config);
  return [value];
}

function parseField(expr: string, config: FieldConfig): number[] {
  if (typeof expr !== "string" || expr.trim() === "") {
    throw new SyntaxError(`Empty or invalid expression for field "${config.name}"`);
  }

  // Comma-separated list — split carefully and recurse
  const segments = expr.split(",").map(s => s.trim());
  if (segments.some(s => s === "")) {
    throw new SyntaxError(`Trailing or double comma in "${expr}" for field "${config.name}"`);
  }

  const seen = new Set<number>();
  const values: number[] = [];

  for (const segment of segments) {
    for (const v of parseSingleSegment(segment, config)) {
      if (!seen.has(v)) {
        seen.add(v);
        values.push(v);
      }
    }
  }

  return values.sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, received ${typeof expression}`);
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), ` +
      `got ${fields.length} in "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute:     parseField(minuteExpr, FIELD_CONFIGS.minute),
    hour:       parseField(hourExpr,   FIELD_CONFIGS.hour),
    dayOfMonth: parseField(domExpr,    FIELD_CONFIGS.dayOfMonth),
    month:      parseField(monthExpr,  FIELD_CONFIGS.month),
    dayOfWeek:  parseField(dowExpr,    FIELD_CONFIGS.dayOfWeek),
  };
}

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function parseField(expression: string, min: number, max: number): number[] {
  const results = new Set<number>();

  const parts = expression.split(",");

  for (const part of parts) {
    const trimmed = part.trim();

    if (trimmed === "*") {
      for (let i = min; i <= max; i++) results.add(i);
      continue;
    }

    if (trimmed.startsWith("*/")) {
      const step = parseInt(trimmed.slice(2), 10);
      if (isNaN(step) || step <= 0) {
        throw new Error(`Invalid step value in expression: "${trimmed}"`);
      }
      for (let i = min; i <= max; i += step) results.add(i);
      continue;
    }

    if (trimmed.includes("/")) {
      const [rangePart, stepPart] = trimmed.split("/");
      const step = parseInt(stepPart, 10);
      if (isNaN(step) || step <= 0) {
        throw new Error(`Invalid step value in expression: "${trimmed}"`);
      }
      if (rangePart.includes("-")) {
        const [startStr, endStr] = rangePart.split("-");
        const start = parseInt(startStr, 10);
        const end = parseInt(endStr, 10);
        if (isNaN(start) || isNaN(end)) {
          throw new Error(`Invalid range in expression: "${trimmed}"`);
        }
        validateRange(start, min, max, trimmed);
        validateRange(end, min, max, trimmed);
        if (start > end) {
          throw new Error(`Range start exceeds end in expression: "${trimmed}"`);
        }
        for (let i = start; i <= end; i += step) results.add(i);
      } else {
        const start = parseInt(rangePart, 10);
        if (isNaN(start)) {
          throw new Error(`Invalid expression: "${trimmed}"`);
        }
        validateRange(start, min, max, trimmed);
        for (let i = start; i <= max; i += step) results.add(i);
      }
      continue;
    }

    if (trimmed.includes("-")) {
      const [startStr, endStr] = trimmed.split("-");
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);
      if (isNaN(start) || isNaN(end)) {
        throw new Error(`Invalid range in expression: "${trimmed}"`);
      }
      validateRange(start, min, max, trimmed);
      validateRange(end, min, max, trimmed);
      if (start > end) {
        throw new Error(`Range start exceeds end in expression: "${trimmed}"`);
      }
      for (let i = start; i <= end; i++) results.add(i);
      continue;
    }

    const value = parseInt(trimmed, 10);
    if (isNaN(value)) {
      throw new Error(`Invalid value in expression: "${trimmed}"`);
    }
    validateRange(value, min, max, trimmed);
    results.add(value);
  }

  return Array.from(results).sort((a, b) => a - b);
}

function validateRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new Error(
      `Value ${value} is out of range [${min}, ${max}] in expression: "${context}"`
    );
  }
}

function parseCron(expression: string): CronResult {
  if (!expression || typeof expression !== "string") {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] = fields;
  const fieldNames = Object.keys(FIELD_RANGES) as Array<keyof CronResult>;

  const [minute, hour, dayOfMonth, month, dayOfWeek] = [
    minuteExpr,
    hourExpr,
    dayOfMonthExpr,
    monthExpr,
    dayOfWeekExpr,
  ].map((expr, i) => {
    const [min, max] = FIELD_RANGES[fieldNames[i]];
    return parseField(expr, min, max);
  });

  return { minute, hour, dayOfMonth, month, dayOfWeek };
}

export default parseCron;

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronResult;

const FIELD_RANGES: Record<FieldName, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_ORDER: FieldName[] = [
  "minute", "hour", "dayOfMonth", "month", "dayOfWeek",
];

function assertInBounds(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(`${context}: value ${value} is outside valid range [${min}, ${max}]`);
  }
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Step: */n or a-b/n or a/n (a to max, stepping n)
  if (segment.includes("/")) {
    const slashIdx = segment.indexOf("/");
    const base = segment.slice(0, slashIdx);
    const stepStr = segment.slice(slashIdx + 1);

    if (stepStr === "" || stepStr.includes("/") || stepStr.includes("-")) {
      throw new SyntaxError(`Invalid step expression: "${segment}"`);
    }

    const step = Number(stepStr);
    if (!Number.isInteger(step) || step <= 0) {
      throw new RangeError(`Step must be a positive integer, got "${stepStr}"`);
    }

    let rangeMin: number;
    let rangeMax: number;

    if (base === "*") {
      rangeMin = min;
      rangeMax = max;
    } else if (base.includes("-")) {
      const dashIdx = base.indexOf("-");
      rangeMin = Number(base.slice(0, dashIdx));
      rangeMax = Number(base.slice(dashIdx + 1));
      if (!Number.isInteger(rangeMin) || !Number.isInteger(rangeMax)) {
        throw new SyntaxError(`Invalid range in step expression: "${segment}"`);
      }
    } else {
      rangeMin = Number(base);
      if (!Number.isInteger(rangeMin)) {
        throw new SyntaxError(`Invalid base in step expression: "${segment}"`);
      }
      rangeMax = max;
    }

    assertInBounds(rangeMin, min, max, `Step range start "${segment}"`);
    assertInBounds(rangeMax, min, max, `Step range end "${segment}"`);

    if (rangeMin > rangeMax) {
      throw new RangeError(
        `Step range start ${rangeMin} exceeds end ${rangeMax} in "${segment}"`
      );
    }

    const values: number[] = [];
    for (let v = rangeMin; v <= rangeMax; v += step) {
      values.push(v);
    }
    return values;
  }

  // Wildcard
  if (segment === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => min + i);
  }

  // Range: a-b
  if (segment.includes("-")) {
    const dashIdx = segment.indexOf("-");
    const start = Number(segment.slice(0, dashIdx));
    const end = Number(segment.slice(dashIdx + 1));

    if (!Number.isInteger(start) || !Number.isInteger(end)) {
      throw new SyntaxError(`Invalid range: "${segment}"`);
    }
    if (start > end) {
      throw new RangeError(
        `Range start ${start} exceeds end ${end} in "${segment}"`
      );
    }

    assertInBounds(start, min, max, `Range start "${segment}"`);
    assertInBounds(end, min, max, `Range end "${segment}"`);

    return Array.from({ length: end - start + 1 }, (_, i) => start + i);
  }

  // Single numeric value
  const num = Number(segment);
  if (!Number.isInteger(num)) {
    throw new SyntaxError(`Unrecognized field token: "${segment}"`);
  }
  assertInBounds(num, min, max, `Value "${segment}"`);
  return [num];
}

function parseField(field: string, min: number, max: number): number[] {
  if (field === "" || field.trim() !== field) {
    throw new SyntaxError(`Field must be non-empty and untrimmed, got "${field}"`);
  }

  // Comma-separated list — each item is parsed independently
  if (field.includes(",")) {
    const parts = field.split(",");
    const seen = new Set<number>();

    for (const part of parts) {
      if (part === "") {
        throw new SyntaxError(`Empty segment in comma list: "${field}"`);
      }
      for (const v of parseSegment(part, min, max)) {
        seen.add(v);
      }
    }

    return [...seen].sort((a, b) => a - b);
  }

  return parseSegment(field, min, max);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError(`Cron expression must be a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const rawFields = trimmed.split(/\s+/);

  if (rawFields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields (got ${rawFields.length}): "${expression}"`
    );
  }

  const result = {} as CronResult;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const name = FIELD_ORDER[i];
    const { min, max } = FIELD_RANGES[name];
    const raw = rawFields[i];

    try {
      result[name] = parseField(raw, min, max);
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      throw new Error(`Invalid cron field "${name}" (value: "${raw}"): ${message}`);
    }
  }

  return result;
}

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
  name: string;
}

const FIELD_CONFIGS: [keyof CronExpression, FieldConfig][] = [
  ["minute",     { min: 0,  max: 59, name: "minute"     }],
  ["hour",       { min: 0,  max: 23, name: "hour"       }],
  ["dayOfMonth", { min: 1,  max: 31, name: "dayOfMonth" }],
  ["month",      { min: 1,  max: 12, name: "month"      }],
  ["dayOfWeek",  { min: 0,  max: 7,  name: "dayOfWeek"  }],
];

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of valid range [${min}, ${max}] in field "${context}"`
    );
  }
}

function expandRange(start: number, end: number, step: number, config: FieldConfig): number[] {
  assertInRange(start, config.min, config.max, config.name);
  assertInRange(end, config.min, config.max, config.name);

  if (start > end) {
    throw new RangeError(
      `Range start ${start} exceeds range end ${end} in field "${config.name}"`
    );
  }
  if (step <= 0) {
    throw new RangeError(
      `Step value ${step} must be a positive integer in field "${config.name}"`
    );
  }

  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function parseSingleToken(token: string, config: FieldConfig): number[] {
  // Step expression: */N or start/N or start-end/N
  if (token.includes("/")) {
    const slashIndex = token.lastIndexOf("/");
    const left = token.slice(0, slashIndex);
    const stepStr = token.slice(slashIndex + 1);
    const step = Number(stepStr);

    if (!Number.isInteger(step) || step <= 0) {
      throw new RangeError(
        `Invalid step value "${stepStr}" in field "${config.name}"`
      );
    }

    if (left === "*") {
      return expandRange(config.min, config.max, step, config);
    }

    if (left.includes("-")) {
      const [startStr, endStr] = left.split("-");
      const start = Number(startStr);
      const end = Number(endStr);
      if (!Number.isInteger(start) || !Number.isInteger(end)) {
        throw new TypeError(
          `Non-integer range bounds "${left}" in field "${config.name}"`
        );
      }
      return expandRange(start, end, step, config);
    }

    // N/step — start at N, step to max
    const start = Number(left);
    if (!Number.isInteger(start)) {
      throw new TypeError(
        `Non-integer step base "${left}" in field "${config.name}"`
      );
    }
    return expandRange(start, config.max, step, config);
  }

  // Wildcard
  if (token === "*") {
    return expandRange(config.min, config.max, 1, config);
  }

  // Range: N-M
  if (token.includes("-")) {
    const parts = token.split("-");
    if (parts.length !== 2) {
      throw new SyntaxError(
        `Malformed range "${token}" in field "${config.name}"`
      );
    }
    const start = Number(parts[0]);
    const end = Number(parts[1]);
    if (!Number.isInteger(start) || !Number.isInteger(end)) {
      throw new TypeError(
        `Non-integer range bounds "${token}" in field "${config.name}"`
      );
    }
    return expandRange(start, end, 1, config);
  }

  // Single number
  const value = Number(token);
  if (!Number.isInteger(value)) {
    throw new TypeError(
      `Non-integer value "${token}" in field "${config.name}"`
    );
  }
  assertInRange(value, config.min, config.max, config.name);
  return [value];
}

function parseField(raw: string, config: FieldConfig): number[] {
  if (raw === "" || raw == null) {
    throw new SyntaxError(`Empty value for field "${config.name}"`);
  }

  // Comma-separated list — each element is parsed individually then merged
  const tokens = raw.split(",");
  if (tokens.some((t) => t.trim() === "")) {
    throw new SyntaxError(
      `Empty token in comma list for field "${config.name}"`
    );
  }

  const seen = new Set<number>();
  for (const token of tokens) {
    for (const v of parseSingleToken(token.trim(), config)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string" || expression.trim() === "") {
    throw new TypeError("Cron expression must be a non-empty string");
  }

  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new SyntaxError(
      `Expected exactly 5 fields, got ${parts.length}: "${expression}"`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const [key, config] = FIELD_CONFIGS[i];
    result[key] = parseField(parts[i], config);
  }

  return result;
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 7],
};

const range = (from: number, to: number): number[] =>
  Array.from({ length: to - from + 1 }, (_, i) => from + i);

const parseField = (field: string, min: number, max: number): number[] => {
  const full = range(min, max);

  if (field === "*") return full;

  if (field.startsWith("*/")) {
    const step = parseInt(field.slice(2), 10);
    if (isNaN(step) || step < 1) throw new Error(`Invalid step value: ${field}`);
    return full.filter(v => (v - min) % step === 0);
  }

  if (field.includes(",")) {
    const values = field.split(",").flatMap(part => parseField(part.trim(), min, max));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  if (field.includes("-")) {
    const [startStr, endStr] = field.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: ${field}`);
    if (start > end) throw new Error(`Range start exceeds end: ${field}`);
    if (start < min || end > max) throw new Error(`Range out of bounds [${min}-${max}]: ${field}`);
    return range(start, end);
  }

  const num = parseInt(field, 10);
  if (isNaN(num)) throw new Error(`Invalid cron value: ${field}`);
  if (num < min || num > max) throw new Error(`Value ${num} out of bounds [${min}-${max}]`);
  return [num];
};

const parseCron = (expression: string): CronFields => {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) throw new Error(`Expected 5 fields, got ${parts.length}`);

  const [minuteStr, hourStr, domStr, monthStr, dowStr] = parts;
  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];

  const [minute, hour, dayOfMonth, month, dayOfWeek] = [
    minuteStr, hourStr, domStr, monthStr, dowStr,
  ].map((field, i) => {
    const name = fieldNames[i];
    const [min, max] = FIELD_RANGES[name];
    try {
      return parseField(field, min, max);
    } catch (err) {
      throw new Error(`Error in field "${name}" ("${field}"): ${(err as Error).message}`);
    }
  });

  // Normalize dayOfWeek: treat 7 as 0 (both = Sunday)
  const normalizedDow = [...new Set(dayOfWeek.map(v => (v === 7 ? 0 : v)))].sort((a, b) => a - b);

  return { minute, hour, dayOfMonth, month, dayOfWeek: normalizedDow };
};

export default parseCron;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface WaitEntry {
  tokens: number;
  resolve: () => void;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: WaitEntry[];
  private scheduledRefill: ReturnType<typeof setTimeout> | null;

  constructor(options: RateLimiterOptions) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError(`maxTokens must be a finite positive number, got ${options.maxTokens}`);
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate <= 0) {
      throw new RangeError(`refillRate must be a finite positive number, got ${options.refillRate}`);
    }
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0) {
      throw new RangeError(`refillIntervalMs must be a finite positive number, got ${options.refillIntervalMs}`);
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
    this.scheduledRefill = null;
  }

  private lazyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    if (elapsed > 0) {
      const tokensToAdd = (elapsed / this.refillIntervalMs) * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime = now;
    }
  }

  private validateTokenCount(tokens: number, label: string): void {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError(`${label} must be a finite non-negative number, got ${tokens}`);
    }
  }

  tryConsume(tokens: number = 1): boolean {
    this.validateTokenCount(tokens, "tokens");

    // A request for more than the bucket can ever hold will never succeed
    if (tokens > this.maxTokens) return false;

    this.lazyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.lazyRefill();
    return this.currentTokens;
  }

  reset(): void {
    if (this.scheduledRefill !== null) {
      clearTimeout(this.scheduledRefill);
      this.scheduledRefill = null;
    }
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.drainQueue();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    this.validateTokenCount(tokens, "tokens");

    if (tokens > this.maxTokens) {
      throw new RangeError(
        `Requested tokens (${tokens}) exceed maxTokens (${this.maxTokens}); ` +
          `this promise would never resolve`
      );
    }

    if (tokens === 0 || this.tryConsume(tokens)) return;

    return new Promise<void>((resolve) => {
      this.waitQueue.push({ tokens, resolve });
      this.scheduleNextDrain();
    });
  }

  private scheduleNextDrain(): void {
    // Only one pending timeout at a time; avoids thundering-herd from rapid enqueues
    if (this.scheduledRefill !== null || this.waitQueue.length === 0) return;

    this.lazyRefill();
    const next = this.waitQueue[0];

    if (this.currentTokens >= next.tokens) {
      this.drainQueue();
      return;
    }

    const tokensStillNeeded = next.tokens - this.currentTokens;
    // How long until lazy refill accumulates enough tokens?
    const msNeeded = (tokensStillNeeded / this.refillRate) * this.refillIntervalMs;
    // Add 1ms buffer to avoid sub-ms floating-point shortfall on wakeup
    const delay = Math.ceil(msNeeded) + 1;

    this.scheduledRefill = setTimeout(() => {
      this.scheduledRefill = null;
      this.drainQueue();
    }, delay);
  }

  private drainQueue(): void {
    while (this.waitQueue.length > 0) {
      this.lazyRefill();
      const entry = this.waitQueue[0];

      if (this.currentTokens >= entry.tokens) {
        this.currentTokens -= entry.tokens;
        this.waitQueue.shift();
        // Resolve after shifting so re-entrant calls from the callback
        // see an up-to-date queue length
        entry.resolve();
      } else {
        // Insufficient tokens for the head of queue; schedule the next wake
        this.scheduleNextDrain();
        break;
      }
    }
  }
}

export default RateLimiter;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface Waiter {
  tokens: number;
  resolve: () => void;
}

export default class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waiters: Waiter[] = [];
  private scheduledDrain: ReturnType<typeof setTimeout> | null = null;

  constructor({ maxTokens, refillRate, refillIntervalMs }: RateLimiterOptions) {
    if (!Number.isFinite(maxTokens) || maxTokens <= 0)
      throw new RangeError("maxTokens must be a finite positive number");
    if (!Number.isFinite(refillRate) || refillRate < 0)
      throw new RangeError("refillRate must be a finite non-negative number");
    if (!Number.isFinite(refillIntervalMs) || refillIntervalMs <= 0)
      throw new RangeError("refillIntervalMs must be a finite positive number");

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.currentTokens = maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed > 0) {
      if (this.refillRate > 0) {
        const tokensToAdd = (elapsed / this.refillIntervalMs) * this.refillRate;
        this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      }
      this.lastRefillTime = now;
    }
  }

  private validateTokenArg(tokens: number, label = "tokens"): void {
    if (!Number.isFinite(tokens) || tokens < 0)
      throw new RangeError(`${label} must be a finite non-negative number`);
  }

  tryConsume(tokens: number = 1): boolean {
    this.validateTokenArg(tokens);
    if (tokens > this.maxTokens) return false;
    if (tokens === 0) return true;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.drainWaiters();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    this.validateTokenArg(tokens);

    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds bucket capacity of ${this.maxTokens}`
        )
      );
    }

    if (tokens === 0) return Promise.resolve();

    // Attempt immediate consumption only when no one is ahead in line.
    if (this.waiters.length === 0) {
      this.refill();
      if (this.currentTokens >= tokens) {
        this.currentTokens -= tokens;
        return Promise.resolve();
      }
    }

    return new Promise<void>((resolve) => {
      this.waiters.push({ tokens, resolve });
      this.scheduleDrain();
    });
  }

  private drainWaiters(): void {
    while (this.waiters.length > 0) {
      this.refill();

      const waiter = this.waiters[0]!;

      if (this.currentTokens >= waiter.tokens) {
        this.currentTokens -= waiter.tokens;
        this.waiters.shift();
        waiter.resolve();
      } else {
        // Head waiter cannot yet be served — schedule a future check.
        this.scheduleDrain();
        return;
      }
    }
  }

  private scheduleDrain(): void {
    // Only one pending timer at a time.
    if (this.scheduledDrain !== null || this.waiters.length === 0) return;

    this.refill();

    const waiter = this.waiters[0]!;
    const deficit = waiter.tokens - this.currentTokens;

    if (deficit <= 0) {
      // Already satisfiable — yield to let the call stack unwind first.
      this.scheduledDrain = setTimeout(() => {
        this.scheduledDrain = null;
        this.drainWaiters();
      }, 0);
      return;
    }

    if (this.refillRate === 0) {
      // No automatic refill; waiters unblock only via reset().
      return;
    }

    const tokensPerMs = this.refillRate / this.refillIntervalMs;
    // Add 1 ms buffer to avoid racing just below the threshold.
    const delayMs = Math.ceil(deficit / tokensPerMs) + 1;

    this.scheduledDrain = setTimeout(() => {
      this.scheduledDrain = null;
      this.drainWaiters();
    }, delayMs);
  }
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: Readonly<Record<CronField, FieldConfig>> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
} as const;

const FIELD_ORDER: readonly CronField[] = [
  "minute", "hour", "dayOfMonth", "month", "dayOfWeek",
] as const;

function parseNonNegativeInt(raw: string, context: string): number {
  if (!/^\d+$/.test(raw)) {
    throw new Error(`Invalid integer '${raw}' in ${context}`);
  }
  const n = parseInt(raw, 10);
  if (!Number.isSafeInteger(n)) {
    throw new Error(`Integer '${raw}' exceeds safe range in ${context}`);
  }
  return n;
}

function assertInRange(
  value: number,
  config: FieldConfig,
  fieldName: string,
): void {
  if (value < config.min || value > config.max) {
    throw new RangeError(
      `Value ${value} out of valid range [${config.min}, ${config.max}] for field '${fieldName}'`,
    );
  }
}

function expandRange(
  start: number,
  end: number,
  step: number,
  fieldName: string,
): number[] {
  if (step < 1) {
    throw new RangeError(
      `Step must be >= 1, got ${step} in field '${fieldName}'`,
    );
  }
  if (start > end) {
    throw new RangeError(
      `Range start ${start} exceeds end ${end} in field '${fieldName}'`,
    );
  }
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function parseToken(
  token: string,
  config: FieldConfig,
  fieldName: string,
): number[] {
  if (token.length === 0) {
    throw new Error(`Empty token in field '${fieldName}'`);
  }

  // Comma-separated list: "1,3,5" — recurse on each element, deduplicate
  if (token.includes(",")) {
    const parts = token.split(",");
    if (parts.some((p) => p === "")) {
      throw new Error(
        `Empty element in comma-separated list for field '${fieldName}'`,
      );
    }
    const seen = new Set<number>();
    const values: number[] = [];
    for (const part of parts) {
      for (const v of parseToken(part, config, fieldName)) {
        if (!seen.has(v)) {
          seen.add(v);
          values.push(v);
        }
      }
    }
    return values.sort((a, b) => a - b);
  }

  // Step expression: "*/N" or "start-end/N" or "start/N"
  if (token.includes("/")) {
    const slashIdx = token.indexOf("/");
    const lastSlash = token.lastIndexOf("/");
    if (slashIdx !== lastSlash) {
      throw new Error(
        `Multiple '/' in step expression '${token}' for field '${fieldName}'`,
      );
    }
    const rangePart = token.slice(0, slashIdx);
    const stepPart = token.slice(slashIdx + 1);
    if (rangePart === "" || stepPart === "") {
      throw new Error(
        `Malformed step expression '${token}' for field '${fieldName}'`,
      );
    }
    const step = parseNonNegativeInt(stepPart, `step in field '${fieldName}'`);
    if (step < 1) {
      throw new RangeError(
        `Step must be >= 1, got ${step} in field '${fieldName}'`,
      );
    }
    if (rangePart === "*") {
      return expandRange(config.min, config.max, step, fieldName);
    }
    if (rangePart.includes("-")) {
      const dashIdx = rangePart.indexOf("-");
      const lastDash = rangePart.lastIndexOf("-");
      if (dashIdx !== lastDash) {
        throw new Error(
          `Malformed range '${rangePart}' in field '${fieldName}'`,
        );
      }
      const start = parseNonNegativeInt(
        rangePart.slice(0, dashIdx),
        `range start in field '${fieldName}'`,
      );
      const end = parseNonNegativeInt(
        rangePart.slice(dashIdx + 1),
        `range end in field '${fieldName}'`,
      );
      assertInRange(start, config, fieldName);
      assertInRange(end, config, fieldName);
      return expandRange(start, end, step, fieldName);
    }
    // "start/step" — step from start up to field max
    const start = parseNonNegativeInt(
      rangePart,
      `step base in field '${fieldName}'`,
    );
    assertInRange(start, config, fieldName);
    return expandRange(start, config.max, step, fieldName);
  }

  // Range: "start-end"
  if (token.includes("-")) {
    const dashIdx = token.indexOf("-");
    const lastDash = token.lastIndexOf("-");
    if (dashIdx !== lastDash) {
      throw new Error(`Malformed range '${token}' in field '${fieldName}'`);
    }
    const start = parseNonNegativeInt(
      token.slice(0, dashIdx),
      `range start in field '${fieldName}'`,
    );
    const end = parseNonNegativeInt(
      token.slice(dashIdx + 1),
      `range end in field '${fieldName}'`,
    );
    assertInRange(start, config, fieldName);
    assertInRange(end, config, fieldName);
    if (start > end) {
      throw new RangeError(
        `Range start ${start} exceeds end ${end} in field '${fieldName}'`,
      );
    }
    return expandRange(start, end, 1, fieldName);
  }

  // Wildcard: "*"
  if (token === "*") {
    return expandRange(config.min, config.max, 1, fieldName);
  }

  // Single numeric value
  const value = parseNonNegativeInt(token, `field '${fieldName}'`);
  assertInRange(value, config, fieldName);
  return [value];
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron expects a string, received ${typeof expression}`,
    );
  }

  const trimmed = expression.trim();
  if (trimmed.length === 0) {
    throw new Error("Cron expression must not be empty");
  }

  // Guard against pathologically long inputs before any further parsing
  if (trimmed.length > 256) {
    throw new Error(
      `Cron expression exceeds maximum length of 256 characters`,
    );
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Expected exactly 5 fields, got ${fields.length} in expression '${trimmed}'`,
    );
  }

  const result = {} as CronResult;
  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    result[fieldName] = parseToken(fields[i], FIELD_CONFIGS[fieldName], fieldName);
  }
  return result;
}

type CronObject = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldConfig = {
  min: number;
  max: number;
};

const FIELD_CONFIGS: FieldConfig[] = [
  { min: 0, max: 59 },  // minute
  { min: 0, max: 23 },  // hour
  { min: 1, max: 31 },  // dayOfMonth
  { min: 1, max: 12 },  // month
  { min: 0, max: 7 },   // dayOfWeek (0 and 7 both represent Sunday)
];

const FIELD_NAMES = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"] as const;

function rangeArray(start: number, end: number, step = 1): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function parseSegment(segment: string, config: FieldConfig): number[] {
  const { min, max } = config;

  // Wildcard: "*"
  if (segment === "*") {
    return rangeArray(min, max);
  }

  // Step with wildcard: "*/n"
  const stepWildcardMatch = segment.match(/^\*\/(\d+)$/);
  if (stepWildcardMatch) {
    const step = parseInt(stepWildcardMatch[1], 10);
    if (step < 1) throw new Error(`Invalid step value: ${step}`);
    return rangeArray(min, max, step);
  }

  // Step with range: "start-end/n"
  const stepRangeMatch = segment.match(/^(\d+)-(\d+)\/(\d+)$/);
  if (stepRangeMatch) {
    const start = parseInt(stepRangeMatch[1], 10);
    const end = parseInt(stepRangeMatch[2], 10);
    const step = parseInt(stepRangeMatch[3], 10);
    if (start < min || end > max || start > end) {
      throw new Error(`Range ${start}-${end} is out of bounds [${min}, ${max}]`);
    }
    if (step < 1) throw new Error(`Invalid step value: ${step}`);
    return rangeArray(start, end, step);
  }

  // Range: "start-end"
  const rangeMatch = segment.match(/^(\d+)-(\d+)$/);
  if (rangeMatch) {
    const start = parseInt(rangeMatch[1], 10);
    const end = parseInt(rangeMatch[2], 10);
    if (start < min || end > max || start > end) {
      throw new Error(`Range ${start}-${end} is out of bounds [${min}, ${max}]`);
    }
    return rangeArray(start, end);
  }

  // Single number
  const numMatch = segment.match(/^(\d+)$/);
  if (numMatch) {
    const value = parseInt(numMatch[1], 10);
    if (value < min || value > max) {
      throw new Error(`Value ${value} is out of bounds [${min}, ${max}]`);
    }
    return [value];
  }

  throw new Error(`Invalid cron segment: "${segment}"`);
}

function parseField(field: string, config: FieldConfig): number[] {
  const segments = field.split(",");
  const valuesSet = new Set<number>();

  for (const segment of segments) {
    const trimmed = segment.trim();
    if (!trimmed) throw new Error(`Empty segment in field: "${field}"`);
    const values = parseSegment(trimmed, config);
    for (const v of values) valuesSet.add(v);
  }

  // Normalize dayOfWeek: treat 7 as 0 (Sunday)
  if (config.min === 0 && config.max === 7) {
    if (valuesSet.has(7)) {
      valuesSet.delete(7);
      valuesSet.add(0);
    }
  }

  return Array.from(valuesSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronObject {
  if (typeof expression !== "string") {
    throw new Error("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Expected 5 fields in cron expression, got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronObject;

  for (let i = 0; i < 5; i++) {
    const name = FIELD_NAMES[i];
    const config = FIELD_CONFIGS[i];
    result[name] = parseField(fields[i], config);
  }

  return result;
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError("maxTokens must be a positive finite number");
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate <= 0) {
      throw new RangeError("refillRate must be a positive finite number");
    }
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0) {
      throw new RangeError("refillIntervalMs must be a positive finite number");
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private lazyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed < this.refillIntervalMs) return;

    const intervalsElapsed = Math.floor(elapsed / this.refillIntervalMs);
    const tokensToAdd = intervalsElapsed * this.refillRate;

    this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
    // Advance lastRefillTime by whole intervals only — preserve fractional interval progress
    this.lastRefillTime += intervalsElapsed * this.refillIntervalMs;
  }

  private validateTokenArg(tokens: number, label = "tokens"): void {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError(`${label} must be a non-negative finite number`);
    }
  }

  tryConsume(tokens: number = 1): boolean {
    this.validateTokenArg(tokens);
    this.lazyRefill();

    if (tokens === 0) return true;

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.lazyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    this.validateTokenArg(tokens);

    if (tokens === 0) return Promise.resolve();

    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds bucket capacity of ${this.maxTokens}`
        )
      );
    }

    return new Promise<void>((resolve) => {
      const attempt = (): void => {
        this.lazyRefill();

        if (this.currentTokens >= tokens) {
          this.currentTokens -= tokens;
          resolve();
          return;
        }

        // Calculate minimum wait: time until enough refill intervals have elapsed.
        // After lazyRefill(), lastRefillTime is within one interval of now.
        const deficit = tokens - this.currentTokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const timeInCurrentInterval = Date.now() - this.lastRefillTime;
        const timeUntilFirstRefill = this.refillIntervalMs - timeInCurrentInterval;
        // Total wait covers first partial interval + remaining full intervals.
        // Add 1ms guard against floating-point scheduling jitter.
        const waitMs = timeUntilFirstRefill + (intervalsNeeded - 1) * this.refillIntervalMs + 1;

        setTimeout(attempt, Math.max(0, waitMs));
      };

      attempt();
    });
  }
}

export default RateLimiter;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface Waiter {
  tokens: number;
  resolve: () => void;
}

export default class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;

  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: Waiter[];
  private scheduledDrain: ReturnType<typeof setTimeout> | null;

  constructor(options: RateLimiterOptions) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError(`maxTokens must be a finite positive number, got ${options.maxTokens}`);
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate <= 0) {
      throw new RangeError(`refillRate must be a finite positive number, got ${options.refillRate}`);
    }
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0) {
      throw new RangeError(`refillIntervalMs must be a finite positive number, got ${options.refillIntervalMs}`);
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;

    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
    this.scheduledDrain = null;
  }

  /**
   * Lazily refills tokens based on elapsed wall-clock time since the last
   * refill checkpoint. Advances the checkpoint by whole intervals only, so
   * fractional elapsed intervals do not drift away.
   */
  private lazyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed < this.refillIntervalMs) return;

    const completedIntervals = Math.floor(elapsed / this.refillIntervalMs);
    const tokensToAdd = completedIntervals * this.refillRate;

    this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
    // Advance checkpoint by exactly the consumed intervals to avoid drift.
    this.lastRefillTime += completedIntervals * this.refillIntervalMs;
  }

  /** Validates a token count argument. */
  private assertTokenArg(tokens: number, label: string): void {
    if (!Number.isFinite(tokens) || tokens <= 0) {
      throw new RangeError(`${label} must be a finite positive number, got ${tokens}`);
    }
    if (tokens > this.maxTokens) {
      throw new RangeError(
        `${label} (${tokens}) exceeds maxTokens (${this.maxTokens}) — request can never be satisfied`,
      );
    }
  }

  /**
   * Attempts to consume `tokens` (default 1).
   * Returns true if the bucket had enough tokens and they were consumed.
   * Returns false otherwise — no tokens are deducted on failure.
   */
  tryConsume(tokens: number = 1): boolean {
    this.assertTokenArg(tokens, "tokens");
    this.lazyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      this.scheduleDrainIfNeeded(); // A consumption may now allow a queued waiter to proceed via next refill.
      return true;
    }
    return false;
  }

  /** Returns current available tokens (triggers lazy refill first). */
  getTokens(): number {
    this.lazyRefill();
    return this.currentTokens;
  }

  /** Resets bucket to full capacity and attempts to satisfy queued waiters. */
  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.cancelScheduledDrain();
    this.drainQueue();
  }

  /**
   * Returns a Promise that resolves once `tokens` have been consumed.
   * Requests are served in FIFO order to prevent starvation of large requests.
   * Rejects immediately if `tokens` > `maxTokens` (request can never be satisfied).
   */
  waitForTokens(tokens: number = 1): Promise<void> {
    this.assertTokenArg(tokens, "tokens");

    return new Promise<void>((resolve) => {
      this.lazyRefill();

      // Fast path: no queue ahead of us and bucket has enough tokens.
      if (this.waitQueue.length === 0 && this.currentTokens >= tokens) {
        this.currentTokens -= tokens;
        resolve();
        return;
      }

      // Enqueue and schedule a drain wakeup if we're the first waiter.
      this.waitQueue.push({ tokens, resolve });
      if (this.waitQueue.length === 1) {
        this.scheduleDrainIfNeeded();
      }
    });
  }

  // ---------------------------------------------------------------------------
  // Private scheduling helpers
  // ---------------------------------------------------------------------------

  /**
   * Processes the head of the wait queue as long as the bucket has enough
   * tokens. After exhausting what it can serve, schedules the next wakeup.
   */
  private drainQueue(): void {
    while (this.waitQueue.length > 0) {
      this.lazyRefill();
      const head = this.waitQueue[0];

      if (this.currentTokens >= head.tokens) {
        this.currentTokens -= head.tokens;
        this.waitQueue.shift();
        head.resolve();
      } else {
        // Can't serve the head yet — schedule the next wakeup and stop.
        this.scheduleDrainIfNeeded();
        return;
      }
    }
    // Queue is empty — no wakeup needed.
    this.cancelScheduledDrain();
  }

  /**
   * Schedules a setTimeout to re-run drainQueue at the earliest moment the
   * head waiter could possibly be satisfied.
   * No-ops if a drain is already scheduled or the queue is empty.
   */
  private scheduleDrainIfNeeded(): void {
    if (this.scheduledDrain !== null || this.waitQueue.length === 0) return;

    const head = this.waitQueue[0];
    const tokensStillNeeded = Math.max(0, head.tokens - this.currentTokens);

    if (tokensStillNeeded === 0) {
      // Tokens are already available — drain on the next microtask.
      this.scheduledDrain = setTimeout(() => {
        this.scheduledDrain = null;
        this.drainQueue();
      }, 0);
      return;
    }

    // How many full intervals are needed to accumulate enough tokens?
    const intervalsNeeded = Math.ceil(tokensStillNeeded / this.refillRate);

    // How long until the very next interval fires?
    const elapsedInCurrentInterval = Date.now() - this.lastRefillTime;
    const timeUntilFirstRefill = Math.max(
      0,
      this.refillIntervalMs - elapsedInCurrentInterval,
    );

    // Total wait: first interval fires at timeUntilFirstRefill, then one more
    // interval per additional batch needed.
    const delay = timeUntilFirstRefill + (intervalsNeeded - 1) * this.refillIntervalMs;

    this.scheduledDrain = setTimeout(() => {
      this.scheduledDrain = null;
      this.drainQueue();
    }, delay);
  }

  private cancelScheduledDrain(): void {
    if (this.scheduledDrain !== null) {
      clearTimeout(this.scheduledDrain);
      this.scheduledDrain = null;
    }
  }
}

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
} as const;

function parseIntStrict(s: string, context: string): number {
  if (!/^\d+$/.test(s)) {
    throw new Error(`Expected an integer in "${context}", got: "${s}"`);
  }
  const n = parseInt(s, 10);
  if (!Number.isFinite(n)) {
    throw new Error(`Non-finite integer in "${context}": "${s}"`);
  }
  return n;
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} is outside valid range [${min}, ${max}] in "${context}"`
    );
  }
}

function expandStep(rangeMin: number, rangeMax: number, step: number): number[] {
  const result: number[] = [];
  for (let i = rangeMin; i <= rangeMax; i += step) {
    result.push(i);
  }
  return result;
}

function parseSegment(segment: string, min: number, max: number): number[] {
  if (!segment) {
    throw new Error(`Empty segment encountered`);
  }

  const slashParts = segment.split("/");

  if (slashParts.length > 2) {
    throw new Error(`Multiple "/" in segment: "${segment}"`);
  }

  if (slashParts.length === 2) {
    const [rangePart, stepStr] = slashParts;

    const step = parseIntStrict(stepStr, segment);
    if (step < 1) {
      throw new RangeError(`Step must be >= 1 in "${segment}"`);
    }

    let rangeMin = min;
    let rangeMax = max;

    if (rangePart === "*") {
      // use defaults
    } else {
      const dashParts = rangePart.split("-");
      if (dashParts.length === 2) {
        rangeMin = parseIntStrict(dashParts[0], segment);
        rangeMax = parseIntStrict(dashParts[1], segment);
        assertInRange(rangeMin, min, max, segment);
        assertInRange(rangeMax, min, max, segment);
        if (rangeMin > rangeMax) {
          throw new RangeError(`Range start ${rangeMin} > end ${rangeMax} in "${segment}"`);
        }
      } else if (dashParts.length === 1) {
        rangeMin = parseIntStrict(rangePart, segment);
        assertInRange(rangeMin, min, max, segment);
        rangeMax = max;
      } else {
        throw new Error(`Invalid range in step expression: "${segment}"`);
      }
    }

    return expandStep(rangeMin, rangeMax, step);
  }

  if (segment === "*") {
    return expandStep(min, max, 1);
  }

  const dashParts = segment.split("-");

  if (dashParts.length === 2) {
    const lo = parseIntStrict(dashParts[0], segment);
    const hi = parseIntStrict(dashParts[1], segment);
    assertInRange(lo, min, max, segment);
    assertInRange(hi, min, max, segment);
    if (lo > hi) {
      throw new RangeError(`Range start ${lo} > end ${hi} in "${segment}"`);
    }
    return expandStep(lo, hi, 1);
  }

  if (dashParts.length > 2) {
    throw new Error(`Multiple "-" without step in segment: "${segment}"`);
  }

  const n = parseIntStrict(segment, segment);
  assertInRange(n, min, max, segment);
  return [n];
}

function parseField(
  raw: string,
  min: number,
  max: number,
  acceptedMax: number = max
): number[] {
  if (!raw || raw.trim() === "") {
    throw new Error(`Cron field is empty`);
  }

  const commaSegments = raw.split(",");
  const collected = new Set<number>();

  for (const segment of commaSegments) {
    const trimmed = segment.trim();
    if (!trimmed) {
      throw new Error(`Empty segment in cron field: "${raw}"`);
    }

    const values = parseSegment(trimmed, min, acceptedMax);

    for (const v of values) {
      // Normalize dayOfWeek 7 (Sunday alias) to 0
      collected.add(v === 7 && max === 6 ? 0 : v);
    }
  }

  return Array.from(collected).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(`Expected a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (!trimmed) {
    throw new Error(`Cron expression cannot be empty`);
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 whitespace-separated fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteRaw, hourRaw, domRaw, monthRaw, dowRaw] = fields;

  return {
    minute:     parseField(minuteRaw, FIELD_RANGES.minute.min,     FIELD_RANGES.minute.max),
    hour:       parseField(hourRaw,   FIELD_RANGES.hour.min,       FIELD_RANGES.hour.max),
    dayOfMonth: parseField(domRaw,    FIELD_RANGES.dayOfMonth.min, FIELD_RANGES.dayOfMonth.max),
    month:      parseField(monthRaw,  FIELD_RANGES.month.min,      FIELD_RANGES.month.max),
    // acceptedMax=7 so 7 is parsed but then normalised to 0 inside parseField
    dayOfWeek:  parseField(dowRaw,    FIELD_RANGES.dayOfWeek.min,  FIELD_RANGES.dayOfWeek.max, 7),
  };
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronFields;

interface FieldBounds {
  min: number;
  max: number;
}

const FIELD_BOUNDS: Record<FieldName, FieldBounds> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

const FIELD_ORDER: FieldName[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function assertInBounds(value: number, bounds: FieldBounds, context: string): void {
  if (!Number.isInteger(value) || value < bounds.min || value > bounds.max) {
    throw new RangeError(
      `Value ${value} in "${context}" is out of valid range [${bounds.min}-${bounds.max}]`
    );
  }
}

function expandRange(start: number, end: number, step: number): number[] {
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(segment: string, bounds: FieldBounds): number[] {
  const { min, max } = bounds;

  // Step expression: "*/n" or "a-b/n" or "a/n"
  if (segment.includes("/")) {
    const slashIndex = segment.lastIndexOf("/");
    const rangePart = segment.slice(0, slashIndex);
    const stepStr  = segment.slice(slashIndex + 1);

    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0 || String(step) !== stepStr) {
      throw new SyntaxError(`Invalid step value in "${segment}"`);
    }

    if (rangePart === "*") {
      return expandRange(min, max, step);
    }

    if (rangePart.includes("-")) {
      const [startStr, endStr] = rangePart.split("-");
      const start = parseInt(startStr, 10);
      const end   = parseInt(endStr,   10);
      if (isNaN(start) || isNaN(end) || start > end) {
        throw new SyntaxError(`Invalid range "${rangePart}" in "${segment}"`);
      }
      assertInBounds(start, bounds, segment);
      assertInBounds(end,   bounds, segment);
      return expandRange(start, end, step);
    }

    const startVal = parseInt(rangePart, 10);
    if (isNaN(startVal)) {
      throw new SyntaxError(`Invalid step expression "${segment}"`);
    }
    assertInBounds(startVal, bounds, segment);
    return expandRange(startVal, max, step);
  }

  // Wildcard
  if (segment === "*") {
    return expandRange(min, max, 1);
  }

  // Range: "a-b"
  if (segment.includes("-")) {
    const dashIndex = segment.indexOf("-");
    const startStr  = segment.slice(0, dashIndex);
    const endStr    = segment.slice(dashIndex + 1);
    const start = parseInt(startStr, 10);
    const end   = parseInt(endStr,   10);

    if (isNaN(start) || String(start) !== startStr) {
      throw new SyntaxError(`Invalid range start in "${segment}"`);
    }
    if (isNaN(end)   || String(end)   !== endStr) {
      throw new SyntaxError(`Invalid range end in "${segment}"`);
    }
    if (start > end) {
      throw new RangeError(`Range start must be ≤ end in "${segment}"`);
    }
    assertInBounds(start, bounds, segment);
    assertInBounds(end,   bounds, segment);
    return expandRange(start, end, 1);
  }

  // Single integer
  const num = parseInt(segment, 10);
  if (isNaN(num) || String(num) !== segment) {
    throw new SyntaxError(`Invalid cron token "${segment}"`);
  }
  assertInBounds(num, bounds, segment);
  return [num];
}

function parseField(expr: string, bounds: FieldBounds): number[] {
  if (!expr || expr.trim() === "") {
    throw new SyntaxError("Empty field in cron expression");
  }

  const segments = expr.split(",");
  if (segments.some((s) => s.trim() === "")) {
    throw new SyntaxError(`Trailing or double comma in field "${expr}"`);
  }

  const valueSet = new Set<number>();
  for (const segment of segments) {
    for (const v of parseSegment(segment.trim(), bounds)) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const parts = trimmed.split(/\s+/);
  if (parts.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${parts.length}: "${expression}"`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const field  = FIELD_ORDER[i];
    const bounds = FIELD_BOUNDS[field];
    try {
      result[field] = parseField(parts[i], bounds);
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      throw new (err instanceof RangeError ? RangeError : SyntaxError)(
        `Invalid cron field "${field}" (position ${i + 1}, value "${parts[i]}"): ${msg}`
      );
    }
  }

  return result;
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      const tokensToAdd = intervals * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens to consume must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens to consume must be > 0"));
    if (tokens > this.maxTokens) return Promise.reject(new RangeError("tokens exceeds maxTokens capacity"));

    return new Promise((resolve) => {
      const attempt = (): void => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();
        const deficit = tokens - this.currentTokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const delay = Math.max(1, intervalsNeeded * this.refillIntervalMs);

        setTimeout(attempt, delay);
      };

      attempt();
    });
  }
}

export default RateLimiter;

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronExpression;

interface FieldRange {
  readonly min: number;
  readonly max: number;
}

const FIELD_RANGES: Readonly<Record<FieldName, FieldRange>> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
} as const;

const FIELD_ORDER: readonly FieldName[] = [
  "minute", "hour", "dayOfMonth", "month", "dayOfWeek",
] as const;

function buildRange(start: number, end: number, step: number): number[] {
  if (step <= 0) throw new RangeError(`Step must be a positive integer, got ${step}`);
  if (start > end) throw new RangeError(`Range start ${start} must be <= end ${end}`);
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function assertInBounds(value: number, range: FieldRange, context: string): void {
  if (value < range.min || value > range.max) {
    throw new RangeError(
      `Value ${value} in "${context}" is out of bounds [${range.min}–${range.max}]`
    );
  }
}

function parseSegment(segment: string, range: FieldRange): number[] {
  if (segment.trim() === "") {
    throw new SyntaxError("Empty segment in cron field");
  }

  // Wildcard: * or */step
  if (segment === "*") {
    return buildRange(range.min, range.max, 1);
  }

  if (segment.startsWith("*/")) {
    const raw = segment.slice(2);
    const step = Number(raw);
    if (!Number.isInteger(step) || step <= 0) {
      throw new RangeError(`Invalid step value "${raw}" in "${segment}"`);
    }
    return buildRange(range.min, range.max, step);
  }

  // Range with optional step: n-m or n-m/step
  if (segment.includes("-")) {
    const slashIndex = segment.indexOf("/");
    const rangePart = slashIndex === -1 ? segment : segment.slice(0, slashIndex);
    const stepPart  = slashIndex === -1 ? "1"     : segment.slice(slashIndex + 1);

    const step = Number(stepPart);
    if (!Number.isInteger(step) || step <= 0) {
      throw new RangeError(`Invalid step value "${stepPart}" in "${segment}"`);
    }

    const dashIndex = rangePart.indexOf("-");
    const rawStart = rangePart.slice(0, dashIndex);
    const rawEnd   = rangePart.slice(dashIndex + 1);

    if (rawStart === "" || rawEnd === "") {
      throw new SyntaxError(`Malformed range "${segment}"`);
    }

    const start = Number(rawStart);
    const end   = Number(rawEnd);

    if (!Number.isInteger(start) || !Number.isInteger(end)) {
      throw new SyntaxError(`Non-integer range bounds in "${segment}"`);
    }

    assertInBounds(start, range, segment);
    assertInBounds(end,   range, segment);

    return buildRange(start, end, step);
  }

  // Single numeric value
  const value = Number(segment);
  if (!Number.isInteger(value)) {
    throw new SyntaxError(`Invalid cron field token "${segment}"`);
  }
  assertInBounds(value, range, segment);
  return [value];
}

function parseField(field: string, range: FieldRange): number[] {
  if (field.trim() === "") {
    throw new SyntaxError("Cron field must not be empty");
  }

  const segments = field.split(",");
  const seen = new Set<number>();

  for (const segment of segments) {
    for (const value of parseSegment(segment.trim(), range)) {
      seen.add(value);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const name = FIELD_ORDER[i];
    try {
      result[name] = parseField(fields[i], FIELD_RANGES[name]);
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      throw new (err instanceof TypeError ? TypeError : RangeError instanceof err.constructor ? RangeError : SyntaxError)(
        `Invalid "${name}" field (position ${i + 1}) "${fields[i]}": ${message}`
      );
    }
  }

  return result;
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: Record<keyof CronFields, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const range = (start: number, end: number, step = 1): number[] => {
  if (step <= 0) throw new Error(`Step must be positive, got ${step}`);
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
};

const clamp = (value: number, min: number, max: number, context: string): number => {
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of range [${min}, ${max}] for field "${context}"`);
  }
  return value;
};

const parseSegment = (segment: string, config: FieldConfig, fieldName: string): number[] => {
  const { min, max } = config;

  // Wildcard with optional step: * or */n
  if (segment.startsWith("*")) {
    if (segment === "*") return range(min, max);
    const slashIndex = segment.indexOf("/");
    if (slashIndex !== 1) throw new Error(`Invalid segment "${segment}" for field "${fieldName}"`);
    const step = parseInt(segment.slice(2), 10);
    if (isNaN(step)) throw new Error(`Invalid step in "${segment}" for field "${fieldName}"`);
    clamp(step, 1, max - min, fieldName);
    return range(min, max, step);
  }

  // Range with optional step: n-m or n-m/s
  if (segment.includes("-")) {
    const slashIndex = segment.indexOf("/");
    const rangePart = slashIndex !== -1 ? segment.slice(0, slashIndex) : segment;
    const step = slashIndex !== -1 ? parseInt(segment.slice(slashIndex + 1), 10) : 1;
    const [startStr, endStr] = rangePart.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end) || isNaN(step)) {
      throw new Error(`Invalid range "${segment}" for field "${fieldName}"`);
    }
    if (start > end) throw new Error(`Range start > end in "${segment}" for field "${fieldName}"`);
    clamp(start, min, max, fieldName);
    clamp(end, min, max, fieldName);
    clamp(step, 1, max - min, fieldName);
    return range(start, end, step);
  }

  // Plain number
  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new Error(`Invalid value "${segment}" for field "${fieldName}"`);
  return [clamp(value, min, max, fieldName)];
};

const parseField = (expression: string, config: FieldConfig, fieldName: string): number[] => {
  const segments = expression.split(",");
  const values = new Set<number>();
  for (const segment of segments) {
    for (const v of parseSegment(segment.trim(), config, fieldName)) {
      values.add(v);
    }
  }
  return Array.from(values).sort((a, b) => a - b);
};

const parseCron = (expression: string): CronFields => {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(`Expected 5 fields, got ${parts.length}`);
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = parts;
  const fields = Object.keys(FIELD_CONFIGS) as (keyof CronFields)[];
  const exprs = [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr];

  return fields.reduce((acc, field, i) => {
    acc[field] = parseField(exprs[i], FIELD_CONFIGS[field], field);
    return acc;
  }, {} as CronFields);
};

export default parseCron;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface Waiter {
  tokens: number;
  resolve: () => void;
  reject: (err: Error) => void;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waiters: Waiter[];
  private scheduledRefill: ReturnType<typeof setTimeout> | null;

  constructor(options: RateLimiterOptions) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError("maxTokens must be a finite positive number");
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate < 0) {
      throw new RangeError("refillRate must be a finite non-negative number");
    }
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0) {
      throw new RangeError("refillIntervalMs must be a finite positive number");
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
    this.waiters = [];
    this.scheduledRefill = null;
  }

  private applyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed <= 0 || this.refillRate === 0) return;

    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      this.currentTokens = Math.min(
        this.maxTokens,
        this.currentTokens + intervals * this.refillRate
      );
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  private msUntilNextRefill(): number {
    const elapsed = Date.now() - this.lastRefillTime;
    return Math.max(0, this.refillIntervalMs - (elapsed % this.refillIntervalMs));
  }

  private scheduleRefill(): void {
    if (this.scheduledRefill !== null || this.refillRate === 0 || this.waiters.length === 0) {
      return;
    }

    const delay = this.msUntilNextRefill();

    this.scheduledRefill = setTimeout(() => {
      this.scheduledRefill = null;
      this.drainWaiters();
    }, delay === 0 ? 1 : delay);
  }

  private drainWaiters(): void {
    this.applyRefill();

    while (this.waiters.length > 0) {
      const head = this.waiters[0];

      if (this.currentTokens >= head.tokens) {
        this.currentTokens -= head.tokens;
        this.waiters.shift();
        head.resolve();
      } else {
        break;
      }
    }

    if (this.waiters.length > 0) {
      this.scheduleRefill();
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError("tokens must be a finite non-negative number");
    }
    if (tokens === 0) return true;
    if (tokens > this.maxTokens) return false;

    this.applyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.applyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();

    if (this.scheduledRefill !== null) {
      clearTimeout(this.scheduledRefill);
      this.scheduledRefill = null;
    }

    this.drainWaiters();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0) {
      return Promise.reject(new RangeError("tokens must be a finite non-negative number"));
    }
    if (tokens === 0) return Promise.resolve();
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested tokens (${tokens}) exceeds maxTokens (${this.maxTokens}); ` +
          `this request can never be fulfilled`
        )
      );
    }
    if (this.refillRate === 0 && !this.tryConsume(tokens)) {
      return Promise.reject(
        new Error(
          `Insufficient tokens and refillRate is 0; ` +
          `this request can never be fulfilled`
        )
      );
    }

    // Only bypass the queue if no other waiters are ahead — preserves FIFO fairness.
    if (this.waiters.length === 0 && this.tryConsume(tokens)) {
      return Promise.resolve();
    }

    return new Promise<void>((resolve, reject) => {
      this.waiters.push({ tokens, resolve, reject });
      this.scheduleRefill();
    });
  }
}

export default RateLimiter;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface WaitEntry {
  tokens: number;
  resolve: () => void;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTimestamp: number;
  private readonly waitQueue: WaitEntry[];
  private refillScheduled: boolean;

  constructor(options: RateLimiterOptions) {
    const { maxTokens, refillRate, refillIntervalMs } = options;

    if (!Number.isFinite(maxTokens) || maxTokens <= 0) {
      throw new RangeError(`maxTokens must be a positive finite number, got ${maxTokens}`);
    }
    if (!Number.isFinite(refillRate) || refillRate <= 0) {
      throw new RangeError(`refillRate must be a positive finite number, got ${refillRate}`);
    }
    if (!Number.isFinite(refillIntervalMs) || refillIntervalMs <= 0) {
      throw new RangeError(`refillIntervalMs must be a positive finite number, got ${refillIntervalMs}`);
    }

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.currentTokens = maxTokens;
    this.lastRefillTimestamp = Date.now();
    this.waitQueue = [];
    this.refillScheduled = false;
  }

  private applyLazyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTimestamp;

    if (elapsed <= 0) return;

    const intervals = Math.floor(elapsed / this.refillIntervalMs);
    if (intervals > 0) {
      // Guard against astronomical elapsed times causing Infinity
      const tokensToAdd = Math.min(
        intervals * this.refillRate,
        this.maxTokens - this.currentTokens
      );
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      // Advance timestamp by exact consumed intervals to preserve fractional interval
      this.lastRefillTimestamp += intervals * this.refillIntervalMs;
    }
  }

  private validateTokenArg(tokens: number, context: string): void {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError(`${context}: tokens must be a non-negative finite number, got ${tokens}`);
    }
  }

  tryConsume(tokens: number = 1): boolean {
    this.validateTokenArg(tokens, "tryConsume");
    if (tokens === 0) return true;
    // A request exceeding the bucket's capacity can never be satisfied
    if (tokens > this.maxTokens) return false;

    this.applyLazyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }
    return false;
  }

  getTokens(): number {
    this.applyLazyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTimestamp = Date.now();
    // Drain the wait queue immediately: everyone gets their tokens now
    this.drainQueue();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    this.validateTokenArg(tokens, "waitForTokens");
    if (tokens === 0) return Promise.resolve();

    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `waitForTokens: requested ${tokens} tokens but bucket capacity is ${this.maxTokens} — request can never be satisfied`
        )
      );
    }

    // Only attempt immediate consumption if no one else is ahead in line (fairness)
    if (this.waitQueue.length === 0 && this.tryConsume(tokens)) {
      return Promise.resolve();
    }

    return new Promise<void>((resolve) => {
      this.waitQueue.push({ tokens, resolve });
      this.scheduleNextDrain();
    });
  }

  private scheduleNextDrain(): void {
    if (this.refillScheduled) return;
    this.refillScheduled = true;

    // Fire just after the next refill interval boundary
    const now = Date.now();
    const elapsed = now - this.lastRefillTimestamp;
    const remainder = elapsed % this.refillIntervalMs;
    const delay = remainder === 0
      ? this.refillIntervalMs
      : this.refillIntervalMs - remainder;

    setTimeout(() => {
      this.refillScheduled = false;
      this.applyLazyRefill();
      this.drainQueue();
    }, delay + 1); // +1 ms to ensure the interval has actually elapsed
  }

  private drainQueue(): void {
    // Process FIFO — do NOT skip the head even if a later entry could be satisfied;
    // skipping would starve large requests indefinitely.
    while (this.waitQueue.length > 0) {
      const head = this.waitQueue[0];
      if (this.currentTokens >= head.tokens) {
        this.currentTokens -= head.tokens;
        this.waitQueue.shift();
        // Resolve outside the tight loop to avoid re-entrant tryConsume calls
        // stealing tokens before the next queue entry is checked.
        queueMicrotask(head.resolve);
      } else {
        // Head can't be satisfied yet; schedule another drain after the next refill
        this.scheduleNextDrain();
        break;
      }
    }
  }
}

export default RateLimiter;

type FieldName = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

type CronObject = Record<FieldName, number[]>;

type FieldRange = { readonly min: number; readonly max: number };

const FIELD_RANGES: Record<FieldName, FieldRange> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
} as const;

const FIELD_ORDER: readonly FieldName[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
] as const;

function assertInRange(value: number, range: FieldRange, context: string): void {
  if (!Number.isInteger(value) || value < range.min || value > range.max) {
    throw new RangeError(
      `Value ${value} out of valid range [${range.min}-${range.max}] in segment "${context}"`
    );
  }
}

function parseInteger(raw: string, context: string): number {
  const n = Number(raw);
  if (!Number.isInteger(n) || raw.trim() === "" || raw.includes(".")) {
    throw new TypeError(`Expected integer, got "${raw}" in segment "${context}"`);
  }
  return n;
}

function expandRange(start: number, end: number, step: number, segment: string): number[] {
  if (start > end) {
    throw new RangeError(`Range start (${start}) exceeds end (${end}) in segment "${segment}"`);
  }
  if (step <= 0) {
    throw new RangeError(`Step must be a positive integer in segment "${segment}"`);
  }
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(segment: string, range: FieldRange): number[] {
  const slashIndex = segment.indexOf("/");

  if (slashIndex !== -1) {
    const base = segment.slice(0, slashIndex);
    const stepRaw = segment.slice(slashIndex + 1);

    if (stepRaw === "" || stepRaw.includes("/")) {
      throw new SyntaxError(`Malformed step expression in segment "${segment}"`);
    }

    const step = parseInteger(stepRaw, segment);

    if (base === "*") {
      return expandRange(range.min, range.max, step, segment);
    }

    if (base.includes("-")) {
      const dashIndex = base.indexOf("-");
      const start = parseInteger(base.slice(0, dashIndex), segment);
      const end   = parseInteger(base.slice(dashIndex + 1), segment);
      assertInRange(start, range, segment);
      assertInRange(end,   range, segment);
      return expandRange(start, end, step, segment);
    }

    // single-number base: "5/15" → start at 5, step 15 to range.max
    const start = parseInteger(base, segment);
    assertInRange(start, range, segment);
    return expandRange(start, range.max, step, segment);
  }

  if (segment === "*") {
    return expandRange(range.min, range.max, 1, segment);
  }

  if (segment.includes("-")) {
    const dashIndex = segment.indexOf("-");
    const start = parseInteger(segment.slice(0, dashIndex), segment);
    const end   = parseInteger(segment.slice(dashIndex + 1), segment);
    assertInRange(start, range, segment);
    assertInRange(end,   range, segment);
    return expandRange(start, end, 1, segment);
  }

  const value = parseInteger(segment, segment);
  assertInRange(value, range, segment);
  return [value];
}

function parseField(field: string, range: FieldRange): number[] {
  if (field === "") {
    throw new SyntaxError("Empty cron field");
  }

  const parts = field.split(",");
  const seen = new Set<number>();

  for (const part of parts) {
    const trimmed = part.trim();
    if (trimmed === "") {
      throw new SyntaxError(`Empty segment in field "${field}"`);
    }
    for (const value of parseSegment(trimmed, range)) {
      seen.add(value);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronObject {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, received ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, received ${fields.length}: "${expression}"`
    );
  }

  return FIELD_ORDER.reduce<Partial<CronObject>>((acc, name, index) => {
    acc[name] = parseField(fields[index], FIELD_RANGES[name]);
    return acc;
  }, {}) as CronObject;
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface Waiter {
  tokens: number;
  resolve: () => void;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: Waiter[] = [];
  private scheduledRefill: boolean = false;

  constructor(options: RateLimiterOptions) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError("maxTokens must be a finite positive number");
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate < 0) {
      throw new RangeError("refillRate must be a finite non-negative number");
    }
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0) {
      throw new RangeError("refillIntervalMs must be a finite positive number");
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private lazyRefill(): void {
    if (this.refillRate === 0) return;

    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed < this.refillIntervalMs) return;

    const intervals = Math.floor(elapsed / this.refillIntervalMs);
    const added = intervals * this.refillRate;

    this.currentTokens = Math.min(this.maxTokens, this.currentTokens + added);
    // Advance the refill clock by whole intervals only — preserve sub-interval remainder
    this.lastRefillTime += intervals * this.refillIntervalMs;
  }

  private drainWaitQueue(): void {
    while (this.waitQueue.length > 0) {
      const waiter = this.waitQueue[0];
      if (this.currentTokens >= waiter.tokens) {
        this.currentTokens -= waiter.tokens;
        this.waitQueue.shift();
        waiter.resolve();
      } else {
        break;
      }
    }
  }

  private scheduleNextWaiter(): void {
    if (this.scheduledRefill || this.waitQueue.length === 0 || this.refillRate === 0) return;

    const tokensNeeded = this.waitQueue[0].tokens - this.currentTokens;

    if (tokensNeeded <= 0) {
      this.drainWaitQueue();
      if (this.waitQueue.length > 0) this.scheduleNextWaiter();
      return;
    }

    const intervalsNeeded = Math.ceil(tokensNeeded / this.refillRate);
    const elapsed = Date.now() - this.lastRefillTime;
    const remainingInCurrentInterval = this.refillIntervalMs - (elapsed % this.refillIntervalMs);
    // Add a 1ms guard to ensure the interval has fully elapsed before we check
    const delayMs = remainingInCurrentInterval + (intervalsNeeded - 1) * this.refillIntervalMs + 1;

    this.scheduledRefill = true;
    setTimeout(() => {
      this.scheduledRefill = false;
      this.lazyRefill();
      this.drainWaitQueue();
      if (this.waitQueue.length > 0) this.scheduleNextWaiter();
    }, delayMs);
  }

  private validateTokenArg(tokens: number, label: string): void {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError(`${label} must be a finite non-negative number`);
    }
  }

  tryConsume(tokens: number = 1): boolean {
    this.validateTokenArg(tokens, "tokens");

    // A request that can never be satisfied should never silently succeed
    if (tokens > this.maxTokens) return false;

    this.lazyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      // Consuming tokens may unblock waiters if reset() over-filled somehow; keep queue consistent
      this.drainWaitQueue();
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.lazyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.drainWaitQueue();
    // Reschedule for any remaining waiters that still can't be served yet
    if (this.waitQueue.length > 0) this.scheduleNextWaiter();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    this.validateTokenArg(tokens, "tokens");

    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested tokens (${tokens}) exceed maxTokens (${this.maxTokens}) — can never be satisfied`
        )
      );
    }

    this.lazyRefill();

    // Fast path: serve immediately if queue is empty and tokens are available.
    // Queue must be empty first to preserve FIFO fairness across concurrent waiters.
    if (this.waitQueue.length === 0 && this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return Promise.resolve();
    }

    return new Promise<void>((resolve) => {
      this.waitQueue.push({ tokens, resolve });
      this.scheduleNextWaiter();
    });
  }
}

export default RateLimiter;

export interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export class RateLimiter {
  private readonly maxTokens: number;
