    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervalsElapsed = Math.floor(elapsed / this.refillIntervalMs);

    if (intervalsElapsed > 0) {
      const tokensToAdd = intervalsElapsed * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervalsElapsed * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) {
      throw new RangeError(`Requested tokens (${tokens}) exceed maxTokens (${this.maxTokens})`);
    }

    while (true) {
      this.refill();

      if (this.currentTokens >= tokens) {
        this.currentTokens -= tokens;
        return;
      }

      const deficit = tokens - this.currentTokens;
      const intervalsNeeded = Math.ceil(deficit / this.refillRate);
      const msUntilRefill = this.refillIntervalMs - (Date.now() - this.lastRefillTime);
      const waitMs = Math.max(0, msUntilRefill + (intervalsNeeded - 1) * this.refillIntervalMs);

      await new Promise<void>((resolve) => setTimeout(resolve, waitMs));
    }
  }
}

export default RateLimiter;

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldRange = {
  min: number;
  max: number;
};

const FIELD_RANGES: Record<keyof CronResult, FieldRange> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

const range = (start: number, end: number): number[] =>
  Array.from({ length: end - start + 1 }, (_, i) => start + i);

const parseField = (field: string, { min, max }: FieldRange): number[] => {
  // Comma-separated list
  if (field.includes(",")) {
    const values = field
      .split(",")
      .flatMap((part) => parseField(part.trim(), { min, max }));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Wildcard
  if (field === "*") {
    return range(min, max);
  }

  // Step value: */step or start-end/step
  if (field.includes("/")) {
    const [rangePart, stepStr] = field.split("/");
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: ${stepStr}`);
    }

    let start = min;
    let end = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [startStr, endStr] = rangePart.split("-");
        start = parseInt(startStr, 10);
        end = parseInt(endStr, 10);
      } else {
        start = parseInt(rangePart, 10);
      }
    }

    validateRange(start, end, min, max);

    const result: number[] = [];
    for (let i = start; i <= end; i += step) {
      result.push(i);
    }
    return result;
  }

  // Range: start-end
  if (field.includes("-")) {
    const [startStr, endStr] = field.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);

    validateRange(start, end, min, max);

    return range(start, end);
  }

  // Single number
  const value = parseInt(field, 10);

  if (isNaN(value)) {
    throw new Error(`Invalid cron field value: ${field}`);
  }

  if (value < min || value > max) {
    throw new Error(
      `Value ${value} out of range [${min}, ${max}]`
    );
  }

  return [value];
};

const validateRange = (
  start: number,
  end: number,
  min: number,
  max: number
): void => {
  if (isNaN(start) || isNaN(end)) {
    throw new Error(`Invalid range values: ${start}-${end}`);
  }
  if (start > end) {
    throw new Error(
      `Range start ${start} is greater than end ${end}`
    );
  }
  if (start < min || end > max) {
    throw new Error(
      `Range ${start}-${end} is out of bounds [${min}, ${max}]`
    );
  }
};

const normalizeDayOfWeek = (values: number[]): number[] => {
  // Treat 7 as Sunday (0) for compatibility
  const normalized = values.map((v) => (v === 7 ? 0 : v));
  return [...new Set(normalized)].sort((a, b) => a - b);
};

const parseCron = (expression: string): CronResult => {
  if (typeof expression !== "string" || expression.trim() === "") {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Expected 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteField, hourField, domField, monthField, dowField] = fields;

  const fieldKeys = Object.keys(FIELD_RANGES) as (keyof CronResult)[];
  const rawValues = [minuteField, hourField, domField, monthField, dowField].map(
    (field, i) => parseField(field, FIELD_RANGES[fieldKeys[i]])
  );

  const [minute, hour, dayOfMonth, month, dayOfWeek] = rawValues;

  return {
    minute,
    hour,
    dayOfMonth,
    month,
    dayOfWeek: normalizeDayOfWeek(dayOfWeek),
  };
};

export default parseCron;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError("maxTokens must be a finite positive number");
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate < 0) {
      throw new RangeError("refillRate must be a finite non-negative number");
    }
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0) {
      throw new RangeError("refillIntervalMs must be a finite positive number");
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    // Guard against clock skew (e.g. NTP adjustments going backwards)
    const elapsed = Math.max(0, now - this.lastRefillTime);
    const tokensToAdd = (elapsed / this.refillIntervalMs) * this.refillRate;
    this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
    this.lastRefillTime = now;
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError("tokens must be a finite non-negative number");
    }
    // Zero-token requests are vacuously satisfiable
    if (tokens === 0) return true;
    // Requests exceeding the bucket ceiling can never be satisfied
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError("tokens must be a finite non-negative number");
    }
    if (tokens === 0) return;
    // Permanent deadlock: requested amount can never fit in the bucket
    if (tokens > this.maxTokens) {
      throw new RangeError(
        `Requested tokens (${tokens}) exceed maxTokens (${this.maxTokens}) and can never be satisfied`,
      );
    }

    // eslint-disable-next-line no-constant-condition
    while (true) {
      // tryConsume is the authoritative check: it calls refill() atomically
      // before the conditional deduction, keeping concurrent callers safe
      // under JS's single-threaded event loop (no mid-check interleaving).
      if (this.tryConsume(tokens)) return;

      // Permanent deadlock: no refill will ever occur
      if (this.refillRate === 0) {
        throw new Error(
          "Cannot satisfy waitForTokens: refillRate is 0 and insufficient tokens available",
        );
      }

      // After a failed tryConsume, currentTokens reflects the post-refill value.
      // Sleep just long enough for the deficit to be covered, then re-check.
      const deficit = tokens - this.currentTokens;
      const waitMs = Math.ceil((deficit / this.refillRate) * this.refillIntervalMs);
      await new Promise<void>((resolve) => setTimeout(resolve, Math.max(1, waitMs)));
    }
  }
}

export default RateLimiter;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    const { maxTokens, refillRate, refillIntervalMs } = options;

    if (maxTokens <= 0) throw new RangeError("maxTokens must be greater than 0");
    if (refillRate <= 0) throw new RangeError("refillRate must be greater than 0");
    if (refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be greater than 0");

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.currentTokens = maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      const tokensToAdd = intervals * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be greater than 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) throw new RangeError("tokens must be greater than 0");
    if (tokens > this.maxTokens) {
      throw new RangeError(`Requested tokens (${tokens}) exceeds maxTokens (${this.maxTokens})`);
    }

    while (!this.tryConsume(tokens)) {
      const tokensNeeded = tokens - this.currentTokens;
      const intervalsNeeded = Math.ceil(tokensNeeded / this.refillRate);
      const elapsed = Date.now() - this.lastRefillTime;
      const waitMs = Math.max(1, intervalsNeeded * this.refillIntervalMs - elapsed);

      await new Promise<void>((resolve) => setTimeout(resolve, waitMs));
    }
  }
}

export default RateLimiter;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be positive");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be positive");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be positive");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      const tokensToAdd = intervals * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be positive");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens must be positive"));
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(`Requested tokens (${tokens}) exceeds maxTokens (${this.maxTokens})`)
      );
    }

    return new Promise<void>((resolve) => {
      const attempt = (): void => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();
        const deficit = tokens - this.currentTokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const waitMs = Math.max(1, intervalsNeeded * this.refillIntervalMs);

        setTimeout(attempt, waitMs);
      };

      attempt();
    });
  }
}

export default RateLimiter;

export default class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: Array<{ tokens: number; resolve: () => void }>;
  private wakeTimeout: ReturnType<typeof setTimeout> | null;

  constructor(options: {
    maxTokens: number;
    refillRate: number;
    refillIntervalMs: number;
  }) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError("maxTokens must be a positive finite number");
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate < 0) {
      throw new RangeError("refillRate must be a non-negative finite number");
    }
    if (
      !Number.isFinite(options.refillIntervalMs) ||
      options.refillIntervalMs <= 0
    ) {
      throw new RangeError("refillIntervalMs must be a positive finite number");
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
    this.wakeTimeout = null;
  }

  private refill(): void {
    if (this.refillRate === 0) return;
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    if (elapsed >= this.refillIntervalMs) {
      const intervals = Math.floor(elapsed / this.refillIntervalMs);
      this.currentTokens = Math.min(
        this.maxTokens,
        this.currentTokens + intervals * this.refillRate
      );
      // Advance lastRefillTime by whole intervals only — preserves sub-interval
      // progress and prevents elapsed time from being silently discarded.
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  private drainQueue(): void {
    // FIFO: serve waiters in order to prevent starvation of the head waiter.
    while (this.waitQueue.length > 0) {
      const waiter = this.waitQueue[0]!;
      if (this.currentTokens >= waiter.tokens) {
        this.currentTokens -= waiter.tokens;
        this.waitQueue.shift();
        waiter.resolve();
      } else {
        break;
      }
    }
  }

  private scheduleWake(): void {
    // Cancel any pending wake — avoids duplicate timers after reset() or when
    // a new, sooner-to-satisfy waiter arrives at the head of the queue.
    if (this.wakeTimeout !== null) {
      clearTimeout(this.wakeTimeout);
      this.wakeTimeout = null;
    }

    if (this.waitQueue.length === 0 || this.refillRate === 0) return;

    const waiter = this.waitQueue[0]!;
    const needed = waiter.tokens - this.currentTokens;
    const intervalsNeeded = Math.ceil(needed / this.refillRate);
    // How far into the current interval are we right now?
    const elapsed = Date.now() - this.lastRefillTime;
    const msUntilNextInterval = this.refillIntervalMs - elapsed;
    // Wake just after the interval boundary where enough tokens will exist.
    const delay = Math.max(
      1,
      (intervalsNeeded - 1) * this.refillIntervalMs + msUntilNextInterval
    );

    this.wakeTimeout = setTimeout(() => {
      this.wakeTimeout = null;
      this.refill();
      this.drainQueue();
      // Re-schedule if the queue still has pending waiters (e.g. head needed
      // more tokens than one interval could provide, or multiple waiters remain).
      this.scheduleWake();
    }, delay);
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens <= 0) {
      throw new RangeError("tokens must be a positive finite number");
    }
    // A request larger than the bucket can never be satisfied — fail fast
    // instead of silently blocking forever.
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }
    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    // Drain before rescheduling so the wake timer reflects the actual
    // remaining queue after the reset flush.
    this.drainQueue();
    this.scheduleWake();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens <= 0) {
      return Promise.reject(
        new RangeError("tokens must be a positive finite number")
      );
    }
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `tokens (${tokens}) exceeds maxTokens (${this.maxTokens}) and can never be satisfied`
        )
      );
    }

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return Promise.resolve();
    }

    // With refillRate === 0 and insufficient tokens, this promise would never
    // resolve — reject immediately to prevent a silent memory/handle leak.
    if (this.refillRate === 0) {
      return Promise.reject(
        new Error(
          "Insufficient tokens and refillRate is 0; request can never be fulfilled"
        )
      );
    }

    return new Promise<void>((resolve) => {
      const wasEmpty = this.waitQueue.length === 0;
      this.waitQueue.push({ tokens, resolve });
      // Only (re)schedule when we add the first waiter — subsequent additions
      // are already covered by the existing scheduled wake, and scheduleWake
      // is called again after each drain to re-evaluate the new head.
      if (wasEmpty) {
        this.scheduleWake();
      }
    });
  }
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface QueueEntry {
  tokens: number;
  resolve: () => void;
  reject: (err: Error) => void;
}

export default class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: QueueEntry[];
  private refillTimer: ReturnType<typeof setTimeout> | null;

  constructor(options: RateLimiterOptions) {
    const { maxTokens, refillRate, refillIntervalMs } = options;

    if (!Number.isFinite(maxTokens) || maxTokens <= 0) {
      throw new RangeError(
        `maxTokens must be a positive finite number, got ${maxTokens}`
      );
    }
    if (!Number.isFinite(refillRate) || refillRate <= 0) {
      throw new RangeError(
        `refillRate must be a positive finite number, got ${refillRate}`
      );
    }
    if (!Number.isFinite(refillIntervalMs) || refillIntervalMs <= 0) {
      throw new RangeError(
        `refillIntervalMs must be a positive finite number, got ${refillIntervalMs}`
      );
    }

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.currentTokens = maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
    this.refillTimer = null;
  }

  private applyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    if (elapsed > 0) {
      const tokensToAdd = (elapsed / this.refillIntervalMs) * this.refillRate;
      this.currentTokens = Math.min(
        this.maxTokens,
        this.currentTokens + tokensToAdd
      );
      this.lastRefillTime = now;
    }
  }

  private validateTokenCount(tokens: number, caller: string): void {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError(
        `${caller}: tokens must be a non-negative finite number, got ${tokens}`
      );
    }
  }

  private drainQueue(): void {
    while (this.waitQueue.length > 0) {
      const entry = this.waitQueue[0]!;
      if (this.currentTokens >= entry.tokens) {
        this.currentTokens -= entry.tokens;
        this.waitQueue.shift();
        entry.resolve();
      } else {
        break;
      }
    }
  }

  private scheduleNextCheck(): void {
    if (this.refillTimer !== null || this.waitQueue.length === 0) return;

    const entry = this.waitQueue[0]!;
    this.applyRefill();

    const deficit = entry.tokens - this.currentTokens;
    if (deficit <= 0) {
      this.drainQueue();
      if (this.waitQueue.length > 0) {
        this.scheduleNextCheck();
      }
      return;
    }

    const msPerToken = this.refillIntervalMs / this.refillRate;
    const delayMs = Math.ceil(deficit * msPerToken);

    this.refillTimer = setTimeout(() => {
      this.refillTimer = null;
      this.applyRefill();
      this.drainQueue();
      if (this.waitQueue.length > 0) {
        this.scheduleNextCheck();
      }
    }, delayMs);
  }

  tryConsume(tokens: number = 1): boolean {
    this.validateTokenCount(tokens, "tryConsume");

    if (tokens === 0) return true;

    // A request exceeding the bucket ceiling can never be satisfied.
    if (tokens > this.maxTokens) return false;

    this.applyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }
    return false;
  }

  getTokens(): number {
    this.applyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();

    // Opportunistically satisfy any queued waiters with the freshly filled bucket.
    this.drainQueue();

    // If entries remain, reschedule (cancel stale timer first to avoid double-fire).
    if (this.refillTimer !== null) {
      clearTimeout(this.refillTimer);
      this.refillTimer = null;
    }
    if (this.waitQueue.length > 0) {
      this.scheduleNextCheck();
    }
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    try {
      this.validateTokenCount(tokens, "waitForTokens");
    } catch (err) {
      return Promise.reject(err);
    }

    if (tokens === 0) return Promise.resolve();

    // Requests that can never be satisfied must fail fast; waiting forever is
    // indistinguishable from a hang and would silently leak memory.
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `waitForTokens: requested ${tokens} tokens exceeds bucket capacity of ` +
            `${this.maxTokens} — this would wait forever`
        )
      );
    }

    // Fast path: consume immediately when the queue is empty.
    if (this.waitQueue.length === 0 && this.tryConsume(tokens)) {
      return Promise.resolve();
    }

    return new Promise<void>((resolve, reject) => {
      this.waitQueue.push({ tokens, resolve, reject });
      this.scheduleNextCheck();
    });
  }
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronFields;

interface FieldBounds {
  min: number;
  max: number;
}

const FIELD_ORDER: FieldName[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

const FIELD_BOUNDS: Record<FieldName, FieldBounds> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
};

function buildRange(start: number, end: number, step: number = 1): number[] {
  if (step <= 0) {
    throw new Error(`Step must be a positive integer, got: ${step}`);
  }
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseStrictInt(raw: string, context: string): number {
  if (!/^\d+$/.test(raw)) {
    throw new Error(`Invalid integer "${raw}" in ${context}`);
  }
  const n = Number(raw);
  if (!Number.isInteger(n) || !Number.isFinite(n)) {
    throw new Error(`Non-integer value "${raw}" in ${context}`);
  }
  return n;
}

function assertInBounds(value: number, bounds: FieldBounds, context: string): void {
  if (value < bounds.min || value > bounds.max) {
    throw new Error(
      `Value ${value} out of range [${bounds.min}–${bounds.max}] in ${context}`
    );
  }
}

function parseSegment(segment: string, bounds: FieldBounds, fieldName: string): number[] {
  const ctx = `field "${fieldName}", segment "${segment}"`;

  // Step expression: */n or x-y/n or x/n
  if (segment.includes("/")) {
    const slashAt = segment.indexOf("/");
    const lhs = segment.slice(0, slashAt);
    const rhs = segment.slice(slashAt + 1);

    if (rhs.includes("/")) {
      throw new Error(`Multiple slash operators not allowed in ${ctx}`);
    }

    const step = parseStrictInt(rhs, ctx);
    if (step <= 0) {
      throw new Error(`Step must be >= 1 in ${ctx}`);
    }

    if (lhs === "*") {
      return buildRange(bounds.min, bounds.max, step);
    }

    if (lhs.includes("-")) {
      const dashAt = lhs.indexOf("-");
      const startRaw = lhs.slice(0, dashAt);
      const endRaw = lhs.slice(dashAt + 1);
      if (endRaw.includes("-")) {
        throw new Error(`Malformed range in ${ctx}`);
      }
      const start = parseStrictInt(startRaw, ctx);
      const end = parseStrictInt(endRaw, ctx);
      assertInBounds(start, bounds, ctx);
      assertInBounds(end, bounds, ctx);
      if (start > end) {
        throw new Error(`Range start ${start} > end ${end} in ${ctx}`);
      }
      return buildRange(start, end, step);
    }

    // x/n: start at x, step to max
    const start = parseStrictInt(lhs, ctx);
    assertInBounds(start, bounds, ctx);
    return buildRange(start, bounds.max, step);
  }

  // Wildcard
  if (segment === "*") {
    return buildRange(bounds.min, bounds.max);
  }

  // Range: x-y
  if (segment.includes("-")) {
    const dashAt = segment.indexOf("-");
    const startRaw = segment.slice(0, dashAt);
    const endRaw = segment.slice(dashAt + 1);
    if (endRaw.includes("-")) {
      throw new Error(`Malformed range (too many dashes) in ${ctx}`);
    }
    const start = parseStrictInt(startRaw, ctx);
    const end = parseStrictInt(endRaw, ctx);
    assertInBounds(start, bounds, ctx);
    assertInBounds(end, bounds, ctx);
    if (start > end) {
      throw new Error(`Range start ${start} > end ${end} in ${ctx}`);
    }
    return buildRange(start, end);
  }

  // Single value
  const value = parseStrictInt(segment, ctx);
  assertInBounds(value, bounds, ctx);
  return [value];
}

function parseFieldExpression(
  expr: string,
  bounds: FieldBounds,
  fieldName: string
): number[] {
  if (typeof expr !== "string" || expr.trim() === "") {
    throw new Error(`Empty or invalid expression for field "${fieldName}"`);
  }

  const segments = expr.split(",");
  if (segments.length === 0) {
    throw new Error(`No segments found in field "${fieldName}"`);
  }

  const seen = new Set<number>();
  for (const segment of segments) {
    const trimmed = segment.trim();
    if (trimmed === "") {
      throw new Error(`Empty segment in comma-list for field "${fieldName}"`);
    }
    for (const v of parseSegment(trimmed, bounds, fieldName)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new Error("Cron expression must be a string");
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("Cron expression must not be empty");
  }

  const parts = trimmed.split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields (got ${parts.length}): "${trimmed}"`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    result[fieldName] = parseFieldExpression(
      parts[i],
      FIELD_BOUNDS[fieldName],
      fieldName
    );
  }

  return result;
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      const tokensToAdd = intervals * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens to consume must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens to consume must be > 0"));
    if (tokens > this.maxTokens) return Promise.reject(new RangeError("tokens requested exceed maxTokens"));

    return new Promise((resolve) => {
      const attempt = (): void => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();

        const deficit = tokens - this.currentTokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const delay = Math.max(1, intervalsNeeded * this.refillIntervalMs);

        setTimeout(attempt, delay);
      };

      attempt();
    });
  }
}

export default RateLimiter;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function parseField(expression: string, min: number, max: number): number[] {
  const results = new Set<number>();

  for (const part of expression.split(",")) {
    const trimmed = part.trim();

    if (trimmed === "*") {
      for (let i = min; i <= max; i++) results.add(i);
      continue;
    }

    const stepMatch = trimmed.match(/^(\*|(\d+)-(\d+))\/(\d+)$/);
    if (stepMatch) {
      const step = parseInt(stepMatch[4], 10);
      if (step <= 0) throw new Error(`Invalid step value: ${step}`);

      const rangeMin = stepMatch[1] === "*" ? min : parseInt(stepMatch[2], 10);
      const rangeMax = stepMatch[1] === "*" ? max : parseInt(stepMatch[3], 10);

      validateRange(rangeMin, rangeMax, min, max, trimmed);

      for (let i = rangeMin; i <= rangeMax; i += step) results.add(i);
      continue;
    }

    const rangeMatch = trimmed.match(/^(\d+)-(\d+)$/);
    if (rangeMatch) {
      const rangeMin = parseInt(rangeMatch[1], 10);
      const rangeMax = parseInt(rangeMatch[2], 10);

      validateRange(rangeMin, rangeMax, min, max, trimmed);

      for (let i = rangeMin; i <= rangeMax; i++) results.add(i);
      continue;
    }

    const numMatch = trimmed.match(/^(\d+)$/);
    if (numMatch) {
      const value = parseInt(numMatch[1], 10);

      if (value < min || value > max) {
        throw new Error(`Value ${value} out of range [${min}, ${max}]`);
      }

      results.add(value);
      continue;
    }

    throw new Error(`Invalid cron field expression: "${trimmed}"`);
  }

  return Array.from(results).sort((a, b) => a - b);
}

function validateRange(
  rangeMin: number,
  rangeMax: number,
  min: number,
  max: number,
  expression: string
): void {
  if (rangeMin > rangeMax) {
    throw new Error(
      `Invalid range: start ${rangeMin} > end ${rangeMax} in "${expression}"`
    );
  }
  if (rangeMin < min || rangeMax > max) {
    throw new Error(
      `Range ${rangeMin}-${rangeMax} out of bounds [${min}, ${max}] in "${expression}"`
    );
  }
}

export function parseCron(expression: string): CronFields {
  if (typeof expression !== "string" || expression.trim() === "") {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Expected 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] =
    fields;
  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];

  return {
    minute: parseField(minuteExpr, ...FIELD_RANGES.minute),
    hour: parseField(hourExpr, ...FIELD_RANGES.hour),
    dayOfMonth: parseField(dayOfMonthExpr, ...FIELD_RANGES.dayOfMonth),
    month: parseField(monthExpr, ...FIELD_RANGES.month),
    dayOfWeek: parseField(dayOfWeekExpr, ...FIELD_RANGES.dayOfWeek),
  };
}

export default parseCron;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function parseField(expr: string, min: number, max: number): number[] {
  const results = new Set<number>();

  for (const part of expr.split(",")) {
    const trimmed = part.trim();

    if (trimmed === "*") {
      for (let i = min; i <= max; i++) results.add(i);
      continue;
    }

    const stepMatch = trimmed.match(/^(\*|(\d+)-(\d+))\/(\d+)$/);
    if (stepMatch) {
      const step = parseInt(stepMatch[4], 10);
      if (step <= 0) throw new RangeError(`Invalid step value: ${step}`);
      const rangeMin = stepMatch[1] === "*" ? min : parseInt(stepMatch[2], 10);
      const rangeMax = stepMatch[1] === "*" ? max : parseInt(stepMatch[3], 10);
      validateRange(rangeMin, rangeMax, min, max);
      for (let i = rangeMin; i <= rangeMax; i += step) results.add(i);
      continue;
    }

    const rangeMatch = trimmed.match(/^(\d+)-(\d+)$/);
    if (rangeMatch) {
      const lo = parseInt(rangeMatch[1], 10);
      const hi = parseInt(rangeMatch[2], 10);
      validateRange(lo, hi, min, max);
      for (let i = lo; i <= hi; i++) results.add(i);
      continue;
    }

    if (/^\d+$/.test(trimmed)) {
      const val = parseInt(trimmed, 10);
      if (val < min || val > max) {
        throw new RangeError(`Value ${val} is out of range [${min}, ${max}]`);
      }
      results.add(val);
      continue;
    }

    throw new SyntaxError(`Invalid cron field expression: "${trimmed}"`);
  }

  return Array.from(results).sort((a, b) => a - b);
}

function validateRange(lo: number, hi: number, min: number, max: number): void {
  if (lo > hi) throw new RangeError(`Invalid range: ${lo}-${hi} (start > end)`);
  if (lo < min || hi > max) {
    throw new RangeError(`Range ${lo}-${hi} exceeds allowed bounds [${min}, ${max}]`);
  }
}

function parseCron(expression: string): CronFields {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new SyntaxError("Cron expression must be a non-empty string");
  }

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields but got ${parts.length}: "${expression}"`
    );
  }

  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];

  return fieldNames.reduce((acc, name, i) => {
    const [min, max] = FIELD_RANGES[name];
    acc[name] = parseField(parts[i], min, max);
    return acc;
  }, {} as CronFields);
}

export default parseCron;

