    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervalsElapsed = Math.floor(elapsed / this.refillIntervalMs);

    if (intervalsElapsed > 0) {
      const tokensToAdd = intervalsElapsed * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervalsElapsed * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) {
      throw new RangeError(`Requested tokens (${tokens}) exceed maxTokens (${this.maxTokens})`);
    }

    while (!this.tryConsume(tokens)) {
      const msPerToken = this.refillIntervalMs / this.refillRate;
      const deficit = tokens - this.currentTokens;
      const waitMs = Math.ceil(deficit * msPerToken);
      await new Promise<void>((resolve) => setTimeout(resolve, Math.max(1, waitMs)));
    }
  }
}

export default RateLimiter;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;       // tokens added per refill interval
  refillIntervalMs: number; // how often (in ms) the refillRate is applied
}

interface Waiter {
  tokens: number;
  resolve: () => void;
  reject: (err: Error) => void;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;

  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: Waiter[];
  private scheduledDrain: ReturnType<typeof setTimeout> | null;

  constructor(options: RateLimiterOptions) {
    if (
      !Number.isFinite(options.maxTokens) ||
      options.maxTokens <= 0
    ) {
      throw new RangeError(`maxTokens must be a finite positive number, got ${options.maxTokens}`);
    }
    if (
      !Number.isFinite(options.refillRate) ||
      options.refillRate < 0
    ) {
      throw new RangeError(`refillRate must be a finite non-negative number, got ${options.refillRate}`);
    }
    if (
      !Number.isFinite(options.refillIntervalMs) ||
      options.refillIntervalMs <= 0
    ) {
      throw new RangeError(`refillIntervalMs must be a finite positive number, got ${options.refillIntervalMs}`);
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;

    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
    this.scheduledDrain = null;
  }

  /**
   * Lazily refill tokens based on elapsed real time.
   * Updates lastRefillTime to now so subsequent calls don't double-count.
   */
  private refill(): void {
    if (this.refillRate === 0) return;

    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed <= 0) return;

    const tokensToAdd = (elapsed / this.refillIntervalMs) * this.refillRate;
    this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
    this.lastRefillTime = now;
  }

  /**
   * Attempt to consume `tokens` (default 1) without waiting.
   * Returns true if the tokens were consumed, false otherwise.
   *
   * Note: bypasses the wait queue — use waitForTokens for ordered access.
   */
  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens <= 0) {
      throw new RangeError(`tokens must be a finite positive number, got ${tokens}`);
    }
    // Requests exceeding the bucket ceiling can never be satisfied.
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  /** Returns the current number of available tokens after a lazy refill. */
  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  /** Resets the bucket to full capacity and drains any pending waiters. */
  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.drainQueue();
  }

  /**
   * Waits until `tokens` are available, then consumes them.
   * Waiters are served in FIFO order to prevent starvation.
   * Rejects immediately if the requested amount can never fit in the bucket.
   */
  waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens <= 0) {
      return Promise.reject(
        new RangeError(`tokens must be a finite positive number, got ${tokens}`)
      );
    }
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds maxTokens (${this.maxTokens}) — can never be fulfilled`
        )
      );
    }

    // Fast path: no queued waiters and bucket has enough right now.
    if (this.waitQueue.length === 0) {
      this.refill();
      if (this.currentTokens >= tokens) {
        this.currentTokens -= tokens;
        return Promise.resolve();
      }
    }

    // Slow path: join the queue.
    return new Promise<void>((resolve, reject) => {
      this.waitQueue.push({ tokens, resolve, reject });
      this.scheduleNextDrain();
    });
  }

  /**
   * Drain the front of the wait queue as long as there are enough tokens.
   * Reschedules itself if waiters remain.
   */
  private drainQueue(): void {
    this.scheduledDrain = null;
    this.refill();

    while (this.waitQueue.length > 0) {
      const waiter = this.waitQueue[0]!;

      if (this.currentTokens >= waiter.tokens) {
        this.currentTokens -= waiter.tokens;
        this.waitQueue.shift();
        // Resolve asynchronously to avoid deeply synchronous stack growth.
        waiter.resolve();
      } else {
        // Head of queue can't proceed yet — stop and wait for more tokens.
        break;
      }
    }

    if (this.waitQueue.length > 0) {
      this.scheduleNextDrain();
    }
  }

  /**
   * Schedule the next drain at precisely the moment the head waiter
   * will have enough tokens.  Avoids redundant scheduling if one is
   * already pending.
   */
  private scheduleNextDrain(): void {
    if (this.scheduledDrain !== null) return;

    const waiter = this.waitQueue[0];
    if (!waiter) return;

    this.refill(); // ensure currentTokens is fresh

    const deficit = waiter.tokens - this.currentTokens;

    if (deficit <= 0) {
      // Already satisfiable — drain on the next tick.
      this.scheduledDrain = setTimeout(() => this.drainQueue(), 0);
      return;
    }

    if (this.refillRate === 0) {
      // Bucket will never refill — reject everyone in the queue.
      const stuck = this.waitQueue.splice(0);
      for (const w of stuck) {
        w.reject(new Error('refillRate is 0; tokens will never become available'));
      }
      return;
    }

    // Time (ms) until the deficit is covered, rounded up by 1ms to
    // avoid waking slightly early due to timer jitter.
    const msUntilReady = Math.ceil((deficit / this.refillRate) * this.refillIntervalMs) + 1;
    this.scheduledDrain = setTimeout(() => this.drainQueue(), msUntilReady);
  }
}

export default RateLimiter;

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 7],
};

const range = (start: number, end: number): number[] =>
  Array.from({ length: end - start + 1 }, (_, i) => start + i);

const parseField = (field: string, min: number, max: number): number[] => {
  const fullRange = range(min, max);

  if (field === "*") return fullRange;

  if (field.startsWith("*/")) {
    const step = parseInt(field.slice(2), 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step value: ${field}`);
    return fullRange.filter((v) => (v - min) % step === 0);
  }

  if (field.includes(",")) {
    const values = field.split(",").flatMap((part) => parseField(part.trim(), min, max));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  if (field.includes("-")) {
    const [startStr, endStr] = field.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: ${field}`);
    if (start < min || end > max || start > end)
      throw new Error(`Range out of bounds: ${field} (valid: ${min}-${max})`);
    return range(start, end);
  }

  if (field.includes("/")) {
    const [rangeOrStar, stepStr] = field.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step: ${field}`);
    const base = rangeOrStar === "*" ? fullRange : parseField(rangeOrStar, min, max);
    const start = base[0];
    return base.filter((v) => (v - start) % step === 0);
  }

  const num = parseInt(field, 10);
  if (isNaN(num)) throw new Error(`Invalid cron field value: ${field}`);
  if (num < min || num > max)
    throw new Error(`Value ${num} out of range (valid: ${min}-${max})`);
  return [num];
};

const parseCron = (expression: string): CronResult => {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5)
    throw new Error(`Expected 5 fields, got ${fields.length}: "${expression}"`);

  const [minuteStr, hourStr, dayOfMonthStr, monthStr, dayOfWeekStr] = fields;
  const keys = Object.keys(FIELD_RANGES) as (keyof CronResult)[];

  const result = {} as CronResult;

  for (const [i, key] of keys.entries()) {
    const [min, max] = FIELD_RANGES[key];
    let values = parseField(fields[i], min, max);

    // Normalize dayOfWeek: treat 7 as 0 (both represent Sunday)
    if (key === "dayOfWeek") {
      values = [...new Set(values.map((v) => (v === 7 ? 0 : v)))].sort((a, b) => a - b);
    }

    result[key] = values;
  }

  return result;
};

export default parseCron;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      const tokensToAdd = intervals * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens must be > 0"));
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(`Requested tokens (${tokens}) exceed maxTokens (${this.maxTokens})`)
      );
    }

    return new Promise((resolve) => {
      const attempt = (): void => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();
        const deficit = tokens - this.currentTokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const delay = Math.max(1, intervalsNeeded * this.refillIntervalMs);

        setTimeout(attempt, delay);
      };

      attempt();
    });
  }
}

export default RateLimiter;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldRange {
  readonly min: number;
  readonly max: number;
}

const FIELD_RANGES: Record<keyof CronFields, FieldRange> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function assertInRange(value: number, range: FieldRange, context: string): void {
  if (!Number.isInteger(value) || value < range.min || value > range.max) {
    throw new RangeError(
      `Value ${value} in "${context}" is out of valid range [${range.min}, ${range.max}]`
    );
  }
}

function parseSegment(segment: string, range: FieldRange): number[] {
  if (segment === "") {
    throw new SyntaxError("Empty cron segment");
  }

  // Step expression: */n  or  a-b/n  or  a/n
  if (segment.includes("/")) {
    const slashIdx = segment.lastIndexOf("/");
    const rangePart = segment.slice(0, slashIdx);
    const stepStr   = segment.slice(slashIdx + 1);

    const step = Number(stepStr);
    if (!Number.isInteger(step) || step <= 0) {
      throw new RangeError(`Invalid step "${stepStr}" in "${segment}"`);
    }

    let rangeStart: number;
    let rangeEnd: number;

    if (rangePart === "*") {
      rangeStart = range.min;
      rangeEnd   = range.max;
    } else if (rangePart.includes("-")) {
      const dashIdx  = rangePart.indexOf("-");
      rangeStart = Number(rangePart.slice(0, dashIdx));
      rangeEnd   = Number(rangePart.slice(dashIdx + 1));
      if (!Number.isInteger(rangeStart) || !Number.isInteger(rangeEnd)) {
        throw new SyntaxError(`Non-integer bounds in "${segment}"`);
      }
      assertInRange(rangeStart, range, segment);
      assertInRange(rangeEnd,   range, segment);
      if (rangeStart > rangeEnd) {
        throw new RangeError(`Range start exceeds end in "${segment}"`);
      }
    } else {
      rangeStart = Number(rangePart);
      if (!Number.isInteger(rangeStart)) {
        throw new SyntaxError(`Non-integer start in "${segment}"`);
      }
      assertInRange(rangeStart, range, segment);
      rangeEnd = range.max;
    }

    const values: number[] = [];
    for (let v = rangeStart; v <= rangeEnd; v += step) {
      values.push(v);
    }
    return values;
  }

  // Wildcard
  if (segment === "*") {
    const values: number[] = [];
    for (let v = range.min; v <= range.max; v++) {
      values.push(v);
    }
    return values;
  }

  // Range: a-b
  if (segment.includes("-")) {
    const dashIdx = segment.indexOf("-");
    const start = Number(segment.slice(0, dashIdx));
    const end   = Number(segment.slice(dashIdx + 1));
    if (!Number.isInteger(start) || !Number.isInteger(end)) {
      throw new SyntaxError(`Non-integer bounds in range "${segment}"`);
    }
    assertInRange(start, range, segment);
    assertInRange(end,   range, segment);
    if (start > end) {
      throw new RangeError(`Range start exceeds end in "${segment}"`);
    }
    const values: number[] = [];
    for (let v = start; v <= end; v++) {
      values.push(v);
    }
    return values;
  }

  // Single integer
  const value = Number(segment);
  if (!Number.isInteger(value)) {
    throw new SyntaxError(`Unrecognised cron token "${segment}"`);
  }
  assertInRange(value, range, segment);
  return [value];
}

function parseField(field: string, range: FieldRange): number[] {
  if (field === "") {
    throw new SyntaxError("Empty cron field");
  }

  const seen = new Set<number>();

  for (const segment of field.split(",")) {
    for (const v of parseSegment(segment.trim(), range)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string" || expression.trim() === "") {
    throw new TypeError("Cron expression must be a non-empty string");
  }

  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields; got ${parts.length} in "${expression}"`
    );
  }

  const fieldNames = [
    "minute",
    "hour",
    "dayOfMonth",
    "month",
    "dayOfWeek",
  ] as const;

  return fieldNames.reduce((acc, name, i) => {
    acc[name] = parseField(parts[i], FIELD_RANGES[name]);
    return acc;
  }, {} as CronFields);
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  if (start > end) throw new RangeError(`Invalid range: ${start}-${end}`);
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function assertInRange(value: number, min: number, max: number, field: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] for field "${field}"`);
  }
}

function parseSegment(segment: string, min: number, max: number, field: string): number[] {
  // Wildcard: *
  if (segment === "*") {
    return range(min, max);
  }

  // Step: */n or start-end/n
  if (segment.includes("/")) {
    const [rangepart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) {
      throw new RangeError(`Invalid step value "${stepStr}" in field "${field}"`);
    }

    let start: number;
    let end: number;

    if (rangepart === "*") {
      start = min;
      end = max;
    } else if (rangepart.includes("-")) {
      const [s, e] = rangepart.split("-").map(Number);
      if (isNaN(s) || isNaN(e)) throw new RangeError(`Invalid range "${rangepart}" in field "${field}"`);
      assertInRange(s, min, max, field);
      assertInRange(e, min, max, field);
      start = s;
      end = e;
    } else {
      start = parseInt(rangepart, 10);
      if (isNaN(start)) throw new RangeError(`Invalid step expression "${segment}" in field "${field}"`);
      assertInRange(start, min, max, field);
      end = max;
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) {
      values.push(i);
    }
    return values;
  }

  // Range: start-end
  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2) throw new RangeError(`Invalid range "${segment}" in field "${field}"`);
    const [start, end] = parts.map(Number);
    if (isNaN(start) || isNaN(end)) throw new RangeError(`Invalid range "${segment}" in field "${field}"`);
    assertInRange(start, min, max, field);
    assertInRange(end, min, max, field);
    return range(start, end);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new RangeError(`Invalid value "${segment}" in field "${field}"`);
  assertInRange(value, min, max, field);
  return [value];
}

function parseField(expression: string, min: number, max: number, field: string): number[] {
  const segments = expression.split(",");
  const allValues = new Set<number>();

  for (const segment of segments) {
    const values = parseSegment(segment.trim(), min, max, field);
    for (const v of values) allValues.add(v);
  }

  return Array.from(allValues).sort((a, b) => a - b);
}

export function parseCron(expression: string): CronFields {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new TypeError("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new RangeError(`Expected 5 fields, got ${fields.length}`);
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute: parseField(minuteExpr, ...FIELD_RANGES.minute, "minute"),
    hour: parseField(hourExpr, ...FIELD_RANGES.hour, "hour"),
    dayOfMonth: parseField(domExpr, ...FIELD_RANGES.dayOfMonth, "dayOfMonth"),
    month: parseField(monthExpr, ...FIELD_RANGES.month, "month"),
    dayOfWeek: parseField(dowExpr, ...FIELD_RANGES.dayOfWeek, "dayOfWeek"),
  };
}

export default parseCron;

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronResult;

interface FieldConfig {
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: Readonly<Record<FieldName, FieldConfig>> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
} as const;

const FIELD_ORDER: readonly FieldName[] = [
  "minute", "hour", "dayOfMonth", "month", "dayOfWeek",
] as const;

function buildRange(start: number, end: number, step: number): number[] {
  if (!Number.isInteger(step) || step < 1) {
    throw new RangeError(`Step must be a positive integer, got: ${step}`);
  }
  if (start > end) {
    throw new RangeError(`Range start (${start}) must not exceed end (${end})`);
  }
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function assertInRange(value: number, config: FieldConfig, fieldName: string): void {
  if (value < config.min || value > config.max) {
    throw new RangeError(
      `Value ${value} is out of range [${config.min}-${config.max}] for field "${fieldName}"`
    );
  }
}

function parseInteger(raw: string, fieldName: string): number {
  if (!/^\d+$/.test(raw)) {
    throw new SyntaxError(`Expected an integer in field "${fieldName}", got: "${raw}"`);
  }
  const value = parseInt(raw, 10);
  if (!Number.isFinite(value)) {
    throw new RangeError(`Non-finite integer in field "${fieldName}": "${raw}"`);
  }
  return value;
}

function parseSegment(
  segment: string,
  config: FieldConfig,
  fieldName: string
): number[] {
  if (segment.length === 0) {
    throw new SyntaxError(`Empty segment in field "${fieldName}"`);
  }

  // Wildcard with optional step: * or */n
  if (segment === "*") {
    return buildRange(config.min, config.max, 1);
  }

  const stepWildcardMatch = /^\*\/(\d+)$/.exec(segment);
  if (stepWildcardMatch) {
    const step = parseInteger(stepWildcardMatch[1], fieldName);
    if (step < 1) {
      throw new RangeError(`Step must be >= 1 in field "${fieldName}", got: ${step}`);
    }
    return buildRange(config.min, config.max, step);
  }

  // Range with optional step: n-m or n-m/s
  const rangeMatch = /^(\d+)-(\d+)(?:\/(\d+))?$/.exec(segment);
  if (rangeMatch) {
    const start = parseInteger(rangeMatch[1], fieldName);
    const end   = parseInteger(rangeMatch[2], fieldName);
    const step  = rangeMatch[3] !== undefined
      ? parseInteger(rangeMatch[3], fieldName)
      : 1;

    assertInRange(start, config, fieldName);
    assertInRange(end,   config, fieldName);

    if (start > end) {
      throw new RangeError(
        `Range start (${start}) must not exceed end (${end}) in field "${fieldName}"`
      );
    }
    if (step < 1) {
      throw new RangeError(`Step must be >= 1 in field "${fieldName}", got: ${step}`);
    }

    return buildRange(start, end, step);
  }

  // Single numeric value
  if (/^\d+$/.test(segment)) {
    const value = parseInteger(segment, fieldName);
    assertInRange(value, config, fieldName);
    return [value];
  }

  throw new SyntaxError(`Unrecognized segment "${segment}" in field "${fieldName}"`);
}

function parseField(
  raw: string,
  config: FieldConfig,
  fieldName: string
): number[] {
  if (raw.length === 0) {
    throw new SyntaxError(`Empty field for "${fieldName}"`);
  }

  const parts = raw.split(",");
  if (parts.some((p) => p.length === 0)) {
    throw new SyntaxError(`Trailing or double comma in field "${fieldName}": "${raw}"`);
  }

  const seen = new Set<number>();
  for (const part of parts) {
    for (const value of parseSegment(part, config, fieldName)) {
      seen.add(value);
    }
  }

  return [...seen].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, got: ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed.length === 0) {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const tokens = trimmed.split(/\s+/);
  if (tokens.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${tokens.length}: "${trimmed}"`
    );
  }

  const result = {} as CronResult;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    const config    = FIELD_CONFIGS[fieldName];
    result[fieldName] = parseField(tokens[i], config, fieldName);
  }

  return result;
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export default class RateLimiter {
  private readonly _options: Readonly<RateLimiterOptions>;
  private _currentTokens: number;
  private _lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError(
        `maxTokens must be a positive finite number, got ${options.maxTokens}`
      );
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate < 0) {
      throw new RangeError(
        `refillRate must be a non-negative finite number, got ${options.refillRate}`
      );
    }
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0) {
      throw new RangeError(
        `refillIntervalMs must be a positive finite number, got ${options.refillIntervalMs}`
      );
    }

    this._options = Object.freeze({ ...options });
    this._currentTokens = options.maxTokens;
    this._lastRefillTime = Date.now();
  }

  private _refill(): void {
    if (this._options.refillRate === 0) return;

    const now = Date.now();
    const elapsed = now - this._lastRefillTime;

    if (elapsed < this._options.refillIntervalMs) return;

    const intervals = Math.floor(elapsed / this._options.refillIntervalMs);
    const tokensToAdd = intervals * this._options.refillRate;

    this._currentTokens = Math.min(
      this._options.maxTokens,
      this._currentTokens + tokensToAdd
    );
    // Advance clock by exact completed intervals to preserve fractional elapsed time
    this._lastRefillTime += intervals * this._options.refillIntervalMs;
  }

  private _validateTokenArg(tokens: number, label = "tokens"): void {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError(
        `${label} must be a non-negative finite number, got ${tokens}`
      );
    }
  }

  tryConsume(tokens = 1): boolean {
    this._validateTokenArg(tokens);
    this._refill();

    if (tokens === 0) return true;

    if (this._currentTokens >= tokens) {
      this._currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this._refill();
    return this._currentTokens;
  }

  reset(): void {
    this._currentTokens = this._options.maxTokens;
    this._lastRefillTime = Date.now();
  }

  async waitForTokens(tokens = 1): Promise<void> {
    this._validateTokenArg(tokens);

    if (tokens === 0) return;

    if (tokens > this._options.maxTokens) {
      throw new RangeError(
        `Requested ${tokens} tokens exceeds maxTokens (${this._options.maxTokens}); ` +
          `this request can never be fulfilled`
      );
    }

    // With zero refill rate, tokens will never increase — fail fast if insufficient
    if (this._options.refillRate === 0) {
      this._refill(); // no-op, but keeps _currentTokens consistent
      if (this._currentTokens >= tokens) {
        this._currentTokens -= tokens;
        return;
      }
      throw new Error(
        `refillRate is 0 and only ${this._currentTokens} token(s) available ` +
          `(need ${tokens}); this request can never be fulfilled`
      );
    }

    while (!this.tryConsume(tokens)) {
      // After tryConsume(_refill is called inside), _currentTokens and _lastRefillTime
      // are authoritative. Compute the earliest moment enough tokens will exist.
      const needed = tokens - this._currentTokens;
      const intervalsNeeded = Math.ceil(needed / this._options.refillRate);
      const nextRefillAt =
        this._lastRefillTime + intervalsNeeded * this._options.refillIntervalMs;
      // Add 1 ms buffer so we don't wake up a hair before the window opens
      const waitMs = Math.max(1, nextRefillAt - Date.now() + 1);

      await new Promise<void>((resolve) => setTimeout(resolve, waitMs));
    }
  }
}

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldRange = {
  min: number;
  max: number;
};

const FIELD_RANGES: Readonly<Record<keyof CronResult, FieldRange>> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
} as const;

function assertInRange(value: number, range: FieldRange, fieldName: string): void {
  if (!Number.isInteger(value) || value < range.min || value > range.max) {
    throw new RangeError(
      `Value ${value} is out of valid range [${range.min}–${range.max}] for field "${fieldName}"`
    );
  }
}

function parseSegment(segment: string, range: FieldRange, fieldName: string): number[] {
  // Step expression: */n or base/n or start-end/n
  if (segment.includes('/')) {
    const slashIndex = segment.indexOf('/');
    const baseStr = segment.slice(0, slashIndex);
    const stepStr = segment.slice(slashIndex + 1);

    const step = Number(stepStr);
    if (!Number.isInteger(step) || step <= 0) {
      throw new TypeError(`Invalid step value "${stepStr}" in field "${fieldName}"`);
    }

    let start: number;
    let end: number;

    if (baseStr === '*') {
      start = range.min;
      end = range.max;
    } else if (baseStr.includes('-')) {
      [start, end] = parseRangeParts(baseStr, range, fieldName);
    } else {
      start = Number(baseStr);
      if (!Number.isInteger(start)) {
        throw new TypeError(`Invalid step base "${baseStr}" in field "${fieldName}"`);
      }
      assertInRange(start, range, fieldName);
      end = range.max;
    }

    const values: number[] = [];
    for (let v = start; v <= end; v += step) {
      values.push(v);
    }
    return values;
  }

  // Wildcard
  if (segment === '*') {
    return Array.from({ length: range.max - range.min + 1 }, (_, i) => range.min + i);
  }

  // Range: n-m
  if (segment.includes('-')) {
    const [start, end] = parseRangeParts(segment, range, fieldName);
    return Array.from({ length: end - start + 1 }, (_, i) => start + i);
  }

  // Single integer
  const value = Number(segment);
  if (!Number.isInteger(value)) {
    throw new TypeError(`Invalid value "${segment}" for field "${fieldName}"`);
  }
  assertInRange(value, range, fieldName);
  return [value];
}

function parseRangeParts(rangeStr: string, range: FieldRange, fieldName: string): [number, number] {
  const dashIndex = rangeStr.indexOf('-');
  if (dashIndex <= 0 || dashIndex === rangeStr.length - 1) {
    throw new SyntaxError(`Malformed range expression "${rangeStr}" in field "${fieldName}"`);
  }
  const start = Number(rangeStr.slice(0, dashIndex));
  const end   = Number(rangeStr.slice(dashIndex + 1));
  if (!Number.isInteger(start) || !Number.isInteger(end)) {
    throw new TypeError(`Non-integer range bounds in "${rangeStr}" for field "${fieldName}"`);
  }
  assertInRange(start, range, fieldName);
  assertInRange(end,   range, fieldName);
  if (start > end) {
    throw new RangeError(
      `Range start ${start} exceeds end ${end} in field "${fieldName}"`
    );
  }
  return [start, end];
}

function parseField(field: string, range: FieldRange, fieldName: string): number[] {
  if (!field || /\s/.test(field)) {
    throw new SyntaxError(`Empty or whitespace-contaminated field "${fieldName}"`);
  }

  // Comma-separated list — each element is itself a valid segment
  const segments = field.split(',');
  const seen = new Set<number>();

  for (const segment of segments) {
    if (!segment) {
      throw new SyntaxError(`Empty segment in comma list for field "${fieldName}"`);
    }
    for (const v of parseSegment(segment, range, fieldName)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== 'string') {
    throw new TypeError('Cron expression must be a string');
  }

  const trimmed = expression.trim();
  if (!trimmed) {
    throw new SyntaxError('Cron expression must not be empty');
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields (minute hour dayOfMonth month dayOfWeek), got ${fields.length}: "${expression}"`
    );
  }

  const [minuteRaw, hourRaw, domRaw, monthRaw, dowRaw] = fields;

  return {
    minute:     parseField(minuteRaw, FIELD_RANGES.minute,     'minute'),
    hour:       parseField(hourRaw,   FIELD_RANGES.hour,       'hour'),
    dayOfMonth: parseField(domRaw,    FIELD_RANGES.dayOfMonth, 'dayOfMonth'),
    month:      parseField(monthRaw,  FIELD_RANGES.month,      'month'),
    dayOfWeek:  parseField(dowRaw,    FIELD_RANGES.dayOfWeek,  'dayOfWeek'),
  };
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

type CronResult = {
  [K in CronField]: number[];
};

type FieldBounds = {
  readonly min: number;
  readonly max: number;
};

const FIELD_BOUNDS: Readonly<Record<CronField, FieldBounds>> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  }, // 7 is alias for 0 (Sunday)
} as const;

const FIELD_ORDER: readonly CronField[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
] as const;

const rangeArray = (start: number, end: number, step: number = 1): number[] => {
  if (step <= 0) throw new Error(`Step must be positive, got: ${step}`);
  if (start > end) throw new Error(`Range start (${start}) must not exceed end (${end})`);
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
};

const assertInBounds = (value: number, bounds: FieldBounds, context: string): void => {
  if (!Number.isInteger(value) || value < bounds.min || value > bounds.max) {
    throw new RangeError(
      `Value ${value} out of valid range [${bounds.min}–${bounds.max}] in token: "${context}"`
    );
  }
};

const parseInteger = (raw: string, bounds: FieldBounds, context: string): number => {
  const n = Number(raw);
  if (!Number.isInteger(n) || String(n) !== raw.trim()) {
    throw new TypeError(`Expected integer, got "${raw}" in token: "${context}"`);
  }
  assertInBounds(n, bounds, context);
  return n;
};

const parseSingleToken = (token: string, bounds: FieldBounds): number[] => {
  // Step: */n or a-b/n
  if (token.includes("/")) {
    const slashIndex = token.indexOf("/");
    const leftPart = token.slice(0, slashIndex);
    const stepRaw = token.slice(slashIndex + 1);

    if (stepRaw.includes("/")) {
      throw new SyntaxError(`Multiple "/" separators in token: "${token}"`);
    }

    const step = Number(stepRaw);
    if (!Number.isInteger(step) || step <= 0) {
      throw new RangeError(`Invalid step "${stepRaw}" in token: "${token}"`);
    }

    let start: number;
    let end: number;

    if (leftPart === "*") {
      start = bounds.min;
      end = bounds.max;
    } else if (leftPart.includes("-")) {
      const dashIndex = leftPart.indexOf("-");
      start = parseInteger(leftPart.slice(0, dashIndex), bounds, token);
      end   = parseInteger(leftPart.slice(dashIndex + 1), bounds, token);
    } else {
      start = parseInteger(leftPart, bounds, token);
      end   = bounds.max;
    }

    if (start > end) {
      throw new RangeError(`Range start (${start}) exceeds end (${end}) in token: "${token}"`);
    }

    return rangeArray(start, end, step);
  }

  // Range: a-b
  if (token.includes("-")) {
    const dashIndex = token.indexOf("-");
    const start = parseInteger(token.slice(0, dashIndex), bounds, token);
    const end   = parseInteger(token.slice(dashIndex + 1), bounds, token);

    if (start > end) {
      throw new RangeError(`Range start (${start}) exceeds end (${end}) in token: "${token}"`);
    }

    return rangeArray(start, end);
  }

  // Wildcard: *
  if (token === "*") {
    return rangeArray(bounds.min, bounds.max);
  }

  // Single numeric value
  const n = parseInteger(token, bounds, token);
  return [n];
};

const parseFieldExpression = (expr: string, bounds: FieldBounds): number[] => {
  const trimmed = expr.trim();
  if (trimmed.length === 0) {
    throw new SyntaxError(`Empty field expression`);
  }

  const parts = trimmed.split(",");
  if (parts.length > 1) {
    const allValues = parts.flatMap((part) => {
      const p = part.trim();
      if (p.length === 0) throw new SyntaxError(`Empty value in comma list: "${trimmed}"`);
      return parseSingleToken(p, bounds);
    });
    const deduplicated = [...new Set(allValues)].sort((a, b) => a - b);
    return deduplicated;
  }

  return parseSingleToken(trimmed, bounds);
};

const normalizeDayOfWeek = (values: number[]): number[] => {
  // 7 is a legal alias for 0 (Sunday); normalize and deduplicate
  const normalized = values.map((v) => (v === 7 ? 0 : v));
  return [...new Set(normalized)].sort((a, b) => a - b);
};

export const parseCron = (expression: string): CronResult => {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, got: ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed.length === 0) {
    throw new SyntaxError(`Cron expression must not be empty`);
  }

  const rawFields = trimmed.split(/\s+/);
  if (rawFields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${rawFields.length}: "${expression}"`
    );
  }

  const result = {} as CronResult;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const field = FIELD_ORDER[i];
    const bounds = FIELD_BOUNDS[field];
    let values = parseFieldExpression(rawFields[i], bounds);

    if (field === "dayOfWeek") {
      values = normalizeDayOfWeek(values);
    }

    result[field] = values;
  }

  return result;
};

export default parseCron;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute:     [0, 59],
  hour:       [0, 23],
  dayOfMonth: [1, 31],
  month:      [1, 12],
  dayOfWeek:  [0,  6],
};

function rangeArray(min: number, max: number, step = 1): number[] {
  const result: number[] = [];
  for (let i = min; i <= max; i += step) result.push(i);
  return result;
}

function clamp(values: number[], min: number, max: number): number[] {
  return [...new Set(values.filter(v => v >= min && v <= max))].sort((a, b) => a - b);
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Step on wildcard: */n
  if (/^\*\/\d+$/.test(segment)) {
    const step = parseInt(segment.slice(2), 10);
    if (step <= 0) throw new Error(`Invalid step value: ${segment}`);
    return rangeArray(min, max, step);
  }

  // Pure wildcard
  if (segment === "*") {
    return rangeArray(min, max);
  }

  // Comma-separated list (recurse)
  if (segment.includes(",")) {
    const values = segment
      .split(",")
      .flatMap(part => parseSegment(part.trim(), min, max));
    return clamp(values, min, max);
  }

  // Range with optional step: a-b or a-b/n
  if (segment.includes("-")) {
    const [rangePart, stepPart] = segment.split("/");
    const [startStr, endStr] = rangePart.split("-");
    const start = parseInt(startStr, 10);
    const end   = parseInt(endStr,   10);
    const step  = stepPart !== undefined ? parseInt(stepPart, 10) : 1;

    if (isNaN(start) || isNaN(end) || isNaN(step))
      throw new Error(`Invalid range expression: ${segment}`);
    if (start > end)
      throw new Error(`Range start exceeds end: ${segment}`);
    if (step <= 0)
      throw new Error(`Invalid step in range: ${segment}`);

    return clamp(rangeArray(start, end, step), min, max);
  }

  // Plain number
  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new Error(`Invalid cron value: ${segment}`);
  return clamp([value], min, max);
}

export function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") throw new Error("Cron expression must be a string");

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${parts.length}: "${expression}"`
    );
  }

  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];
  const result = {} as CronFields;

  for (let i = 0; i < fieldNames.length; i++) {
    const field = fieldNames[i];
    const [min, max] = FIELD_RANGES[field];
    const values = parseSegment(parts[i], min, max);

    if (values.length === 0) {
      throw new Error(
        `No valid values for field "${field}" with expression "${parts[i]}" (range ${min}-${max})`
      );
    }

    result[field] = values;
  }

  return result;
}

export default parseCron;

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly name: keyof CronFields;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 7 },
];

const RE_UINT = /^\d+$/;

function parseUint(raw: string, context: string): number {
  if (!RE_UINT.test(raw)) {
    throw new Error(`Expected an integer in ${context}, got: "${raw}"`);
  }
  return parseInt(raw, 10);
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new Error(`Value ${value} in "${context}" is outside valid range [${min}, ${max}]`);
  }
}

function expandRange(start: number, end: number, step: number, context: string): number[] {
  if (step < 1) {
    throw new Error(`Step must be >= 1 in "${context}", got ${step}`);
  }
  if (start > end) {
    throw new Error(`Range start ${start} exceeds end ${end} in "${context}"`);
  }
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Step: */N or start-end/N or N/step
  if (segment.includes("/")) {
    const slashIdx = segment.lastIndexOf("/");
    const rangeExpr = segment.slice(0, slashIdx);
    const stepStr = segment.slice(slashIdx + 1);
    const step = parseUint(stepStr, segment);
    if (step < 1) {
      throw new Error(`Step must be >= 1 in "${segment}"`);
    }

    if (rangeExpr === "*") {
      return expandRange(min, max, step, segment);
    }

    if (rangeExpr.includes("-")) {
      const { start, end } = parseRangeExpr(rangeExpr, min, max);
      return expandRange(start, end, step, segment);
    }

    const start = parseUint(rangeExpr, segment);
    assertInRange(start, min, max, segment);
    return expandRange(start, max, step, segment);
  }

  // Range: start-end
  if (segment.includes("-")) {
    const { start, end } = parseRangeExpr(segment, min, max);
    return expandRange(start, end, 1, segment);
  }

  // Wildcard
  if (segment === "*") {
    return expandRange(min, max, 1, segment);
  }

  // Single integer
  const value = parseUint(segment, segment);
  assertInRange(value, min, max, segment);
  return [value];
}

function parseRangeExpr(
  expr: string,
  min: number,
  max: number
): { start: number; end: number } {
  const parts = expr.split("-");
  if (parts.length !== 2) {
    throw new Error(`Invalid range expression: "${expr}"`);
  }
  const start = parseUint(parts[0], expr);
  const end = parseUint(parts[1], expr);
  assertInRange(start, min, max, expr);
  assertInRange(end, min, max, expr);
  if (start > end) {
    throw new Error(`Range start ${start} exceeds end ${end} in "${expr}"`);
  }
  return { start, end };
}

function parseField(expr: string, min: number, max: number): number[] {
  if (!expr) {
    throw new Error("Empty field expression");
  }

  const segments = expr.split(",");
  if (segments.some((s) => s.trim() === "")) {
    throw new Error(`Trailing or consecutive commas in field: "${expr}"`);
  }

  const seen = new Set<number>();
  for (const segment of segments) {
    for (const value of parseSegment(segment.trim(), min, max)) {
      seen.add(value);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (expression == null || typeof expression !== "string") {
    throw new Error("Cron expression must be a non-empty string");
  }

  const trimmed = expression.trim();
  if (trimmed.length === 0) {
    throw new Error("Cron expression must not be blank");
  }

  const rawFields = trimmed.split(/\s+/);
  if (rawFields.length !== 5) {
    throw new Error(
      `Expected exactly 5 fields (minute hour dayOfMonth month dayOfWeek), got ${rawFields.length}: "${expression}"`
    );
  }

  const result = {} as CronFields;
  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const { name, min, max } = FIELD_CONFIGS[i];
    try {
      result[name] = parseField(rawFields[i], min, max);
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      throw new Error(`Invalid ${name} field "${rawFields[i]}": ${message}`);
    }
  }

  return result;
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervalsElapsed = Math.floor(elapsed / this.refillIntervalMs);

    if (intervalsElapsed > 0) {
      const tokensToAdd = intervalsElapsed * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervalsElapsed * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens must be > 0"));
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(`Requested ${tokens} tokens exceeds maxTokens (${this.maxTokens})`)
      );
    }

    return new Promise((resolve) => {
      const attempt = (): void => {
        this.refill();

        if (this.currentTokens >= tokens) {
          this.currentTokens -= tokens;
          resolve();
          return;
        }

        const deficit = tokens - this.currentTokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const msUntilRefill = this.refillIntervalMs - (Date.now() - this.lastRefillTime);
        const waitMs = (intervalsNeeded - 1) * this.refillIntervalMs + msUntilRefill;

        setTimeout(attempt, Math.max(0, waitMs));
      };

      attempt();
    });
  }
}

export default RateLimiter;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
};

function expandRange(start: number, end: number, step: number = 1): number[] {
  if (start > end) throw new RangeError(`Invalid range: ${start}-${end}`);
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Step on wildcard: */n
  if (/^\*\/\d+$/.test(segment)) {
    const step = parseInt(segment.slice(2), 10);
    if (step <= 0) throw new RangeError(`Step must be > 0, got ${step}`);
    return expandRange(min, max, step);
  }

  // Pure wildcard
  if (segment === "*") {
    return expandRange(min, max);
  }

  // Range with optional step: a-b or a-b/n
  if (/^\d+-\d+(\/\d+)?$/.test(segment)) {
    const [rangePart, stepPart] = segment.split("/");
    const [startStr, endStr] = rangePart.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    const step = stepPart !== undefined ? parseInt(stepPart, 10) : 1;
    if (step <= 0) throw new RangeError(`Step must be > 0, got ${step}`);
    if (start < min || end > max) {
      throw new RangeError(`Range ${start}-${end} out of bounds [${min}-${max}]`);
    }
    return expandRange(start, end, step);
  }

  // Single number
  if (/^\d+$/.test(segment)) {
    const value = parseInt(segment, 10);
    if (value < min || value > max) {
      throw new RangeError(`Value ${value} out of bounds [${min}-${max}]`);
    }
    return [value];
  }

  throw new SyntaxError(`Unrecognized cron segment: "${segment}"`);
}

function parseField(expression: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];
  const parts = expression.split(",");
  const values = new Set<number>();

  for (const part of parts) {
    const expanded = parseSegment(part.trim(), min, max);
    for (const v of expanded) {
      // Normalize dayOfWeek: both 0 and 7 represent Sunday
      if (field === "dayOfWeek" && v === 7) {
        values.add(0);
      } else {
        values.add(v);
      }
    }
  }

  return Array.from(values).sort((a, b) => a - b);
}

function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(domExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dowExpr, "dayOfWeek"),
  };
}

export default parseCron;
export type { CronResult, CronField };

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be greater than 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be greater than 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be greater than 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      const tokensToAdd = intervals * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be greater than 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens must be greater than 0"));
    if (tokens > this.maxTokens) return Promise.reject(new RangeError("tokens exceeds maxTokens and can never be fulfilled"));

    return new Promise((resolve) => {
      const attempt = (): void => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();
        const deficit = tokens - this.currentTokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const delay = Math.max(1, intervalsNeeded * this.refillIntervalMs);

        setTimeout(attempt, delay);
      };

      attempt();
    });
  }
}

export default RateLimiter;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronFields;

const FIELD_RANGES: Record<FieldName, [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   6],
};

const FIELD_ORDER: FieldName[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function range(start: number, end: number): number[] {
  if (start > end) throw new RangeError(`Invalid range: ${start}-${end}`);
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function assertInRange(value: number, min: number, max: number, field: string): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} out of range [${min}, ${max}] for field "${field}"`
    );
  }
}

function parseSegment(segment: string, field: FieldName): number[] {
  const [min, max] = FIELD_RANGES[field];

  // Step: */n or start/n
  if (segment.includes("/")) {
    const [base, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) {
      throw new RangeError(`Invalid step value "${stepStr}" in field "${field}"`);
    }

    let start: number;
    let end: number;

    if (base === "*") {
      start = min;
      end = max;
    } else if (base.includes("-")) {
      const [lo, hi] = base.split("-").map(Number);
      assertInRange(lo, min, max, field);
      assertInRange(hi, min, max, field);
      start = lo;
      end = hi;
    } else {
      start = parseInt(base, 10);
      assertInRange(start, min, max, field);
      end = max;
    }

    const result: number[] = [];
    for (let v = start; v <= end; v += step) {
      result.push(v);
    }
    return result;
  }

  // Wildcard
  if (segment === "*") {
    return range(min, max);
  }

  // Range: a-b
  if (segment.includes("-")) {
    const [loStr, hiStr] = segment.split("-");
    const lo = parseInt(loStr, 10);
    const hi = parseInt(hiStr, 10);
    assertInRange(lo, min, max, field);
    assertInRange(hi, min, max, field);
    return range(lo, hi);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Invalid value "${segment}" in field "${field}"`);
  }
  assertInRange(value, min, max, field);
  return [value];
}

function parseField(expression: string, field: FieldName): number[] {
  const segments = expression.split(",");
  const values = new Set<number>();

  for (const segment of segments) {
    const parsed = parseSegment(segment.trim(), field);
    for (const v of parsed) values.add(v);
  }

  return Array.from(values).sort((a, b) => a - b);
}

function parseCron(expression: string): CronFields {
  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields, got ${parts.length}: "${expression}"`
    );
  }

  return FIELD_ORDER.reduce((acc, field, index) => {
    acc[field] = parseField(parts[index], field);
    return acc;
  }, {} as CronFields);
}

