      // Drain the entire queue with a rejection — refillRate is 0
      while (this.waitQueue.length > 0) {
        const waiter = this.waitQueue.shift()!;
        waiter.reject(
          new Error(
            "Cannot acquire tokens: refillRate is 0 and insufficient tokens available"
          )
        );
      }
      return;
    }

    // Add a small buffer tick to avoid waking up fractionally early
    const safeDelay = delayMs + 1;

    setTimeout(() => {
      this.applyRefill();
      this.drainQueue();
      if (this.waitQueue.length > 0) {
        this.scheduleQueueDrain();
      }
    }, safeDelay);
  }
}

export default RateLimiter;

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly pendingWaiters: Array<{ tokens: number; resolve: () => void }>;
  private drainTimer: ReturnType<typeof setTimeout> | null;

  constructor(options: { maxTokens: number; refillRate: number; refillIntervalMs: number }) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError("maxTokens must be a positive finite number");
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate <= 0) {
      throw new RangeError("refillRate must be a positive finite number");
    }
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0) {
      throw new RangeError("refillIntervalMs must be a positive finite number");
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
    this.pendingWaiters = [];
    this.drainTimer = null;
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    if (elapsed >= this.refillIntervalMs) {
      const intervals = Math.floor(elapsed / this.refillIntervalMs);
      this.currentTokens = Math.min(
        this.maxTokens,
        this.currentTokens + intervals * this.refillRate
      );
      // Advance timestamp by whole intervals only — preserves fractional elapsed time
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError("tokens must be a non-negative finite number");
    }
    if (tokens === 0) return true;
    // A request that can never be satisfied even at full capacity always fails
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }
    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    // Cancel the in-flight drain timer so it cannot consume the freshly restored tokens
    if (this.drainTimer !== null) {
      clearTimeout(this.drainTimer);
      this.drainTimer = null;
    }
    // Wake all waiters: they get tokens in FIFO order from the full bucket
    this.flushWaiters();
  }

  async waitForTokens(tokens = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError("tokens must be a non-negative finite number");
    }
    if (tokens === 0) return;
    if (tokens > this.maxTokens) {
      throw new RangeError(
        `Requested ${tokens} tokens exceeds bucket capacity of ${this.maxTokens} — ` +
          `this promise would never resolve`
      );
    }

    // Fast path: no queue and enough tokens are available right now
    if (this.pendingWaiters.length === 0) {
      this.refill();
      if (this.currentTokens >= tokens) {
        this.currentTokens -= tokens;
        return;
      }
    }

    // Enqueue and (if no timer is running) schedule the next drain
    return new Promise<void>((resolve) => {
      this.pendingWaiters.push({ tokens, resolve });
      if (this.drainTimer === null) {
        this.scheduleDrain();
      }
    });
  }

  // Resolve as many head-of-queue waiters as the bucket currently holds
  private flushWaiters(): void {
    while (this.pendingWaiters.length > 0) {
      const waiter = this.pendingWaiters[0];
      if (this.currentTokens >= waiter.tokens) {
        this.currentTokens -= waiter.tokens;
        this.pendingWaiters.shift();
        waiter.resolve();
      } else {
        break;
      }
    }
  }

  // Schedule exactly one timer whose delay is the minimum time until the next
  // head-of-queue waiter can be served. Keeps only one outstanding timer.
  private scheduleDrain(): void {
    if (this.pendingWaiters.length === 0) return;

    // Opportunistically refill and flush before committing to a sleep
    this.refill();
    this.flushWaiters();

    if (this.pendingWaiters.length === 0) return;

    const waiter = this.pendingWaiters[0];
    const tokensNeeded = waiter.tokens - this.currentTokens;
    // How many full refill intervals are required to cover the deficit?
    const intervalsNeeded = Math.ceil(tokensNeeded / this.refillRate);
    // Time until the next interval boundary (may be slightly negative due to timing jitter)
    const msToNextBoundary = this.lastRefillTime + this.refillIntervalMs - Date.now();
    const delayMs = msToNextBoundary + (intervalsNeeded - 1) * this.refillIntervalMs;

    this.drainTimer = setTimeout(() => {
      this.drainTimer = null;
      this.refill();
      this.flushWaiters();
      if (this.pendingWaiters.length > 0) {
        this.scheduleDrain();
      }
    }, Math.max(0, delayMs));
  }
}

export default RateLimiter;
